4795	/* Checks if all keys in a command (or a MULTI-EXEC) belong to the same hash slot.
4796	 * If yes, return 1, otherwise 0. If hashslot is not NULL, it will be set to the
4797	 * slot of the keys. */
4798	int areCommandKeysInSameSlot(client *c, int *hashslot) {
4799	    int slot = -1;
4800	    multiState *ms = NULL;
4801	
4802	    if (c->cmd->proc == execCommand) {
4803	        if (!(c->flags & CLIENT_MULTI)) return 1;
4804	        else ms = &c->mstate;
4805	    }
4806	
4807	    /* If client is in multi-exec, we need to check the slot of all keys
4808	     * in the transaction. */
4809	    for (int i = 0; i < (ms ? ms->count : 1); i++) {
4810	        struct redisCommand *cmd = ms ? ms->commands[i]->cmd : c->cmd;
4811	        robj **argv = ms ? ms->commands[i]->argv : c->argv;
4812	        int argc = ms ? ms->commands[i]->argc : c->argc;
4813	
4814	        getKeysResult result = GETKEYS_RESULT_INIT;
4815	        int numkeys = getKeysFromCommand(cmd, argv, argc, &result);
4816	        keyReference *keyindex = result.keys;
4817	
4818	        /* Check if all keys have the same slots, increment the metric if not */
4819	        for (int j = 0; j < numkeys; j++) {
4820	            robj *thiskey = argv[keyindex[j].pos];
4821	            int thisslot = keyHashSlot((char*)thiskey->ptr, sdslen(thiskey->ptr));
4822	            if (slot == -1) {
4823	                slot = thisslot;
4824	            } else if (slot != thisslot) {
4825	                getKeysFreeResult(&result);
4826	                return 0;
4827	            }
4828	        }
4829	        getKeysFreeResult(&result);
4830	    }
4831	    if (hashslot) *hashslot = slot;
4832	    return 1;
4833	}
