1302	/* This function handles 'background' operations we are required to do
1303	 * incrementally in Redis databases, such as active key expiring, resizing,
1304	 * rehashing. */
1305	void databasesCron(void) {
1306	    /* Expire keys by random sampling. Not required for slaves
1307	     * as master will synthesize DELs for us. */
1308	    if (server.active_expire_enabled) {
1309	        if (iAmMaster()) {
1310	            activeExpireCycle(ACTIVE_EXPIRE_CYCLE_SLOW);
1311	        } else {
1312	            expireSlaveKeys();
1313	        }
1314	    }
1315	
1316	    /* Defrag keys gradually. */
1317	    activeDefragCycle();
1318	
1319	    /* Handle active-trim */
1320	    if (server.cluster_enabled)
1321	        asmActiveTrimCycle();
1322	
1323	    /* Perform hash tables rehashing if needed, but only if there are no
1324	     * other processes saving the DB on disk. Otherwise rehashing is bad
1325	     * as will cause a lot of copy-on-write of memory pages. */
1326	    if (!hasActiveChildProcess()) {
1327	        /* We use global counters so if we stop the computation at a given
1328	         * DB we'll be able to start from the successive in the next
1329	         * cron loop iteration. */
1330	        static unsigned int resize_db = 0;
1331	        static unsigned int rehash_db = 0;
1332	        int dbs_per_call = CRON_DBS_PER_CALL;
1333	        int j;
1334	
1335	        /* Don't test more DBs than we have. */
1336	        if (dbs_per_call > server.dbnum) dbs_per_call = server.dbnum;
1337	
1338	        for (j = 0; j < dbs_per_call; j++) {
1339	            redisDb *db = &server.db[resize_db % server.dbnum];
1340	            kvstoreTryResizeDicts(db->keys, CRON_DICTS_PER_DB);
1341	            kvstoreTryResizeDicts(db->expires, CRON_DICTS_PER_DB);
1342	            resize_db++;
1343	        }
1344	
1345	        /* Rehash */
1346	        if (server.activerehashing) {
1347	            uint64_t elapsed_us = 0;
1348	            for (j = 0; j < dbs_per_call; j++) {
1349	                redisDb *db = &server.db[rehash_db % server.dbnum];
1350	                elapsed_us += kvstoreIncrementallyRehash(db->keys, INCREMENTAL_REHASHING_THRESHOLD_US - elapsed_us);
1351	                if (elapsed_us >= INCREMENTAL_REHASHING_THRESHOLD_US)
1352	                    break;
1353	                elapsed_us += kvstoreIncrementallyRehash(db->expires, INCREMENTAL_REHASHING_THRESHOLD_US - elapsed_us);
1354	                if (elapsed_us >= INCREMENTAL_REHASHING_THRESHOLD_US)
1355	                    break;
1356	                rehash_db++;
1357	            }
1358	        }
1359	    }
1360	}
