1362	static inline void updateCachedTimeWithUs(int update_daylight_info, const long long ustime) {
1363	    server.ustime = ustime;
1364	    server.mstime = server.ustime / 1000;
1365	    time_t unixtime = server.mstime / 1000;
1366	    atomicSet(server.unixtime, unixtime);
1367	
1368	    /* To get information about daylight saving time, we need to call
1369	     * localtime_r and cache the result. However calling localtime_r in this
1370	     * context is safe since we will never fork() while here, in the main
1371	     * thread. The logging function will call a thread safe version of
1372	     * localtime that has no locks. */
1373	    if (update_daylight_info) {
1374	        struct tm tm;
1375	        time_t ut = server.unixtime;
1376	        localtime_r(&ut,&tm);
1377	        atomicSet(server.daylight_active, tm.tm_isdst);
1378	    }
1379	}
