1396	/* Performing required operations in order to enter an execution unit.
1397	 * In general, if we are already inside an execution unit then there is nothing to do,
1398	 * otherwise we need to update cache times so the same cached time will be used all over
1399	 * the execution unit.

1400	 * update_cached_time - if 0, will not update the cached time even if required.
1401	 * us - if not zero, use this time for cached time, otherwise get current time. */
1402	void enterExecutionUnit(int update_cached_time, long long us) {
1403	    if (server.execution_nesting++ == 0 && update_cached_time) {
1404	        if (us == 0) {
1405	            us = ustime();
1406	        }
1407	        updateCachedTimeWithUs(0, us);
1408	        server.cmd_time_snapshot = server.mstime;
1409	    }
1410	}
