1416	void checkChildrenDone(void) {
1417	    int statloc = 0;
1418	    pid_t pid;
1419	
1420	    if ((pid = waitpid(-1, &statloc, WNOHANG)) != 0) {
1421	        int exitcode = WIFEXITED(statloc) ? WEXITSTATUS(statloc) : -1;
1422	        int bysignal = 0;
1423	
1424	        if (WIFSIGNALED(statloc)) bysignal = WTERMSIG(statloc);
1425	
1426	        /* sigKillChildHandler catches the signal and calls exit(), but we
1427	         * must make sure not to flag lastbgsave_status, etc incorrectly.
1428	         * We could directly terminate the child process via SIGUSR1
1429	         * without handling it */
1430	        if (exitcode == SERVER_CHILD_NOERROR_RETVAL) {
1431	            bysignal = SIGUSR1;
1432	            exitcode = 1;
1433	        }
1434	
1435	        if (pid == -1) {
1436	            serverLog(LL_WARNING,"waitpid() returned an error: %s. "
1437	                "child_type: %s, child_pid = %d",
1438	                strerror(errno),
1439	                strChildType(server.child_type),
1440	                (int) server.child_pid);
1441	        } else if (pid == server.child_pid) {
1442	            if (server.child_type == CHILD_TYPE_RDB) {
1443	                backgroundSaveDoneHandler(exitcode, bysignal);
1444	            } else if (server.child_type == CHILD_TYPE_AOF) {
1445	                backgroundRewriteDoneHandler(exitcode, bysignal);
1446	            } else if (server.child_type == CHILD_TYPE_MODULE) {
1447	                ModuleForkDoneHandler(exitcode, bysignal);
1448	            } else {
1449	                serverPanic("Unknown child type %d for child pid %d", server.child_type, server.child_pid);
1450	                exit(1);
1451	            }
1452	            if (!bysignal && exitcode == 0) receiveChildInfo();
1453	            resetChildState();
1454	        } else {
1455	            if (!ldbRemoveChild(pid)) {
1456	                serverLog(LL_WARNING,
1457	                          "Warning, detected child with unmatched pid: %ld",
1458	                          (long) pid);
1459	            }
1460	        }
1461	
1462	        /* start any pending forks immediately. */
1463	        replicationStartPendingFork();
1464	    }
1465	}
