1482	/* Called from serverCron and cronUpdateMemoryStats to update cached memory metrics. */
1483	void cronUpdateMemoryStats(void) {
1484	    updatePeakMemory();
1485	
1486	    run_with_period(100) {
1487	        /* Sample the RSS and other metrics here since this is a relatively slow call.
1488	         * We must sample the zmalloc_used at the same time we take the rss, otherwise
1489	         * the frag ratio calculate may be off (ratio of two samples at different times) */
1490	        server.cron_malloc_stats.process_rss = zmalloc_get_rss();
1491	        server.cron_malloc_stats.zmalloc_used = zmalloc_used_memory();
1492	        /* Sampling the allocator info can be slow too.
1493	         * The fragmentation ratio it'll show is potentially more accurate
1494	         * it excludes other RSS pages such as: shared libraries, LUA and other non-zmalloc
1495	         * allocations, and allocator reserved pages that can be pursed (all not actual frag) */
1496	        zmalloc_get_allocator_info(1,
