1864	/* This function fills in the role of serverCron during RDB or AOF loading, and
1865	 * also during blocked scripts.
1866	 * It attempts to do its duties at a similar rate as the configured server.hz,
1867	 * and updates cronloops variable so that similarly to serverCron, the
1868	 * run_with_period can be used. */
1869	void whileBlockedCron(void) {
1870	    /* Here we may want to perform some cron jobs (normally done server.hz times
1871	     * per second). */
1872	
1873	    /* Since this function depends on a call to blockingOperationStarts, let's
1874	     * make sure it was done. */
1875	    serverAssert(server.blocked_last_cron);
1876	
1877	    /* In case we were called too soon, leave right away. This way one time
1878	     * jobs after the loop below don't need an if. and we don't bother to start
1879	     * latency monitor if this function is called too often. */
1880	    if (server.blocked_last_cron >= server.mstime)
1881	        return;
1882	
1883	    /* Increment server.cronloops so that run_with_period works. */
1884	    long hz_ms = 1000 / server.hz;
1885	    int cronloops = (server.mstime - server.blocked_last_cron + (hz_ms - 1)) / hz_ms; /* rounding up */
1886	    server.blocked_last_cron += cronloops * hz_ms;
1887	    server.cronloops += cronloops;
1888	
1889	    mstime_t latency;
1890	    latencyStartMonitor(latency);
1891	
1892	    /* Only defragment during AOF loading. */
1893	    if (isAOFLoadingContext()) defragWhileBlocked();
1894	
1895	    /* Update memory stats during loading (excluding blocked scripts) */
1896	    if (server.loading) cronUpdateMemoryStats();
1897	
1898	    latencyEndMonitor(latency);
1899	    latencyAddSampleIfNeeded("while-blocked-cron",latency);
1900	
1901	    /* We received a SIGTERM during loading, shutting down here in a safe way,
1902	     * as it isn't ok doing so inside the signal handler. */
1903	    if (shouldShutdownAsap() && server.loading) {
1904	        if (prepareForShutdown(SHUTDOWN_NOSAVE) == C_OK) exit(0);
1905	        serverLog(LL_WARNING,"SIGTERM received but errors trying to shut down the server, check the logs for more information");
1906	        atomicSet(server.shutdown_asap, 0);
1907	        atomicSet(server.last_sig_received, 0);
1908	    }
1909	}
