880	/* Add a sample to the instantaneous metric. This function computes the quotient
881	 * of the increment of value and base, which is useful to record operation count
882	 * per second, or the average time consumption of an operation.
883	 *
884	 * current_value - The dividend
885	 * current_base - The divisor
886	 * */
887	void trackInstantaneousMetric(int metric, long long current_value, long long current_base, long long factor) {
888	    if (server.inst_metric[metric].last_sample_base > 0) {
889	        long long base = current_base - server.inst_metric[metric].last_sample_base;
890	        long long value = current_value - server.inst_metric[metric].last_sample_value;
891	        long long avg = base > 0 ? (value * factor / base) : 0;
892	        server.inst_metric[metric].samples[server.inst_metric[metric].idx] = avg;
893	        server.inst_metric[metric].idx++;
894	        server.inst_metric[metric].idx %= STATS_METRIC_SAMPLES;
895	    }
896	    server.inst_metric[metric].last_sample_base = current_base;
897	    server.inst_metric[metric].last_sample_value = current_value;
898	}
899	
900	/* Return the mean of all the samples. */
901	long long getInstantaneousMetric(int metric) {
902	    int j;
903	    long long sum = 0;
904	
905	    for (j = 0; j < STATS_METRIC_SAMPLES; j++)
906	        sum += server.inst_metric[metric].samples[j];
907	    return sum / STATS_METRIC_SAMPLES;
908	}
