910	/* The client query buffer is an sds.c string that can end with a lot of
911	 * free space not used, this function reclaims space if needed.
912	 *
913	 * The function always returns 0 as it never terminates the client. */
914	int clientsCronResizeQueryBuffer(client *c) {
915	    /* If the client query buffer is NULL, it is using the reusable query buffer and there is nothing to do. */
916	    if (c->querybuf == NULL) return 0;
917	    size_t querybuf_size = sdsalloc(c->querybuf);
918	    time_t idletime = server.unixtime - c->lastinteraction;
919	
920	    /* Only resize the query buffer if the buffer is actually wasting at least a
921	     * few kbytes */
922	    if (sdsavail(c->querybuf) > 1024*4) {
923	        /* There are two conditions to resize the query buffer: */
924	        if (idletime > 2) {
925	            /* 1) Query is idle for a long time. */
926	            size_t remaining = sdslen(c->querybuf) - c->qb_pos;
927	            if (!(c->flags & CLIENT_MASTER) && !remaining) {
928	                /* If the client is not a master and no data is pending,
929	                 * The client can safely use the reusable query buffer in the next read - free the client's querybuf. */
930	                sdsfree(c->querybuf);
931	                /* By setting the querybuf to NULL, the client will use the reusable query buffer in the next read.
932	                 * We don't move the client to the reusable query buffer immediately, because if we allocated a private
933	                 * query buffer for the client, it's likely that the client will use it again soon. */
934	                c->querybuf = NULL;
935	            } else {
936	                c->querybuf = sdsRemoveFreeSpace(c->querybuf, 1);
937	            }
938	        } else if (querybuf_size > PROTO_RESIZE_THRESHOLD && querybuf_size/2 > c->querybuf_peak) {
939	            /* 2) Query buffer is too big for latest peak and is larger than
940	             *    resize threshold. Trim excess space but only up to a limit,
941	             *    not below the recent peak and current c->querybuf (which will
942	             *    be soon get used). If we're in the middle of a bulk then make
943	             *    sure not to resize to less than the bulk length. */
944	            size_t resize = sdslen(c->querybuf);
945	            if (resize < c->querybuf_peak) resize = c->querybuf_peak;
946	            if (c->bulklen != -1 && resize < (size_t)c->bulklen + 2) resize = c->bulklen + 2;
947	            c->querybuf = sdsResize(c->querybuf, resize, 1);
948	        }
949	    }
950	
951	    /* Reset the peak again to capture the peak memory usage in the next
952	     * cycle. */
953	    c->querybuf_peak = c->querybuf ? sdslen(c->querybuf) : 0;
954	    /* We reset to either the current used, or currently processed bulk size,
955	     * which ever is bigger. */
956	    if (c->bulklen != -1 && (size_t)c->bulklen + 2 > c->querybuf_peak) c->querybuf_peak = c->bulklen + 2;
957	    return 0;
958	}
