960	/* The client output buffer can be adjusted to better fit the memory requirements.
961	 *
962	 * the logic is:
963	 * in case the last observed peak size of the buffer equals the buffer size - we double the size
964	 * in case the last observed peak size of the buffer is less than half the buffer size - we shrink by half.
965	 * The buffer peak will be reset back to the buffer position every server.reply_buffer_peak_reset_time milliseconds
966	 * The function always returns 0 as it never terminates the client. */
967	int clientsCronResizeOutputBuffer(client *c, mstime_t now_ms) {
968	
969	    size_t new_buffer_size = 0;
970	    char *oldbuf = NULL;
971	    const size_t buffer_target_shrink_size = c->buf_usable_size/2;
972	    const size_t buffer_target_expand_size = c->buf_usable_size*2;
973	
974	    /* in case the resizing is disabled return immediately */
975	    if(!server.reply_buffer_resizing_enabled)
976	        return 0;
977	
978	    /* Don't resize encoded buffers. When buf is encoded, we track the last
979	     * partially written payloadHeader pointer, so we can't
980	     * reallocate the buffer as it would invalidate this pointer. */
981	    if (c->buf_encoded) return 0;
982	
983	    if (buffer_target_shrink_size >= PROTO_REPLY_MIN_BYTES &&
984	        c->buf_peak < buffer_target_shrink_size )
985	    {
986	        new_buffer_size = max(PROTO_REPLY_MIN_BYTES,c->buf_peak+1);
987	        server.stat_reply_buffer_shrinks++;
988	    } else if (buffer_target_expand_size < PROTO_REPLY_CHUNK_BYTES*2 &&
989	        c->buf_peak == c->buf_usable_size)
990	    {
991	        new_buffer_size = min(PROTO_REPLY_CHUNK_BYTES,buffer_target_expand_size);
992	        server.stat_reply_buffer_expands++;
993	    }
994	
995	    serverAssertWithInfo(c, NULL, (!new_buffer_size) || (new_buffer_size >= (size_t)c->bufpos));
996	
997	    /* reset the peak value each server.reply_buffer_peak_reset_time seconds. in case the client will be idle
998	     * it will start to shrink.
999	     */
1000	    if (server.reply_buffer_peak_reset_time >=0 &&
1001	        now_ms - c->buf_peak_last_reset_time >= server.reply_buffer_peak_reset_time)
1002	    {
1003	        c->buf_peak = c->bufpos;
1004	        c->buf_peak_last_reset_time = now_ms;
1005	    }
1006	
1007	    if (new_buffer_size) {
1008	        oldbuf = c->buf;
1009	        c->buf = zmalloc_usable(new_buffer_size, &c->buf_usable_size);
1010	        memcpy(c->buf,oldbuf,c->bufpos);
1011	        zfree(oldbuf);
1012	    }
1013	    return 0;
1014	}
