1016	/* This function is used in order to track clients using the biggest amount
1017	 * of memory in the latest few seconds. This way we can provide such information
1018	 * in the INFO output (clients section), without having to do an O(N) scan for
1019	 * all the clients.
1020	 *
1021	 * This is how it works. We have an array of CLIENTS_PEAK_MEM_USAGE_SLOTS slots
1022	 * where we track, for each, the biggest client output and input buffers we
1023	 * saw in that slot. Every slot corresponds to one of the latest seconds, since
1024	 * the array is indexed by doing UNIXTIME % CLIENTS_PEAK_MEM_USAGE_SLOTS.
1025	 *
1026	 * When we want to know what was recently the peak memory usage, we just scan
1027	 * such few slots searching for the maximum value. */
1028	#define CLIENTS_PEAK_MEM_USAGE_SLOTS 8
1029	size_t ClientsPeakMemInput[CLIENTS_PEAK_MEM_USAGE_SLOTS] = {0};
1030	size_t ClientsPeakMemOutput[CLIENTS_PEAK_MEM_USAGE_SLOTS] = {0};
1031	int CurrentPeakMemUsageSlot = 0;
1032	
1033	int clientsCronTrackExpansiveClients(client *c) {
1034	    size_t qb_size = c->querybuf ? sdsZmallocSize(c->querybuf) : 0;
1035	    size_t argv_size = c->argv ? zmalloc_size(c->argv) : 0;
1036	    size_t in_usage = qb_size + c->all_argv_len_sum + argv_size;
1037	    size_t out_usage = getClientOutputBufferMemoryUsage(c);
1038	
1039	    /* Track the biggest values observed so far in this slot. */
1040	    if (in_usage > ClientsPeakMemInput[CurrentPeakMemUsageSlot])
1041	        ClientsPeakMemInput[CurrentPeakMemUsageSlot] = in_usage;
1042	    if (out_usage > ClientsPeakMemOutput[CurrentPeakMemUsageSlot])
1043	        ClientsPeakMemOutput[CurrentPeakMemUsageSlot] = out_usage;
1044	
1045	    return 0; /* This function never terminates the client. */
1046	}
