831	/* Feed the slave 'c' with the replication backlog starting from the
832	 * specified 'offset' up to the end of the backlog. */
833	long long addReplyReplicationBacklog(client *c, long long offset) {
834	    serverAssert(c->running_tid == IOTHREAD_MAIN_THREAD_ID);
835	
836	    long long skip;
837	
838	    serverLog(LL_DEBUG, "[PSYNC] Replica request offset: %lld", offset);
839	
840	    if (server.repl_backlog->histlen == 0) {
841	        serverLog(LL_DEBUG, "[PSYNC] Backlog history len is zero");
842	        return 0;
843	    }
844	
845	    serverLog(LL_DEBUG, "[PSYNC] Backlog size: %lld",
846	             server.repl_backlog_size);
847	    serverLog(LL_DEBUG, "[PSYNC] First byte: %lld",
848	             server.repl_backlog->offset);
849	    serverLog(LL_DEBUG, "[PSYNC] History len: %lld",
850	             server.repl_backlog->histlen);
851	
852	    /* Compute the amount of bytes we need to discard. */
853	    skip = offset - server.repl_backlog->offset;
854	    serverLog(LL_DEBUG, "[PSYNC] Skipping: %lld", skip);
855	
856	    /* Iterate recorded blocks, quickly search the approximate node. */
857	    listNode *node = NULL;
858	    if (raxSize(server.repl_backlog->blocks_index) > 0) {
859	        uint64_t encoded_offset = htonu64(offset);
860	        raxIterator ri;
861	        raxStart(&ri, server.repl_backlog->blocks_index);
862	        raxSeek(&ri, ">", (unsigned char*)&encoded_offset, sizeof(uint64_t));
863	        if (raxEOF(&ri)) {
864	            /* No found, so search from the last recorded node. */
865	            raxSeek(&ri, "$", NULL, 0);
866	            raxPrev(&ri);
867	            node = (listNode *)ri.data;
868	        } else {
869	            raxPrev(&ri); /* Skip the sought node. */
870	            /* We should search from the prev node since the offset of current
871	             * sought node exceeds searching offset. */
872	            if (raxPrev(&ri))
873	                node = (listNode *)ri.data;
874	            else
875	                node = server.repl_backlog->ref_repl_buf_node;
876	        }
877	        raxStop(&ri);
878	    } else {
879	        /* No recorded blocks, just from the start node to search. */
880	        node = server.repl_backlog->ref_repl_buf_node;
881	    }
882	
883	    /* Search the exact node. */
884	    while (node != NULL) {
885	        replBufBlock *o = listNodeValue(node);
886	        if (o->repl_offset + (long long)o->used >= offset) break;
887	        node = listNextNode(node);
888	    }
889	    serverAssert(node != NULL);
890	
891	    /* Install a writer handler first.*/
892	    prepareClientToWrite(c);
893	    /* Setting output buffer of the replica. */
894	    replBufBlock *o = listNodeValue(node);
895	    o->refcount++;
896	    c->ref_repl_buf_node = node;
897	    c->ref_block_pos = offset - o->repl_offset;
898	
899	    return server.repl_backlog->histlen - skip;

900	}
