910	/* Send a FULLRESYNC reply in the specific case of a full resynchronization,
911	 * as a side effect setup the slave for a full sync in different ways:
912	 *
913	 * 1) Remember, into the slave client structure, the replication offset
914	 *    we sent here, so that if new slaves will later attach to the same
915	 *    background RDB saving process (by duplicating this client output
916	 *    buffer), we can get the right offset from this slave.
917	 * 2) Set the replication state of the slave to WAIT_BGSAVE_END so that
918	 *    we start accumulating differences from this point.
919	 * 3) Force the replication stream to re-emit a SELECT statement so
920	 *    the new slave incremental differences will start selecting the
921	 *    right database number.
922	 *
923	 * Normally this function should be called immediately after a successful
924	 * BGSAVE for replication was started, or when there is one already in
925	 * progress that we attached our slave to. */
926	int replicationSetupSlaveForFullResync(client *slave, long long offset) {
927	    char buf[128];
928	    int buflen;
929	
930	    slave->psync_initial_offset = offset;
931	    slave->replstate = SLAVE_STATE_WAIT_BGSAVE_END;
932	    /* We are going to accumulate the incremental changes for this
933	     * slave as well. Set slaveseldb to -1 in order to force to re-emit
934	     * a SELECT statement in the replication stream. */
935	    server.slaveseldb = -1;
936	
937	    /* Slots snapshot. */
938	    if (slave->flags & CLIENT_REPL_RDB_CHANNEL &&
939	        slave->slave_req & SLAVE_REQ_SLOTS_SNAPSHOT)
940	    {
941	        /* Start to deliver the commands stream on migrating slots. */
942	        asmSlotSnapshotAndStreamStart(slave->task);
943	
944	        buflen = snprintf(buf, sizeof(buf), "+SLOTSSNAPSHOT\r\n");
945	        if (connWrite(slave->conn, buf, buflen) != buflen) {
946	            freeClientAsync(slave);
947	            return C_ERR;
948	        }
949	        return C_OK;
950	    }
951	
952	    /* Don't send this reply to slaves that approached us with
953	     * the old SYNC command. */
954	    if (!(slave->flags & CLIENT_PRE_PSYNC)) {
955	        if (slave->flags & CLIENT_REPL_RDB_CHANNEL) {
956	            /* This slave is rdbchannel. Find its associated main channel and
957	             * change its state so we can deliver replication stream from now
958	             * on, in parallel to rdb. */
959	            uint64_t id = slave->main_ch_client_id;
960	            client *c = lookupClientByID(id);
961	            if (c && c->replstate == SLAVE_STATE_WAIT_RDB_CHANNEL) {
962	                c->replstate = SLAVE_STATE_SEND_BULK_AND_STREAM;
963	                serverLog(LL_NOTICE, "Starting to deliver RDB and replication stream to replica: %s",
964	                          replicationGetSlaveName(c));
965	            } else {
966	                serverLog(LL_WARNING, "Starting to deliver RDB to replica %s"
967	                                      " but it has no associated main channel",
968	                                      replicationGetSlaveName(slave));
969	            }
970	        }
971	        buflen = snprintf(buf,sizeof(buf),"+FULLRESYNC %s %lld\r\n",
972	                          server.replid,offset);
973	        if (connWrite(slave->conn,buf,buflen) != buflen) {
974	            freeClientAsync(slave);
975	            return C_ERR;
976	        }
977	    }
978	    return C_OK;
979	}
