379	/* Generally, we only have one replication buffer block to trim when replication
380	 * backlog size exceeds our setting and no replica reference it. But if replica
381	 * clients disconnect, we need to free many replication buffer blocks that are
382	 * referenced. It would cost much time if there are a lots blocks to free, that
383	 * will freeze server, so we trim replication backlog incrementally. */
384	void incrementalTrimReplicationBacklog(size_t max_blocks) {
385	    serverAssert(server.repl_backlog != NULL);
386	
387	    size_t trimmed_blocks = 0;
388	    while (server.repl_backlog->histlen > server.repl_backlog_size &&
389	           trimmed_blocks < max_blocks)
390	    {
391	        /* We never trim backlog to less than one block. */
392	        if (listLength(server.repl_buffer_blocks) <= 1) break;
393	
394	        /* Replicas increment the refcount of the first replication buffer block
395	         * they refer to, in that case, we don't trim the backlog even if
396	         * backlog_histlen exceeds backlog_size. This implicitly makes backlog
397	         * bigger than our setting, but makes the master accept partial resync as
398	         * much as possible. So that backlog must be the last reference of
399	         * replication buffer blocks. */

250	    server.repl_backlog->histlen = 0;
251	    /* We don't have any data inside our buffer, but virtually the first
252	     * byte we have is the next byte that will be generated for the
253	     * replication stream. */
254	    server.repl_backlog->offset = server.master_repl_offset+1;
255	}
