264	        server.repl_backlog_size = CONFIG_REPL_BACKLOG_MIN_SIZE;
265	    if (server.repl_backlog)
266	        incrementalTrimReplicationBacklog(REPL_BACKLOG_TRIM_BLOCKS_PER_CALL);
267	}
