454	/* Batched write API for the global replication backlog, optimized for minimal
455	 * overhead per append: data writes are just memcpys into the tail block.
456	 * All bookkeeping is deferred to replBufWriterEnd(). */
457	typedef struct replBufWriter {
458	    listNode *start_node;  /* First repl buffer block written to. */
459	    size_t start_pos;      /* Byte offset within start_node where writing began. */
460	    size_t total_len;      /* Total bytes written across all writes. */
461	    int new_blocks;        /* Number of new blocks allocated during this stream. */
462	    replBufBlock *tail;    /* Current tail block. */
463	} replBufWriter;
464	
465	/* Initialize the writer, cache the current tail position. */
466	static void replBufWriterBegin(replBufWriter *wr) {
467	    listNode *ln = listLast(server.repl_buffer_blocks);
468	    replBufBlock *tail = ln ? listNodeValue(ln) : NULL;
469	
470	    if (tail && tail->used < tail->size) {
471	        wr->start_node = ln;
472	        wr->start_pos = tail->used;
473	    } else {
474	        wr->start_node = NULL;
475	        wr->start_pos = 0;
476	    }
477	
478	    wr->total_len = 0;
479	    wr->new_blocks = 0;
480	    wr->tail = tail;
481	}
482	
483	/* Allocate a new replication backlog block. Called when current block is full. */
484	static void replBufWriterAllocBlock(replBufWriter *wr, size_t hint) {
485	    static long long repl_block_id = 0;
486	    size_t usable_size;
487	    /* Avoid creating nodes smaller than PROTO_REPLY_CHUNK_BYTES, so that we can append more data into them,
488	     * and also avoid creating nodes bigger than repl_backlog_size / 16, so that we won't have huge nodes that can't
489	     * trim when we only still need to hold a small portion from them. */
490	    size_t limit = max((size_t)server.repl_backlog_size / 16, (size_t)PROTO_REPLY_CHUNK_BYTES);
491	    size_t bsize = min(max(hint, (size_t)PROTO_REPLY_CHUNK_BYTES), limit);
492	    replBufBlock *tail = zmalloc_usable(bsize + sizeof(replBufBlock), &usable_size);
493	    /* Take over the allocation's internal fragmentation */
494	    tail->size = usable_size - sizeof(replBufBlock);
495	    tail->used = 0;
496	    tail->refcount = 0;
497	    tail->repl_offset = server.master_repl_offset + wr->total_len + 1;
498	    tail->id = repl_block_id++;
499	    listAddNodeTail(server.repl_buffer_blocks, tail);
500	    server.repl_buffer_mem += (usable_size + sizeof(listNode));
501	    createReplicationBacklogIndex(listLast(server.repl_buffer_blocks));
502	
503	    /* Update stream state. */
504	    wr->tail = tail;
505	    wr->new_blocks++;
506	    if (wr->start_node == NULL) {
507	        wr->start_node = listLast(server.repl_buffer_blocks);
508	        wr->start_pos = 0;
509	    }
510	}
511	
512	/* Slow path: fill remainder of current block + allocate as needed. */
513	static void replBufWriterAppendSlow(replBufWriter *wr, const char *buf, size_t len) {
514	    while (len > 0) {
515	        size_t avail = wr->tail ? wr->tail->size - wr->tail->used : 0;
516	        if (avail > 0) {
517	            size_t copy = (avail >= len) ? len : avail;
518	            memcpy(wr->tail->buf + wr->tail->used, buf, copy);
519	            wr->tail->used += copy;
520	            wr->total_len += copy;
521	            buf += copy;
522	            len -= copy;
523	        }
524	
525	        if (len > 0)
526	            replBufWriterAllocBlock(wr, len);
527	    }
528	}
529	
530	/* Write data into the replication buffer. The slow path is split out to give 
531	 * the compiler a chance to inline the common case where the write fits entirely
532	 * in the current block. */
533	static inline void replBufWriterAppend(replBufWriter *wr, const char *buf, size_t len) {
534	    size_t avail = wr->tail ? wr->tail->size - wr->tail->used : 0;
535	    if (len > 0 && avail >= len) {
536	        memcpy(wr->tail->buf + wr->tail->used, buf, len);
537	        wr->tail->used += len;
538	        wr->total_len += len;
539	        return;
540	    }
541	    replBufWriterAppendSlow(wr, buf, len);
542	}
