544	/* Write a RESP header prefix<value>\r\n (e.g. "$12\r\n" or "*3\r\n").
545	 * Uses pre-built shared objects for small values, formats manually otherwise. */
546	static inline void replBufWriterAppendBulkLen(replBufWriter *wr, char prefix, long long value) {
547	    serverAssert(prefix == '$' || prefix == '*');
548	    if (value >= 0 && value < OBJ_SHARED_BULKHDR_LEN) {
549	        robj **tbl = (prefix == '$') ? shared.bulkhdr : shared.mbulkhdr;
550	        replBufWriterAppend(wr, tbl[value]->ptr, OBJ_SHARED_HDR_STRLEN(value));
551	        return;
552	    }
553	    char buf[LONG_STR_SIZE+3];
554	    buf[0] = prefix;
555	    int len = ll2string(buf+1, sizeof(buf)-1, value);
556	    buf[len+1] = '\r';
557	    buf[len+2] = '\n';
558	    replBufWriterAppend(wr, buf, len+3);
559	}
