562	/* Finalize the replication buffer write: update global offsets, set up replica
563	 * references for new data, check output buffer limits, and trim the
564	 * backlog if new blocks were allocated. */
565	static void replBufWriterEnd(replBufWriter *wr) {
566	    if (wr->total_len == 0) return;
567	
568	    serverAssert(wr->start_node != NULL);
569	    clusterSlotStatsIncrNetworkBytesOutForReplication(wr->total_len);
570	
571	    /* Update the current cmd's keys with the commands replication bytes*/
572	    hotkeyMetrics metrics = {0, wr->total_len};
573	    hotkeyStatsUpdateCurrentCmd(server.hotkeys, metrics);
574	
575	    server.master_repl_offset += wr->total_len;
576	    server.repl_backlog->histlen += wr->total_len;
577	
578	    /* For output buffer of replicas. */
579	    listIter li;
580	    listNode *ln;
581	    listRewind(server.slaves,&li);
582	    while((ln = listNext(&li))) {
583	        client *slave = ln->value;
584	        if (!canFeedReplicaReplBuffer(slave)) continue;
585	
586	        /* Update shared replication buffer start position. */
587	        if (slave->ref_repl_buf_node == NULL) {
588	            slave->ref_repl_buf_node = wr->start_node;
589	            slave->ref_block_pos = wr->start_pos;
590	            /* Only increase the start block reference count. */
591	            ((replBufBlock *)listNodeValue(wr->start_node))->refcount++;
592	        }
593	
594	        /* Check output buffer limit only when new blocks were added. */
595	        if (wr->new_blocks) closeClientOnOutputBufferLimitReached(slave, 1);
596	    }
597	
598	    /* For replication backlog */
599	    if (server.repl_backlog->ref_repl_buf_node == NULL) {

620	    replBufWriterBegin(&wr);
621	    replBufWriterAppend(&wr, buf, len);
622	    replBufWriterEnd(&wr);
623	}
