625	/* Propagate write commands to replication stream.
626	 *
627	 * This function is used if the instance is a master: we use the commands
628	 * received by our clients in order to create the replication stream.
629	 * Instead if the instance is a replica and has sub-replicas attached, we use
630	 * replicationFeedStreamFromMasterStream() */
631	void replicationFeedSlaves(list *slaves, int dictid, robj **argv, int argc) {
632	    int j, len;
633	    char llstr[LONG_STR_SIZE];
634	
635	    /* In case we propagate a command that doesn't touch keys (PING, REPLCONF) we
636	     * pass dbid=-1 that indicate there is no need to replicate `select` command. */
637	    serverAssert(dictid == -1 || (dictid >= 0 && dictid < server.dbnum));
638	
639	    /* If the instance is not a top level master, return ASAP: we'll just proxy
640	     * the stream of data we receive from our master instead, in order to
641	     * propagate *identical* replication stream. In this way this slave can
642	     * advertise the same replication ID as the master (since it shares the
643	     * master replication history and has the same backlog and offsets). */
644	    if (server.masterhost != NULL) return;
645	
646	    /* If current client is marked as master, we will proxy the command stream
647	     * to our slaves instead of replicating them, that also happens when being
648	     * in atomic slot migration. */
649	    if (server.current_client && server.current_client->flags & CLIENT_MASTER) return;
650	
651	    /* If there aren't slaves, and there is no backlog buffer to populate,
652	     * we can return ASAP. */
653	    if (server.repl_backlog == NULL && listLength(slaves) == 0) {
654	        /* We increment the repl_offset anyway, since we use that for tracking AOF fsyncs
655	         * even when there's no replication active. This code will not be reached if AOF
656	         * is also disabled. */
657	        server.master_repl_offset += 1;
658	        return;
659	    }
660	
661	    /* We can't have slaves attached and no backlog. */
662	    serverAssert(!(listLength(slaves) != 0 && server.repl_backlog == NULL));
663	
664	    /* Update the time of sending replication stream to replicas. */
665	    server.repl_stream_lastio = server.unixtime;
666	
667	    /* Must install write handler for all replicas first before feeding
668	     * replication stream. */
669	    prepareReplicasToWrite();
670	
671	    /* Send SELECT command to every slave if needed. */
672	    if (dictid != -1 && server.slaveseldb != dictid) {
673	        robj *selectcmd;
674	
675	        /* For a few DBs we have pre-computed SELECT command. */
676	        if (dictid >= 0 && dictid < PROTO_SHARED_SELECT_CMDS) {
677	            selectcmd = shared.select[dictid];
678	        } else {
679	            int dictid_len;
680	
681	            dictid_len = ll2string(llstr,sizeof(llstr),dictid);
682	            selectcmd = createObject(OBJ_STRING,
683	                sdscatprintf(sdsempty(),
684	                "*2\r\n$6\r\nSELECT\r\n$%d\r\n%s\r\n",
685	                dictid_len, llstr));
686	        }
687	
688	        feedReplicationBuffer(selectcmd->ptr, sdslen(selectcmd->ptr));
689	
690	        /* Although the SELECT command is not associated with any slot,
691	         * its per-slot network-bytes-out accumulation is made by the above function call.
692	         * To cancel-out this accumulation, below adjustment is made. */
693	        clusterSlotStatsDecrNetworkBytesOutForReplication(sdslen(selectcmd->ptr));
694	
695	        if (dictid < 0 || dictid >= PROTO_SHARED_SELECT_CMDS)
696	            decrRefCount(selectcmd);
697	
698	        server.slaveseldb = dictid;
699	    }
700	
701	    /* Write the command to the replication buffer if any. */
702	    char aux[LONG_STR_SIZE+3];
703	    replBufWriter wr;
704	    replBufWriterBegin(&wr);
705	
706	    /* Write the multi bulk count */
707	    replBufWriterAppendBulkLen(&wr, '*', argc);
708	
709	    for (j = 0; j < argc; j++) {
710	        /* Write the bulk count */
711	        long objlen = stringObjectLen(argv[j]);
712	        replBufWriterAppendBulkLen(&wr, '$', objlen);
713	
714	        /* Write the bulk data */
715	        if (argv[j]->encoding == OBJ_ENCODING_INT) {
716	            len = ll2string(aux, sizeof(aux), (long)argv[j]->ptr);
717	            replBufWriterAppend(&wr, aux, len);
718	        } else {
719	            replBufWriterAppend(&wr, argv[j]->ptr, objlen);
720	        }
721	        replBufWriterAppend(&wr, "\r\n", 2);
722	    }
723	
724	    replBufWriterEnd(&wr);
725	}
