763	/* This function is used in order to proxy what we receive from our master
764	 * to our sub-slaves. Besides, we also proxy the replication stream from
765	 * the source node when being in atomic slot migration. */
766	void replicationFeedStreamFromMasterStream(char *buf, size_t buflen) {
767	    /* There must be replication backlog if having attached slaves. */
768	    if (listLength(server.slaves)) serverAssert(server.repl_backlog != NULL);
769	    if (server.repl_backlog) {
770	        /* Must install write handler for all replicas first before feeding
771	         * replication stream. */
772	        prepareReplicasToWrite();
773	        feedReplicationBuffer(buf,buflen);
774	    } else if (server.masterhost == NULL && server.aof_enabled) {
775	        /* We increment the repl_offset anyway, since we use that for tracking
776	         * AOF fsyncs even when there's no replication active. This code will
777	         * not be reached if AOF is also disabled.
778	         *
779	         * As we skip feeding the replication buffer in atomic slot migration,
780	         * so here we need to update the replication offset manually. */
781	        server.master_repl_offset += 1;
782	    }
783	}
