371	static int tryAddPayload(client *c, char *buf, size_t *used, size_t size, uint8_t type, const void *payload, size_t len) {
372	    if (*used + sizeof(payloadHeader) + len > size) return 0;
373	
374	    /* Start a new payload chunk */
375	    payloadHeader *header = (payloadHeader *)(buf + *used);
376	    header->payload_type = type;
377	    header->payload_len = len;
378	    memcpy((char *)header + sizeof(payloadHeader), payload, len);
379	    *used += sizeof(payloadHeader) + len;
380	
381	    /* Track referenced reply bytes for copy avoidance. */
382	    if (type == BULK_STR_REF) {
383	        const bulkStrRef *str_ref = (const bulkStrRef *)payload;
384	        c->reply_bytes_shared += sdslen(str_ref->obj->ptr);
385	    }
386	
387	    return 1;
388	}
