390	/* Adds the payload to the reply linked list.
391	 * Note: some edits to this function need to be relayed to AddReplyFromClient. */
392	static void _addReplyPayloadToList(client *c, list *reply_list, const char *payload, size_t len, uint8_t payload_type) {
393	    listNode *ln = listLast(reply_list);
394	    clientReplyBlock *tail = ln ? listNodeValue(ln) : NULL;
395	    /* Determine if encoded buffer is required */
396	    int encoded = payload_type == BULK_STR_REF;
397	
398	    /* Note that 'tail' may be NULL even if we have a tail node, because when
399	     * addReplyDeferredLen() is used, it sets a dummy node to NULL just
400	     * to fill it later, when the size of the bulk length is set. */
401	
402	    /* Append to tail node when possible. */
403	    if (tail) {
404	        if (unlikely(tail->buf_encoded)) {
405	            /* Try to add to encoded buffer */
406	            if (tryAddPayload(c, tail->buf, &tail->used, tail->size, payload_type, (void *)payload, len)) {
407	                /* For BULK_STR_REF payloads, tryAddPayload updates shared reply bytes
408	                 * which accounts for referenced strings. */
409	                if (encoded) closeClientOnOutputBufferLimitReached(c, 1);
410	                return;
411	            }
412	        } else if (!encoded) {
413	            /* Both tail and new payload are non-encoded, can append directly */
414	            size_t avail = tail->size - tail->used;
415	            size_t copy = avail >= len ? len : avail;
416	            if (copy > 0) {
417	                memcpy(tail->buf + tail->used, payload, copy);
418	                tail->used += copy;
419	                payload += copy;
420	                len -= copy;
421	            }
422	        }
423	        /* else: tail is non-encoded but new payload needs encoding, can't append */
424	    }
425	
426	    if (len) {
427	        /* Create a new node, make sure it is allocated to at
428	         * least PROTO_REPLY_CHUNK_BYTES */
429	        size_t usable_size;
430	        size_t required_size = encoded ? len + sizeof(payloadHeader) : len;
431	        size_t size = required_size < PROTO_REPLY_CHUNK_BYTES ? PROTO_REPLY_CHUNK_BYTES : required_size;
432	        tail = zmalloc_usable(size + sizeof(clientReplyBlock), &usable_size);
433	        /* take over the allocation's internal fragmentation */
434	        tail->size = usable_size - sizeof(clientReplyBlock);
435	        tail->used = 0;
436	        tail->buf_encoded = encoded;
437	        if (tail->buf_encoded) {
438	            serverAssert(tryAddPayload(c, tail->buf, &tail->used, tail->size, payload_type, (void *)payload, len));
439	        } else {
440	            tail->used = len;
441	            memcpy(tail->buf, payload, len);
442	        }
443	        listAddNodeTail(reply_list, tail);
444	        c->reply_bytes += tail->size;
445	
446	        closeClientOnOutputBufferLimitReached(c, 1);
447	    }
448	}
