460	/* Attempts to add the reply to the static buffer in the client struct.
461	 * Returns the length of data that is added to the reply buffer. */
462	static size_t _addReplyPayloadToBuffer(client *c, const void *payload, size_t len, uint8_t payload_type) {
463	    /* If there already are entries in the reply list, we cannot
464	     * add anything more to the static buffer. */
465	    if (listLength(c->reply) > 0) return 0;
466	
467	    size_t available = c->buf_usable_size - c->bufpos;
468	    size_t reply_len = min(available, len);
469	    if (c->buf_encoded) {
470	        if (!tryAddPayload(c, c->buf, &c->bufpos, c->buf_usable_size, payload_type, payload, len))
471	            return 0;
472	        reply_len = len;
473	    } else {
474	        memcpy(c->buf + c->bufpos, payload, reply_len);
475	        c->bufpos+=reply_len;
476	    }
477	
478	    /* We update the buffer peak after appending the reply to the buffer */
479	    if (c->buf_peak < (size_t)c->bufpos) c->buf_peak = (size_t)c->bufpos;
480	    return reply_len;
481	}
