873	/* Sometimes we are forced to create a new reply node, and we can't append to
874	 * the previous one, when that happens, we wanna try to trim the unused space
875	 * at the end of the last reply node which we won't use anymore. */
876	void trimReplyUnusedTailSpace(client *c) {
877	    listNode *ln = listLast(c->reply);
878	    clientReplyBlock *tail = ln? listNodeValue(ln): NULL;
879	
880	    /* Note that 'tail' may be NULL even if we have a tail node, because when
881	     * addReplyDeferredLen() is used */
882	    if (!tail) return;
883	
884	    /* We only try to trim the space is relatively high (more than a 1/4 of the
885	     * allocation), otherwise there's a high chance realloc will NOP.
886	     * Also, to avoid large memmove which happens as part of realloc, we only do
887	     * that if the used part is small.  */
888	    if (tail->size - tail->used > tail->size / 4 &&
889	        tail->used < PROTO_REPLY_CHUNK_BYTES && !tail->buf_encoded)
890	    {
891	        size_t usable_size;
892	        size_t old_size = tail->size;
893	        tail = zrealloc_usable(tail, tail->used + sizeof(clientReplyBlock), &usable_size, NULL);
894	        /* take over the allocation's internal fragmentation (at least for
895	         * memory usage tracking) */
896	        tail->size = usable_size - sizeof(clientReplyBlock);
897	        c->reply_bytes = c->reply_bytes + tail->size - old_size;
898	        listNodeValue(ln) = tail;
899	    }
900	}
