902	/* Adds an empty object to the reply list that will contain the multi bulk
903	 * length, which is not known when this function is called. */
904	void *addReplyDeferredLen(client *c) {
905	    /* Note that we install the write event here even if the object is not
906	     * ready to be sent, since we are sure that before returning to the
907	     * event loop setDeferredAggregateLen() will be called. */
908	    if (_prepareClientToWrite(c) != C_OK) return NULL;
909	
910	    /* Replicas should normally not cause any writes to the reply buffer. In case a rogue replica sent a command on the
911	     * replication link that caused a reply to be generated we'll simply disconnect it.
912	     * Note this is the simplest way to check a command added a response. Replication links are used to write data but
913	     * not for responses, so we should normally never get here on a replica client. */
914	    if (unlikely(clientTypeIsSlave(c))) {
915	        sds cmdname = c->lastcmd ? c->lastcmd->fullname : NULL;
916	        logInvalidUseAndFreeClientAsync(c, "Replica generated a reply to command '%s'",
917	                                        cmdname ? cmdname : "<unknown>");
918	        return NULL;
919	    }
920	
921	    /* We call it here because this function conceptually affects the reply
922	     * buffer offset (see function comment) */
923	    reqresSaveClientReplyOffset(c);
924	
925	    trimReplyUnusedTailSpace(c);
926	    listAddNodeTail(c->reply,NULL); /* NULL is our placeholder. */
927	    return listLast(c->reply);
928	}
