930	void setDeferredReply(client *c, void *node, const char *s, size_t length) {
931	    listNode *ln = (listNode*)node;
932	    clientReplyBlock *next, *prev;
933	
934	    /* Abort when *node is NULL: when the client should not accept writes
935	     * we return NULL in addReplyDeferredLen() */
936	    if (node == NULL) return;
937	    serverAssert(!listNodeValue(ln));
938	
939	    /* Normally we fill this dummy NULL node, added by addReplyDeferredLen(),
940	     * with a new buffer structure containing the protocol needed to specify
941	     * the length of the array following. However sometimes there might be room
942	     * in the previous/next node so we can instead remove this NULL node, and
943	     * suffix/prefix our data in the node immediately before/after it, in order
944	     * to save a write(2) syscall later. Conditions needed to do it:
945	     *
946	     * - The prev node is non-NULL and has space in it or
947	     * - The next node is non-NULL,
948	     * - It has enough room already allocated
949	     * - And not too large (avoid large memmove) */
950	    if (ln->prev != NULL && (prev = listNodeValue(ln->prev)) &&
951	        prev->used < prev->size && !prev->buf_encoded)
952	    {
953	        size_t len_to_copy = prev->size - prev->used;
954	        if (len_to_copy > length)
955	            len_to_copy = length;
956	        memcpy(prev->buf + prev->used, s, len_to_copy);
957	        c->net_output_bytes_curr_cmd += len_to_copy;
958	        prev->used += len_to_copy;
959	        length -= len_to_copy;
960	        if (length == 0) {
961	            listDelNode(c->reply, ln);
962	            return;
963	        }
964	        s += len_to_copy;
965	    }
966	
967	    if (ln->next != NULL && (next = listNodeValue(ln->next)) &&
968	        next->size - next->used >= length &&
969	        next->used < PROTO_REPLY_CHUNK_BYTES * 4 &&
970	        !next->buf_encoded)
971	    {
972	        memmove(next->buf + length, next->buf, next->used);
973	        memcpy(next->buf, s, length);
974	        c->net_output_bytes_curr_cmd += length;
975	        next->used += length;
976	        listDelNode(c->reply,ln);
977	    } else {
978	        /* Create a new node */
979	        size_t usable_size;
980	        clientReplyBlock *buf = zmalloc_usable(length + sizeof(clientReplyBlock), &usable_size);
981	        /* Take over the allocation's internal fragmentation */
982	        buf->size = usable_size - sizeof(clientReplyBlock);
983	        buf->used = length;
984	        buf->buf_encoded = 0;
985	        memcpy(buf->buf, s, length);
986	        c->net_output_bytes_curr_cmd += length;
987	        listNodeValue(ln) = buf;
988	        c->reply_bytes += buf->size;
989	
990	        closeClientOnOutputBufferLimitReached(c, 1);
991	    }
992	}
