1642	void acceptCommonHandler(connection *conn, int flags, char *ip) {
1643	    client *c;
1644	    UNUSED(ip);
1645	
1646	    if (connGetState(conn) != CONN_STATE_ACCEPTING) {
1647	        char addr[NET_ADDR_STR_LEN] = {0};
1648	        char laddr[NET_ADDR_STR_LEN] = {0};
1649	        connFormatAddr(conn, addr, sizeof(addr), 1);
1650	        connFormatAddr(conn, laddr, sizeof(laddr), 0);
1651	        serverLog(LL_VERBOSE,
1652	                  "Accepted client connection in error state: %s (addr=%s laddr=%s)",
1653	                  connGetLastError(conn), addr, laddr);
1654	        connClose(conn);
1655	        return;
1656	    }
1657	
1658	    /* Limit the number of connections we take at the same time.
1659	     *
1660	     * Admission control will happen before a client is created and connAccept()
1661	     * called, because we don't want to even start transport-level negotiation
1662	     * if rejected. */
1663	    if (listLength(server.clients) + getClusterConnectionsCount()
1664	        >= server.maxclients)
1665	    {
1666	        char *err;
1667	        if (server.cluster_enabled)
1668	            err = "-ERR max number of clients + cluster "
1669	                  "connections reached\r\n";
1670	        else
1671	            err = "-ERR max number of clients reached\r\n";
1672	
1673	        /* That's a best effort error message, don't check write errors.
1674	         * Note that for TLS connections, no handshake was done yet so nothing
1675	         * is written and the connection will just drop. */
1676	        if (connWrite(conn,err,strlen(err)) == -1) {
1677	            /* Nothing to do, Just to avoid the warning... */
1678	        }
1679	        server.stat_rejected_conn++;
1680	        connClose(conn);
1681	        return;
1682	    }
1683	
1684	    /* Create connection and client */
1685	    if ((c = createClient(conn)) == NULL) {
1686	        char addr[NET_ADDR_STR_LEN] = {0};
1687	        char laddr[NET_ADDR_STR_LEN] = {0};
1688	        connFormatAddr(conn, addr, sizeof(addr), 1);
1689	        connFormatAddr(conn, laddr, sizeof(laddr), 0);
1690	        serverLog(LL_WARNING,
1691	                  "Error registering fd event for the new client connection: %s (addr=%s laddr=%s)",
1692	                  connGetLastError(conn), addr, laddr);
1693	        connClose(conn); /* May be already closed, just ignore errors */
1694	        return;
1695	    }
1696	
1697	    /* Last chance to keep flags */
1698	    c->flags |= flags;
1699	
1700	    /* Initiate accept.
1701	     *
1702	     * Note that connAccept() is free to do two things here:
1703	     * 1. Call clientAcceptHandler() immediately;
1704	     * 2. Schedule a future call to clientAcceptHandler().
1705	     *
1706	     * Because of that, we must do nothing else afterwards.
1707	     */
1708	    if (connAccept(conn, clientAcceptHandler) == C_ERR) {
1709	        if (connGetState(conn) == CONN_STATE_ERROR)
1710	            serverLog(LL_WARNING,
1711	                      "Error accepting a client connection: %s (addr=%s laddr=%s)",
1712	                      connGetLastError(conn), getClientPeerId(c), getClientSockname(c));
1713	        freeClient(connGetPrivateData(conn));
1714	        return;
1715	    }
1716	}
