205	            snprintf(buf,sizeof(buf),"%s:<unknown-replica-port>",addr);
206	    } else {
207	        snprintf(buf,sizeof(buf),"client id #%llu",
208	            (unsigned long long) c->id);
209	    }
210	    return buf;
211	}
212	
213	/* Plain unlink() can block for quite some time in order to actually apply
214	 * the file deletion to the filesystem. This call removes the file in a
215	 * background thread instead. We actually just do close() in the thread,
216	 * by using the fact that if there is another instance of the same file open,
217	 * the foreground unlink() will only remove the fs name, and deleting the
218	 * file's storage space will only happen once the last reference is lost. */
219	int bg_unlink(const char *filename) {
220	    int fd = open(filename,O_RDONLY|O_NONBLOCK);
221	    if (fd == -1) {
222	        /* Can't open the file? Fall back to unlinking in the main thread. */
223	        return unlink(filename);
224	    } else {
225	        /* The following unlink() removes the name but doesn't free the
226	         * file contents because a process still has it open. */
227	        int retval = unlink(filename);
228	        if (retval == -1) {
229	            /* If we got an unlink error, we just return it, closing the
230	             * new reference we have to the file. */
231	            int old_errno = errno;
232	            close(fd);  /* This would overwrite our errno. So we saved it. */
233	            errno = old_errno;
234	            return -1;
235	        }
236	        bioCreateCloseJob(fd, 0, 0);
237	        return 0; /* Success. */
238	    }
239	}
