242	
243	void createReplicationBacklog(void) {
244	    serverAssert(server.repl_backlog == NULL);
245	    server.repl_backlog = zmalloc(sizeof(replBacklog));
246	    server.repl_backlog->ref_repl_buf_node = NULL;
247	    server.repl_backlog->unindexed_count = 0;
248	    server.repl_backlog->blocks_index = raxNew();
249	    server.repl_backlog->histlen = 0;
250	    /* We don't have any data inside our buffer, but virtually the first
251	     * byte we have is the next byte that will be generated for the
252	     * replication stream. */
253	    server.repl_backlog->offset = server.master_repl_offset+1;
254	}
255	
256	/* This function is called when the user modifies the replication backlog
257	 * size at runtime. It is up to the function to resize the buffer and setup it
258	 * so that it contains the same data as the previous one (possibly less data,
259	 * but the most recent bytes, or the same data and more free space in case the
260	 * buffer is enlarged). */
261	void resizeReplicationBacklog(void) {
262	    if (server.repl_backlog_size < CONFIG_REPL_BACKLOG_MIN_SIZE)
263	        server.repl_backlog_size = CONFIG_REPL_BACKLOG_MIN_SIZE;
264	    if (server.repl_backlog)
265	        incrementalTrimReplicationBacklog(REPL_BACKLOG_TRIM_BLOCKS_PER_CALL);
266	}
267	
268	void freeReplicationBacklog(void) {
269	    serverAssert(listLength(server.slaves) == 0);
270	    if (server.repl_backlog == NULL) return;
271	
272	    /* Decrease the start buffer node reference count. */
273	    if (server.repl_backlog->ref_repl_buf_node) {
274	        replBufBlock *o = listNodeValue(
275	            server.repl_backlog->ref_repl_buf_node);
276	        serverAssert(o->refcount == 1); /* Last reference. */
277	        o->refcount--;
278	    }
279	
280	    /* Replication buffer blocks are completely released when we free the
281	     * backlog, since the backlog is released only when there are no replicas
282	     * and the backlog keeps the last reference of all blocks. */
283	    freeReplicationBacklogRefMemAsync(server.repl_buffer_blocks,
284	                            server.repl_backlog->blocks_index);
285	    resetReplicationBuffer();
286	    zfree(server.repl_backlog);
287	    server.repl_backlog = NULL;
288	}
289	
290	/* To make search offset from replication buffer blocks quickly
291	 * when replicas ask partial resynchronization, we create one index
292	 * block every REPL_BACKLOG_INDEX_PER_BLOCKS blocks. */
293	void createReplicationBacklogIndex(listNode *ln) {
294	    server.repl_backlog->unindexed_count++;
295	    if (server.repl_backlog->unindexed_count >= REPL_BACKLOG_INDEX_PER_BLOCKS) {
296	        replBufBlock *o = listNodeValue(ln);
297	        uint64_t encoded_offset = htonu64(o->repl_offset);
298	        raxInsert(server.repl_backlog->blocks_index,
299	                  (unsigned char*)&encoded_offset, sizeof(uint64_t),
300	                  ln, NULL);
301	        server.repl_backlog->unindexed_count = 0;
302	    }
303	}
304	
305	/* Rebase replication buffer blocks' offset since the initial
306	 * setting offset starts from 0 when master restart. */
307	void rebaseReplicationBuffer(long long base_repl_offset) {
308	    raxFree(server.repl_backlog->blocks_index);
309	    server.repl_backlog->blocks_index = raxNew();
310	    server.repl_backlog->unindexed_count = 0;
311	
312	    listIter li;
313	    listNode *ln;
314	    listRewind(server.repl_buffer_blocks, &li);
315	    while ((ln = listNext(&li))) {
316	        replBufBlock *o = listNodeValue(ln);
317	        o->repl_offset += base_repl_offset;
318	        createReplicationBacklogIndex(ln);
319	    }
320	}
