328	int canFeedReplicaReplBuffer(client *replica) {
329	    /* Don't feed replicas that only want the RDB or main channels of migration
330	     * destinations which need filtered stream for migrating slot ranges. */
331	    if (replica->flags & CLIENT_REPL_RDBONLY ||
332	        replica->flags & CLIENT_ASM_MIGRATING) return 0;
333	
334	    /* Don't feed replicas that are still waiting for BGSAVE to start. */
335	    if (replica->replstate == SLAVE_STATE_WAIT_BGSAVE_START ||
336	        replica->replstate == SLAVE_STATE_WAIT_RDB_CHANNEL) return 0;
337	
338	    /* Don't feed replicas that are going to be closed ASAP. */
339	    if (replica->flags & CLIENT_CLOSE_ASAP) return 0;
340	
341	    return 1;
342	}
