344	/* Create the replication backlog if needed. */
345	void createReplicationBacklogIfNeeded(void) {
346	    if (listLength(server.slaves) == 1 && server.repl_backlog == NULL) {
347	        /* When we create the backlog from scratch, we always use a new
348	         * replication ID and clear the ID2, since there is no valid
349	         * past history. */
350	        changeReplicationId();
351	        clearReplicationId2();
352	        createReplicationBacklog();
353	        serverLog(LL_NOTICE,"Replication backlog created, my new "
354	                            "replication IDs are '%s' and '%s'",
355	                            server.replid, server.replid2);
356	    }
357	}
358	/* Similar with 'prepareClientToWrite', note that we must call this function
359	 * before feeding replication stream into global replication buffer, since
360	 * clientHasPendingReplies in prepareClientToWrite will access the global
361	 * replication buffer to make judgements. */
362	int prepareReplicasToWrite(void) {
363	    listIter li;
364	    listNode *ln;
365	    int prepared = 0;
366	
367	    listRewind(server.slaves,&li);
368	    while((ln = listNext(&li))) {
369	        client *slave = ln->value;
370	        if (!canFeedReplicaReplBuffer(slave)) continue;
371	        if (prepareClientToWrite(slave) == C_ERR) continue;
372	        prepared++;
373	    }
374	
375	    return prepared;
376	}
