378	/* Generally, we only have one replication buffer block to trim when replication
379	 * backlog size exceeds our setting and no replica reference it. But if replica
380	 * clients disconnect, we need to free many replication buffer blocks that are
381	 * referenced. It would cost much time if there are a lots blocks to free, that
382	 * will freeze server, so we trim replication backlog incrementally. */
383	void incrementalTrimReplicationBacklog(size_t max_blocks) {
384	    serverAssert(server.repl_backlog != NULL);
385	
386	    size_t trimmed_blocks = 0;
387	    while (server.repl_backlog->histlen > server.repl_backlog_size &&
388	           trimmed_blocks < max_blocks)
389	    {
390	        /* We never trim backlog to less than one block. */
391	        if (listLength(server.repl_buffer_blocks) <= 1) break;
392	
393	        /* Replicas increment the refcount of the first replication buffer block
394	         * they refer to, in that case, we don't trim the backlog even if
395	         * backlog_histlen exceeds backlog_size. This implicitly makes backlog
396	         * bigger than our setting, but makes the master accept partial resync as
397	         * much as possible. So that backlog must be the last reference of
398	         * replication buffer blocks. */
399	        listNode *first = listFirst(server.repl_buffer_blocks);
400	        serverAssert(first == server.repl_backlog->ref_repl_buf_node);
401	        replBufBlock *fo = listNodeValue(first);
402	        if (fo->refcount != 1) break;
403	
404	        /* We don't try trim backlog if backlog valid size will be lessen than
405	         * setting backlog size once we release the first repl buffer block. */
406	        if (server.repl_backlog->histlen - (long long)fo->size <=
407	            server.repl_backlog_size) break;
408	
409	        /* Decr refcount and release the first block later. */
410	        fo->refcount--;
411	        trimmed_blocks++;
412	        server.repl_backlog->histlen -= fo->size;
413	
414	        /* Go to use next replication buffer block node. */
415	        listNode *next = listNextNode(first);
416	        server.repl_backlog->ref_repl_buf_node = next;
417	        serverAssert(server.repl_backlog->ref_repl_buf_node != NULL);
418	        /* Incr reference count to keep the new head node. */
419	        ((replBufBlock *)listNodeValue(next))->refcount++;
420	
421	        /* Remove the node in recorded blocks. */
422	        uint64_t encoded_offset = htonu64(fo->repl_offset);
423	        raxRemove(server.repl_backlog->blocks_index,
424	            (unsigned char*)&encoded_offset, sizeof(uint64_t), NULL);
425	
426	        /* Delete the first node from global replication buffer. */
427	        serverAssert(fo->refcount == 0 && fo->used == fo->size);
428	        server.repl_buffer_mem -= (fo->size +
429	            sizeof(listNode) + sizeof(replBufBlock));
430	        listDelNode(server.repl_buffer_blocks, first);
431	    }
432	
433	    /* Set the offset of the first byte we have in the backlog. */
434	    server.repl_backlog->offset = server.master_repl_offset -
435	                              server.repl_backlog->histlen + 1;
436	}
