438	/* Free replication buffer blocks that are referenced by this client. */
439	void freeReplicaReferencedReplBuffer(client *replica) {
440	    serverAssert(replica->running_tid == IOTHREAD_MAIN_THREAD_ID);
441	
442	    if (replica->ref_repl_buf_node != NULL) {
443	        /* Decrease the start buffer node reference count. */
444	        replBufBlock *o = listNodeValue(replica->ref_repl_buf_node);
445	        serverAssert(o->refcount > 0);
446	        o->refcount--;
447	        incrementalTrimReplicationBacklog(REPL_BACKLOG_TRIM_BLOCKS_PER_CALL);
448	    }
449	    replica->ref_repl_buf_node = NULL;
450	    replica->ref_block_pos = 0;
451	}
452	
453	/* Batched write API for the global replication backlog, optimized for minimal
454	 * overhead per append: data writes are just memcpys into the tail block.
455	 * All bookkeeping is deferred to replBufWriterEnd(). */
456	typedef struct replBufWriter {
457	    listNode *start_node;  /* First repl buffer block written to. */
458	    size_t start_pos;      /* Byte offset within start_node where writing began. */
459	    size_t total_len;      /* Total bytes written across all writes. */
460	    int new_blocks;        /* Number of new blocks allocated during this stream. */
461	    replBufBlock *tail;    /* Current tail block. */
462	} replBufWriter;
463	
464	/* Initialize the writer, cache the current tail position. */
465	static void replBufWriterBegin(replBufWriter *wr) {
466	    listNode *ln = listLast(server.repl_buffer_blocks);
467	    replBufBlock *tail = ln ? listNodeValue(ln) : NULL;
468	
469	    if (tail && tail->used < tail->size) {
470	        wr->start_node = ln;
471	        wr->start_pos = tail->used;
472	    } else {
473	        wr->start_node = NULL;
474	        wr->start_pos = 0;
475	    }
476	
477	    wr->total_len = 0;
478	    wr->new_blocks = 0;
479	    wr->tail = tail;
480	}
481	
482	/* Allocate a new replication backlog block. Called when current block is full. */
483	static void replBufWriterAllocBlock(replBufWriter *wr, size_t hint) {
484	    static long long repl_block_id = 0;
485	    size_t usable_size;
486	    /* Avoid creating nodes smaller than PROTO_REPLY_CHUNK_BYTES, so that we can append more data into them,
487	     * and also avoid creating nodes bigger than repl_backlog_size / 16, so that we won't have huge nodes that can't
488	     * trim when we only still need to hold a small portion from them. */
489	    size_t limit = max((size_t)server.repl_backlog_size / 16, (size_t)PROTO_REPLY_CHUNK_BYTES);
490	    size_t bsize = min(max(hint, (size_t)PROTO_REPLY_CHUNK_BYTES), limit);
491	    replBufBlock *tail = zmalloc_usable(bsize + sizeof(replBufBlock), &usable_size);
492	    /* Take over the allocation's internal fragmentation */
493	    tail->size = usable_size - sizeof(replBufBlock);
494	    tail->used = 0;
495	    tail->refcount = 0;
496	    tail->repl_offset = server.master_repl_offset + wr->total_len + 1;
497	    tail->id = repl_block_id++;
498	    listAddNodeTail(server.repl_buffer_blocks, tail);
499	    server.repl_buffer_mem += (usable_size + sizeof(listNode));
500	    createReplicationBacklogIndex(listLast(server.repl_buffer_blocks));
501	
502	    /* Update stream state. */
503	    wr->tail = tail;
504	    wr->new_blocks++;
505	    if (wr->start_node == NULL) {
506	        wr->start_node = listLast(server.repl_buffer_blocks);
507	        wr->start_pos = 0;
508	    }
509	}
510	
511	/* Slow path: fill remainder of current block + allocate as needed. */
512	static void replBufWriterAppendSlow(replBufWriter *wr, const char *buf, size_t len) {
513	    while (len > 0) {
514	        size_t avail = wr->tail ? wr->tail->size - wr->tail->used : 0;
515	        if (avail > 0) {
516	            size_t copy = (avail >= len) ? len : avail;
517	            memcpy(wr->tail->buf + wr->tail->used, buf, copy);
518	            wr->tail->used += copy;
519	            wr->total_len += copy;
520	            buf += copy;
521	            len -= copy;
522	        }
523	
524	        if (len > 0)
525	            replBufWriterAllocBlock(wr, len);
526	    }
527	}
528	
529	/* Write data into the replication buffer. The slow path is split out to give 
530	 * the compiler a chance to inline the common case where the write fits entirely
531	 * in the current block. */
532	static inline void replBufWriterAppend(replBufWriter *wr, const char *buf, size_t len) {
533	    size_t avail = wr->tail ? wr->tail->size - wr->tail->used : 0;
534	    if (len > 0 && avail >= len) {
535	        memcpy(wr->tail->buf + wr->tail->used, buf, len);
536	        wr->tail->used += len;
537	        wr->total_len += len;
538	        return;
539	    }
540	    replBufWriterAppendSlow(wr, buf, len);
541	}
542	
543	/* Write a RESP header prefix<value>\r\n (e.g. "$12\r\n" or "*3\r\n").
544	 * Uses pre-built shared objects for small values, formats manually otherwise. */
545	static inline void replBufWriterAppendBulkLen(replBufWriter *wr, char prefix, long long value) {
546	    serverAssert(prefix == '$' || prefix == '*');
547	    if (value >= 0 && value < OBJ_SHARED_BULKHDR_LEN) {
548	        robj **tbl = (prefix == '$') ? shared.bulkhdr : shared.mbulkhdr;
549	        replBufWriterAppend(wr, tbl[value]->ptr, OBJ_SHARED_HDR_STRLEN(value));
550	        return;
551	    }
552	    char buf[LONG_STR_SIZE+3];
553	    buf[0] = prefix;
554	    int len = ll2string(buf+1, sizeof(buf)-1, value);
555	    buf[len+1] = '\r';
556	    buf[len+2] = '\n';
557	    replBufWriterAppend(wr, buf, len+3);
558	}
559	
560	
561	/* Finalize the replication buffer write: update global offsets, set up replica
562	 * references for new data, check output buffer limits, and trim the
563	 * backlog if new blocks were allocated. */
564	static void replBufWriterEnd(replBufWriter *wr) {
565	    if (wr->total_len == 0) return;
566	
567	    serverAssert(wr->start_node != NULL);
568	    clusterSlotStatsIncrNetworkBytesOutForReplication(wr->total_len);
569	
570	    /* Update the current cmd's keys with the commands replication bytes*/
571	    hotkeyMetrics metrics = {0, wr->total_len};
572	    hotkeyStatsUpdateCurrentCmd(server.hotkeys, metrics);
573	
574	    server.master_repl_offset += wr->total_len;
575	    server.repl_backlog->histlen += wr->total_len;
576	
577	    /* For output buffer of replicas. */
578	    listIter li;
579	    listNode *ln;
580	    listRewind(server.slaves,&li);
581	    while((ln = listNext(&li))) {
582	        client *slave = ln->value;
583	        if (!canFeedReplicaReplBuffer(slave)) continue;
584	
585	        /* Update shared replication buffer start position. */
586	        if (slave->ref_repl_buf_node == NULL) {
587	            slave->ref_repl_buf_node = wr->start_node;
588	            slave->ref_block_pos = wr->start_pos;
589	            /* Only increase the start block reference count. */
590	            ((replBufBlock *)listNodeValue(wr->start_node))->refcount++;
591	        }
592	
593	        /* Check output buffer limit only when new blocks were added. */
594	        if (wr->new_blocks) closeClientOnOutputBufferLimitReached(slave, 1);
595	    }
596	
597	    /* For replication backlog */
598	    if (server.repl_backlog->ref_repl_buf_node == NULL) {
599	        server.repl_backlog->ref_repl_buf_node = wr->start_node;
600	        /* Only increase the start block reference count. */
601	        ((replBufBlock *)listNodeValue(wr->start_node))->refcount++;
602	
603	        /* Replication buffer must be empty before adding replication stream
604	         * into replication backlog. */
605	        serverAssert(wr->new_blocks > 0 && wr->start_pos == 0);
606	    }
607	    if (wr->new_blocks) {
608	        /* It is important to trim after adding replication data to keep the backlog size close to
609	         * repl_backlog_size in the common case. We wait until we add a new block to avoid repeated
610	         * unnecessary trimming attempts when small amounts of data are added. See comments in
611	         * freeMemoryGetNotCountedMemory() for details on replication backlog memory tracking. */
612	        incrementalTrimReplicationBacklog(REPL_BACKLOG_TRIM_BLOCKS_PER_CALL);
613	    }
614	}
615	
616	/* Append bytes into the global replication buffer. */
617	static void feedReplicationBuffer(const char *buf, size_t len) {
618	    replBufWriter wr;
619	    replBufWriterBegin(&wr);
620	    replBufWriterAppend(&wr, buf, len);
621	    replBufWriterEnd(&wr);
622	}
623	
624	/* Propagate write commands to replication stream.
625	 *
626	 * This function is used if the instance is a master: we use the commands
627	 * received by our clients in order to create the replication stream.
628	 * Instead if the instance is a replica and has sub-replicas attached, we use
629	 * replicationFeedStreamFromMasterStream() */
630	void replicationFeedSlaves(list *slaves, int dictid, robj **argv, int argc) {
631	    int j, len;
632	    char llstr[LONG_STR_SIZE];
633	
634	    /* In case we propagate a command that doesn't touch keys (PING, REPLCONF) we
635	     * pass dbid=-1 that indicate there is no need to replicate `select` command. */
636	    serverAssert(dictid == -1 || (dictid >= 0 && dictid < server.dbnum));
637	
638	    /* If the instance is not a top level master, return ASAP: we'll just proxy
639	     * the stream of data we receive from our master instead, in order to
640	     * propagate *identical* replication stream. In this way this slave can
641	     * advertise the same replication ID as the master (since it shares the
642	     * master replication history and has the same backlog and offsets). */
643	    if (server.masterhost != NULL) return;
644	
645	    /* If current client is marked as master, we will proxy the command stream
646	     * to our slaves instead of replicating them, that also happens when being
647	     * in atomic slot migration. */
648	    if (server.current_client && server.current_client->flags & CLIENT_MASTER) return;
649	
650	    /* If there aren't slaves, and there is no backlog buffer to populate,
651	     * we can return ASAP. */
652	    if (server.repl_backlog == NULL && listLength(slaves) == 0) {
653	        /* We increment the repl_offset anyway, since we use that for tracking AOF fsyncs
654	         * even when there's no replication active. This code will not be reached if AOF
655	         * is also disabled. */
656	        server.master_repl_offset += 1;
657	        return;
658	    }
659	
660	    /* We can't have slaves attached and no backlog. */
661	    serverAssert(!(listLength(slaves) != 0 && server.repl_backlog == NULL));
662	
663	    /* Update the time of sending replication stream to replicas. */
664	    server.repl_stream_lastio = server.unixtime;
665	
666	    /* Must install write handler for all replicas first before feeding
667	     * replication stream. */
668	    prepareReplicasToWrite();
669	
670	    /* Send SELECT command to every slave if needed. */
671	    if (dictid != -1 && server.slaveseldb != dictid) {
672	        robj *selectcmd;
673	
674	        /* For a few DBs we have pre-computed SELECT command. */
675	        if (dictid >= 0 && dictid < PROTO_SHARED_SELECT_CMDS) {
676	            selectcmd = shared.select[dictid];
677	        } else {
678	            int dictid_len;
679	
680	            dictid_len = ll2string(llstr,sizeof(llstr),dictid);
681	            selectcmd = createObject(OBJ_STRING,
682	                sdscatprintf(sdsempty(),
683	                "*2\r\n$6\r\nSELECT\r\n$%d\r\n%s\r\n",
684	                dictid_len, llstr));
685	        }
686	
687	        feedReplicationBuffer(selectcmd->ptr, sdslen(selectcmd->ptr));
688	
689	        /* Although the SELECT command is not associated with any slot,
690	         * its per-slot network-bytes-out accumulation is made by the above function call.
691	         * To cancel-out this accumulation, below adjustment is made. */
692	        clusterSlotStatsDecrNetworkBytesOutForReplication(sdslen(selectcmd->ptr));
693	
694	        if (dictid < 0 || dictid >= PROTO_SHARED_SELECT_CMDS)
695	            decrRefCount(selectcmd);
696	
697	        server.slaveseldb = dictid;
698	    }
699	
700	    /* Write the command to the replication buffer if any. */
701	    char aux[LONG_STR_SIZE+3];
702	    replBufWriter wr;
703	    replBufWriterBegin(&wr);
704	
705	    /* Write the multi bulk count */
706	    replBufWriterAppendBulkLen(&wr, '*', argc);
707	
708	    for (j = 0; j < argc; j++) {
709	        /* Write the bulk count */
710	        long objlen = stringObjectLen(argv[j]);
711	        replBufWriterAppendBulkLen(&wr, '$', objlen);
712	
713	        /* Write the bulk data */
714	        if (argv[j]->encoding == OBJ_ENCODING_INT) {
715	            len = ll2string(aux, sizeof(aux), (long)argv[j]->ptr);
716	            replBufWriterAppend(&wr, aux, len);
717	        } else {
718	            replBufWriterAppend(&wr, argv[j]->ptr, objlen);
719	        }
720	        replBufWriterAppend(&wr, "\r\n", 2);
721	    }
722	
723	    replBufWriterEnd(&wr);
724	}
725	
726	/* This is a debugging function that gets called when we detect something
727	 * wrong with the replication protocol: the goal is to peek into the
728	 * replication backlog and show a few final bytes to make simpler to
729	 * guess what kind of bug it could be. */
730	void showLatestBacklog(void) {
731	    if (server.repl_backlog == NULL) return;
732	    if (listLength(server.repl_buffer_blocks) == 0) return;
733	    if (server.hide_user_data_from_log) {
734	        serverLog(LL_NOTICE,"hide-user-data-from-log is on, skip logging backlog content to avoid spilling PII.");
735	        return;
736	    }
737	
738	    size_t dumplen = 256;
739	    if (server.repl_backlog->histlen < (long long)dumplen)
740	        dumplen = server.repl_backlog->histlen;
741	
742	    sds dump = sdsempty();
743	    listNode *node = listLast(server.repl_buffer_blocks);
744	    while(dumplen) {
745	        if (node == NULL) break;
746	        replBufBlock *o = listNodeValue(node);
747	        size_t thislen = o->used >= dumplen ? dumplen : o->used;
748	        sds head = sdscatrepr(sdsempty(), o->buf+o->used-thislen, thislen);
749	        sds tmp = sdscatsds(head, dump);
750	        sdsfree(dump);
751	        dump = tmp;
752	        dumplen -= thislen;
753	        node = listPrevNode(node);
754	    }
755	
756	    /* Finally log such bytes: this is vital debugging info to
757	     * understand what happened. */
758	    serverLog(LL_NOTICE,"Latest backlog is: '%s'", dump);
759	    sdsfree(dump);
760	}
