762	/* This function is used in order to proxy what we receive from our master
763	 * to our sub-slaves. Besides, we also proxy the replication stream from
764	 * the source node when being in atomic slot migration. */
765	void replicationFeedStreamFromMasterStream(char *buf, size_t buflen) {
766	    /* There must be replication backlog if having attached slaves. */
767	    if (listLength(server.slaves)) serverAssert(server.repl_backlog != NULL);
768	    if (server.repl_backlog) {
769	        /* Must install write handler for all replicas first before feeding
770	         * replication stream. */
771	        prepareReplicasToWrite();
772	        feedReplicationBuffer(buf,buflen);
773	    } else if (server.masterhost == NULL && server.aof_enabled) {
774	        /* We increment the repl_offset anyway, since we use that for tracking
775	         * AOF fsyncs even when there's no replication active. This code will
776	         * not be reached if AOF is also disabled.
777	         *
778	         * As we skip feeding the replication buffer in atomic slot migration,
779	         * so here we need to update the replication offset manually. */
780	        server.master_repl_offset += 1;
781	    }
782	}
