784	void replicationFeedMonitors(client *c, list *monitors, int dictid, robj **argv, int argc) {
785	    /* Fast path to return if the monitors list is empty or the server is in loading. */
786	    if (monitors == NULL || listLength(monitors) == 0 || server.loading) return;
787	    listNode *ln;
788	    listIter li;
789	    int j;
790	    sds cmdrepr = sdsnew("+");
791	    robj *cmdobj;
792	    struct timeval tv;
793	
794	    gettimeofday(&tv,NULL);
795	    cmdrepr = sdscatprintf(cmdrepr,"%ld.%06ld ",(long)tv.tv_sec,(long)tv.tv_usec);
796	    if (c->flags & CLIENT_SCRIPT) {
797	        cmdrepr = sdscatprintf(cmdrepr,"[%d lua] ",dictid);
798	    } else if (c->flags & CLIENT_UNIX_SOCKET) {
799	        cmdrepr = sdscatprintf(cmdrepr,"[%d unix:%s] ",dictid,server.unixsocket);
800	    } else {
801	        cmdrepr = sdscatprintf(cmdrepr,"[%d %s] ",dictid,getClientPeerId(c));
802	    }
803	
804	    for (j = 0; j < argc; j++) {
805	        if (argv[j]->encoding == OBJ_ENCODING_INT) {
806	            cmdrepr = sdscatprintf(cmdrepr, "\"%ld\"", (long)argv[j]->ptr);
807	        } else {
808	            cmdrepr = sdscatrepr(cmdrepr,(char*)argv[j]->ptr,
809	                        sdslen(argv[j]->ptr));
810	        }
811	        if (j != argc-1)
812	            cmdrepr = sdscatlen(cmdrepr," ",1);
813	    }
814	    cmdrepr = sdscatlen(cmdrepr,"\r\n",2);
815	    cmdobj = createObject(OBJ_STRING,cmdrepr);
816	
817	    listRewind(monitors,&li);
818	    while((ln = listNext(&li))) {
819	        client *monitor = ln->value;
820	        /* Do not show internal commands to non-internal clients. */
821	        if (c->realcmd && (c->realcmd->flags & CMD_INTERNAL) && !(monitor->flags & CLIENT_INTERNAL)) {
822	            continue;
823	        }
824	        addReply(monitor,cmdobj);
825	        updateClientMemUsageAndBucket(monitor);
826	    }
827	    decrRefCount(cmdobj);
828	}
