830	/* Feed the slave 'c' with the replication backlog starting from the
831	 * specified 'offset' up to the end of the backlog. */
832	long long addReplyReplicationBacklog(client *c, long long offset) {
833	    serverAssert(c->running_tid == IOTHREAD_MAIN_THREAD_ID);
834	
835	    long long skip;
836	
837	    serverLog(LL_DEBUG, "[PSYNC] Replica request offset: %lld", offset);
838	
839	    if (server.repl_backlog->histlen == 0) {
840	        serverLog(LL_DEBUG, "[PSYNC] Backlog history len is zero");
841	        return 0;
842	    }
843	
844	    serverLog(LL_DEBUG, "[PSYNC] Backlog size: %lld",
845	             server.repl_backlog_size);
846	    serverLog(LL_DEBUG, "[PSYNC] First byte: %lld",
847	             server.repl_backlog->offset);
848	    serverLog(LL_DEBUG, "[PSYNC] History len: %lld",
849	             server.repl_backlog->histlen);
850	
851	    /* Compute the amount of bytes we need to discard. */
852	    skip = offset - server.repl_backlog->offset;
853	    serverLog(LL_DEBUG, "[PSYNC] Skipping: %lld", skip);
854	
855	    /* Iterate recorded blocks, quickly search the approximate node. */
856	    listNode *node = NULL;
857	    if (raxSize(server.repl_backlog->blocks_index) > 0) {
858	        uint64_t encoded_offset = htonu64(offset);
859	        raxIterator ri;
860	        raxStart(&ri, server.repl_backlog->blocks_index);
861	        raxSeek(&ri, ">", (unsigned char*)&encoded_offset, sizeof(uint64_t));
862	        if (raxEOF(&ri)) {
863	            /* No found, so search from the last recorded node. */
864	            raxSeek(&ri, "$", NULL, 0);
865	            raxPrev(&ri);
866	            node = (listNode *)ri.data;
867	        } else {
868	            raxPrev(&ri); /* Skip the sought node. */
869	            /* We should search from the prev node since the offset of current
870	             * sought node exceeds searching offset. */
871	            if (raxPrev(&ri))
872	                node = (listNode *)ri.data;
873	            else
874	                node = server.repl_backlog->ref_repl_buf_node;
875	        }
876	        raxStop(&ri);
877	    } else {
878	        /* No recorded blocks, just from the start node to search. */
879	        node = server.repl_backlog->ref_repl_buf_node;
880	    }
881	
882	    /* Search the exact node. */
883	    while (node != NULL) {
884	        replBufBlock *o = listNodeValue(node);
885	        if (o->repl_offset + (long long)o->used >= offset) break;
886	        node = listNextNode(node);
887	    }
888	    serverAssert(node != NULL);
889	
890	    /* Install a writer handler first.*/
891	    prepareClientToWrite(c);
892	    /* Setting output buffer of the replica. */
893	    replBufBlock *o = listNodeValue(node);
894	    o->refcount++;
895	    c->ref_repl_buf_node = node;
896	    c->ref_block_pos = offset - o->repl_offset;
897	
898	    return server.repl_backlog->histlen - skip;
899	}
