909	/* Send a FULLRESYNC reply in the specific case of a full resynchronization,
910	 * as a side effect setup the slave for a full sync in different ways:
911	 *
912	 * 1) Remember, into the slave client structure, the replication offset
913	 *    we sent here, so that if new slaves will later attach to the same
914	 *    background RDB saving process (by duplicating this client output
915	 *    buffer), we can get the right offset from this slave.
916	 * 2) Set the replication state of the slave to WAIT_BGSAVE_END so that
917	 *    we start accumulating differences from this point.
918	 * 3) Force the replication stream to re-emit a SELECT statement so
919	 *    the new slave incremental differences will start selecting the
920	 *    right database number.
921	 *
922	 * Normally this function should be called immediately after a successful
923	 * BGSAVE for replication was started, or when there is one already in
924	 * progress that we attached our slave to. */
925	int replicationSetupSlaveForFullResync(client *slave, long long offset) {
926	    char buf[128];
927	    int buflen;
928	
929	    slave->psync_initial_offset = offset;
930	    slave->replstate = SLAVE_STATE_WAIT_BGSAVE_END;
931	    /* We are going to accumulate the incremental changes for this
932	     * slave as well. Set slaveseldb to -1 in order to force to re-emit
933	     * a SELECT statement in the replication stream. */
934	    server.slaveseldb = -1;
935	
936	    /* Slots snapshot. */
937	    if (slave->flags & CLIENT_REPL_RDB_CHANNEL &&
938	        slave->slave_req & SLAVE_REQ_SLOTS_SNAPSHOT)
939	    {
940	        /* Start to deliver the commands stream on migrating slots. */
941	        asmSlotSnapshotAndStreamStart(slave->task);
942	
943	        buflen = snprintf(buf, sizeof(buf), "+SLOTSSNAPSHOT\r\n");
944	        if (connWrite(slave->conn, buf, buflen) != buflen) {
945	            freeClientAsync(slave);
946	            return C_ERR;
947	        }
948	        return C_OK;
949	    }
950	
951	    /* Don't send this reply to slaves that approached us with
952	     * the old SYNC command. */
953	    if (!(slave->flags & CLIENT_PRE_PSYNC)) {
954	        if (slave->flags & CLIENT_REPL_RDB_CHANNEL) {
955	            /* This slave is rdbchannel. Find its associated main channel and
956	             * change its state so we can deliver replication stream from now
957	             * on, in parallel to rdb. */
958	            uint64_t id = slave->main_ch_client_id;
959	            client *c = lookupClientByID(id);
960	            if (c && c->replstate == SLAVE_STATE_WAIT_RDB_CHANNEL) {
961	                c->replstate = SLAVE_STATE_SEND_BULK_AND_STREAM;
962	                serverLog(LL_NOTICE, "Starting to deliver RDB and replication stream to replica: %s",
963	                          replicationGetSlaveName(c));
964	            } else {
965	                serverLog(LL_WARNING, "Starting to deliver RDB to replica %s"
966	                                      " but it has no associated main channel",
967	                                      replicationGetSlaveName(slave));
968	            }
969	        }
970	        buflen = snprintf(buf,sizeof(buf),"+FULLRESYNC %s %lld\r\n",
971	                          server.replid,offset);
972	        if (connWrite(slave->conn,buf,buflen) != buflen) {
973	            freeClientAsync(slave);
974	            return C_ERR;
975	        }
976	    }
977	    return C_OK;
978	}
