980	/* This function handles the PSYNC command from the point of view of a
981	 * master receiving a request for partial resynchronization.
982	 *
983	 * On success return C_OK, otherwise C_ERR is returned and we proceed
984	 * with the usual full resync. */
985	int masterTryPartialResynchronization(client *c, long long psync_offset) {
986	    long long psync_len;
987	    char *master_replid = c->argv[1]->ptr;
988	    char buf[128];
989	    int buflen;
990	
991	    /* Is the replication ID of this master the same advertised by the wannabe
992	     * slave via PSYNC? If the replication ID changed this master has a
993	     * different replication history, and there is no way to continue.
994	     *
995	     * Note that there are two potentially valid replication IDs: the ID1
996	     * and the ID2. The ID2 however is only valid up to a specific offset. */
997	    if (strcasecmp(master_replid, server.replid) &&
998	        (strcasecmp(master_replid, server.replid2) ||
999	         psync_offset > server.second_replid_offset))

1000	         psync_offset > server.second_replid_offset))
1001	    {
1002	        /* Replid "?" is used by slaves that want to force a full resync. */
1003	        if (master_replid[0] != '?') {
1004	            if (strcasecmp(master_replid, server.replid) &&
1005	                strcasecmp(master_replid, server.replid2))
1006	            {
1007	                serverLog(LL_NOTICE,"Partial resynchronization not accepted: "
1008	                    "Replication ID mismatch (Replica asked for '%s', my "
1009	                    "replication IDs are '%s' and '%s')",
1010	                    master_replid, server.replid, server.replid2);
1011	            } else {
1012	                serverLog(LL_NOTICE,"Partial resynchronization not accepted: "
1013	                    "Requested offset for second ID was %lld, but I can reply "
1014	                    "up to %lld", psync_offset, server.second_replid_offset);
1015	            }
1016	        } else {
1017	            serverLog(LL_NOTICE,"Full resync requested by replica %s %s",
1018	                replicationGetSlaveName(c),
1019	                c->flags & CLIENT_REPL_RDB_CHANNEL ? "(rdb-channel)" : "");
1020	        }
1021	        goto need_full_resync;
1022	    }
1023	
1024	    /* We still have the data our slave is asking for? */
1025	    if (!server.repl_backlog ||
1026	        psync_offset < server.repl_backlog->offset ||
1027	        psync_offset > (server.repl_backlog->offset + server.repl_backlog->histlen))
1028	    {
1029	        serverLog(LL_NOTICE,
1030	            "Unable to partial resync with replica %s for lack of backlog (Replica request was: %lld).", replicationGetSlaveName(c), psync_offset);
1031	        if (psync_offset > server.master_repl_offset) {
1032	            serverLog(LL_WARNING,
1033	                "Warning: replica %s tried to PSYNC with an offset that is greater than the master replication offset.", replicationGetSlaveName(c));
1034	        }
1035	        goto need_full_resync;
1036	    }
1037	
1038	    /* If we reached this point, we are able to perform a partial resync:
1039	     * 1) Set client state to make it a slave.
1040	     * 2) Inform the client we can continue with +CONTINUE
1041	     * 3) Send the backlog data (from the offset to the end) to the slave. */
1042	    c->flags |= CLIENT_SLAVE;
1043	    c->replstate = SLAVE_STATE_ONLINE;
1044	    c->repl_ack_time = server.unixtime;
1045	    c->repl_start_cmd_stream_on_ack = 0;
1046	    listAddNodeTail(server.slaves,c);
1047	    /* We can't use the connection buffers since they are used to accumulate
1048	     * new commands at this stage. But we are sure the socket send buffer is
1049	     * empty so this write will never fail actually. */
1050	    if (c->slave_capa & SLAVE_CAPA_PSYNC2) {
1051	        buflen = snprintf(buf,sizeof(buf),"+CONTINUE %s\r\n", server.replid);
1052	    } else {
1053	        buflen = snprintf(buf,sizeof(buf),"+CONTINUE\r\n");
1054	    }
1055	    if (connWrite(c->conn,buf,buflen) != buflen) {
1056	        freeClientAsync(c);
1057	        return C_OK;
1058	    }
1059	    psync_len = addReplyReplicationBacklog(c,psync_offset);
1060	    serverLog(LL_NOTICE,
1061	        "Partial resynchronization request from %s accepted. Sending %lld bytes of backlog starting from offset %lld.",
1062	            replicationGetSlaveName(c),
1063	            psync_len, psync_offset);
1064	    /* Note that we don't need to set the selected DB at server.slaveseldb
1065	     * to -1 to force the master to emit SELECT, since the slave already
1066	     * has this state from the previous connection with the master. */
1067	
1068	    refreshGoodSlavesCount();
1069	
1070	    /* Fire the replica change modules event. */
1071	    moduleFireServerEvent(REDISMODULE_EVENT_REPLICA_CHANGE,
1072	                          REDISMODULE_SUBEVENT_REPLICA_CHANGE_ONLINE,
1073	                          NULL);
1074	
1075	    return C_OK; /* The caller can return, no full resync needed. */
1076	
1077	need_full_resync:
1078	    /* We need a full resync for some reason... Note that we can't
1079	     * reply to PSYNC right now if a full SYNC is needed. The reply
1080	     * must include the master offset at the time the RDB file we transfer
1081	     * is generated, so we need to delay the reply to that moment. */
1082	    return C_ERR;
1083	}
