1085	/* Start a BGSAVE for replication goals, which is, selecting the disk or
1086	 * socket target depending on the configuration, and making sure that
1087	 * the script cache is flushed before to start.
1088	 *
1089	 * The mincapa argument is the bitwise AND among all the slaves capabilities
1090	 * of the slaves waiting for this BGSAVE, so represents the slave capabilities
1091	 * all the slaves support. Can be tested via SLAVE_CAPA_* macros.
1092	 *
1093	 * Side effects, other than starting a BGSAVE:
1094	 *
1095	 * 1) Handle the slaves in WAIT_START state, by preparing them for a full
1096	 *    sync if the BGSAVE was successfully started, or sending them an error
1097	 *    and dropping them from the list of slaves.
1098	 *
1099	 * 2) Flush the Lua scripting script cache if the BGSAVE was actually
1100	 *    started.
1101	 *
1102	 * Returns C_OK on success or C_ERR otherwise. */
1103	int startBgsaveForReplication(int mincapa, int req) {
1104	    int retval;
1105	    int socket_target = 0;
1106	    listIter li;
1107	    listNode *ln;
1108	
1109	    /* We use a socket target if slave can handle the EOF marker and we're configured to do diskless syncs.
1110	     * Note that in case we're creating a "filtered" RDB (functions-only, for example) we also force socket replication
1111	     * to avoid overwriting the snapshot RDB file with filtered data. */
1112	    socket_target = (server.repl_diskless_sync || req & SLAVE_REQ_RDB_MASK) && (mincapa & SLAVE_CAPA_EOF);
1113	    /* `SYNC` should have failed with error if we don't support socket and require a filter, assert this here */
1114	    serverAssert(socket_target || !(req & SLAVE_REQ_RDB_MASK));
1115	
1116	    int slots_req = req & SLAVE_REQ_SLOTS_SNAPSHOT;
1117	    serverLog(LL_NOTICE,"Starting BGSAVE for SYNC with target: %s%s",
1118	        socket_target ? (slots_req ? "slot migration destination socket" : "replicas sockets") : "disk",
1119	        (req & SLAVE_REQ_RDB_CHANNEL) ? " (rdb-channel)" : "");
1120	
1121	    rdbSaveInfo rsi, *rsiptr;
1122	    rsiptr = rdbPopulateSaveInfo(&rsi);
1123	    /* Only do rdbSave* when rsiptr is not NULL,
1124	     * otherwise slave will miss repl-stream-db. */
1125	    if (rsiptr) {
1126	        if (socket_target)
1127	            retval = rdbSaveToSlavesSockets(req,rsiptr);
1128	        else {
1129	            /* Keep the page cache since it'll get used soon */
1130	            retval = rdbSaveBackground(req, server.rdb_filename, rsiptr, RDBFLAGS_REPLICATION | RDBFLAGS_KEEP_CACHE);
1131	        }
1132	        if (server.repl_debug_pause & REPL_DEBUG_AFTER_FORK)
1133	            debugPauseProcess();
1134	    } else {
1135	        serverLog(LL_WARNING,"BGSAVE for replication: replication information not available, can't generate the RDB file right now. Try later.");
1136	        retval = C_ERR;
1137	    }
1138	
1139	    /* If we succeeded to start a BGSAVE with disk target, let's remember
1140	     * this fact, so that we can later delete the file if needed. Note
1141	     * that we don't set the flag to 1 if the feature is disabled, otherwise
1142	     * it would never be cleared: the file is not deleted. This way if
1143	     * the user enables it later with CONFIG SET, we are fine. */
1144	    if (retval == C_OK && !socket_target && server.rdb_del_sync_files)
1145	        RDBGeneratedByReplication = 1;
1146	
1147	    /* If we failed to BGSAVE, remove the slaves waiting for a full
1148	     * resynchronization from the list of slaves, inform them with
1149	     * an error about what happened, close the connection ASAP. */
1150	    if (retval == C_ERR) {
1151	        serverLog(LL_WARNING,"BGSAVE for replication failed");
1152	        listRewind(server.slaves,&li);
1153	        while((ln = listNext(&li))) {
1154	            client *slave = ln->value;
1155	
1156	            if (slave->replstate == SLAVE_STATE_WAIT_BGSAVE_START) {
1157	                slave->replstate = REPL_STATE_NONE;
1158	                slave->flags &= ~CLIENT_SLAVE;
1159	                listDelNode(server.slaves,ln);
1160	                addReplyError(slave,
1161	                    "BGSAVE failed, replication can't continue");
1162	                slave->flags |= CLIENT_CLOSE_AFTER_REPLY;
1163	            }
1164	        }
1165	        return retval;
1166	    }
1167	
1168	    /* If the target is socket, rdbSaveToSlavesSockets() already setup
1169	     * the slaves for a full resync. Otherwise for disk target do it now.*/
1170	    if (!socket_target) {
1171	        listRewind(server.slaves,&li);
1172	        while((ln = listNext(&li))) {
1173	            client *slave = ln->value;
1174	
1175	            if (slave->replstate == SLAVE_STATE_WAIT_BGSAVE_START) {
1176	                /* Check slave has the exact requirements */
1177	                if (slave->slave_req != req)
1178	                    continue;
1179	                replicationSetupSlaveForFullResync(slave, getPsyncInitialOffset());
1180	            }
1181	        }
1182	    }
1183	
1184	    return retval;
1185	}
