1187	/* SYNC and PSYNC command implementation. */
1188	void syncCommand(client *c) {
1189	    /* ignore SYNC if already slave or in monitor mode */
1190	    if (c->flags & CLIENT_SLAVE) return;
1191	
1192	    /* Check if this is a failover request to a replica with the same replid and
1193	     * become a master if so. */
1194	    if (c->argc > 3 && !strcasecmp(c->argv[0]->ptr,"psync") && 
1195	        !strcasecmp(c->argv[3]->ptr,"failover"))
1196	    {
1197	        serverLog(LL_NOTICE, "Failover request received for replid %s.",
1198	            (unsigned char *)c->argv[1]->ptr);
1199	        if (!server.masterhost) {
1200	            addReplyError(c, "PSYNC FAILOVER can't be sent to a master.");
1201	            return;
1202	        }
1203	
1204	        if (!strcasecmp(c->argv[1]->ptr,server.replid)) {
1205	            if (server.cluster_enabled) {
1206	                clusterPromoteSelfToMaster();
1207	            } else {
1208	                replicationUnsetMaster();
1209	            }
1210	            sds client = catClientInfoString(sdsempty(),c);
1211	            serverLog(LL_NOTICE,
1212	                "MASTER MODE enabled (failover request from '%s')",client);
1213	            sdsfree(client);
1214	        } else {
1215	            addReplyError(c, "PSYNC FAILOVER replid must match my replid.");
1216	            return;            
1217	        }
1218	    }
1219	
1220	    /* Don't let replicas sync with us while we're failing over */
1221	    if (server.failover_state != NO_FAILOVER) {
1222	        addReplyError(c,"-NOMASTERLINK Can't SYNC while failing over");
1223	        return;
1224	    }
1225	
1226	    /* Refuse SYNC requests if we are a slave but the link with our master
1227	     * is not ok... */
1228	    if (server.masterhost && server.repl_state != REPL_STATE_CONNECTED) {
1229	        addReplyError(c,"-NOMASTERLINK Can't SYNC while not connected with my master");
1230	        return;
1231	    }
1232	
1233	    /* SYNC can't be issued when the server has pending data to send to
1234	     * the client about already issued commands. We need a fresh reply
1235	     * buffer registering the differences between the BGSAVE and the current
1236	     * dataset, so that we can copy to other slaves if needed. */
1237	    if (clientHasPendingReplies(c)) {
1238	        addReplyError(c,"SYNC and PSYNC are invalid with pending output");
1239	        return;
1240	    }
1241	
1242	    /* Fail sync if slave doesn't support EOF capability but wants a filtered RDB. This is because we force filtered
1243	     * RDB's to be generated over a socket and not through a file to avoid conflicts with the snapshot files. Forcing
1244	     * use of a socket is handled, if needed, in `startBgsaveForReplication`. */
1245	    if (c->slave_req & SLAVE_REQ_RDB_MASK && !(c->slave_capa & SLAVE_CAPA_EOF)) {
1246	        addReplyError(c,"Filtered replica requires EOF capability");
1247	        return;
1248	    }
1249	
1250	    serverLog(LL_NOTICE,"Replica %s asks for synchronization",
1251	        replicationGetSlaveName(c));
1252	
1253	    /* Try a partial resynchronization if this is a PSYNC command.
1254	     * If it fails, we continue with usual full resynchronization, however
1255	     * when this happens replicationSetupSlaveForFullResync will replied
1256	     * with:
1257	     *
1258	     * +FULLRESYNC <replid> <offset>
1259	     *
1260	     * So the slave knows the new replid and offset to try a PSYNC later
1261	     * if the connection with the master is lost. */
1262	    if (!strcasecmp(c->argv[0]->ptr,"psync")) {
1263	        long long psync_offset;
1264	        if (getLongLongFromObjectOrReply(c, c->argv[2], &psync_offset, NULL) != C_OK) {
1265	            serverLog(LL_WARNING, "Replica %s asks for synchronization but with a wrong offset",
1266	                      replicationGetSlaveName(c));
1267	            return;
1268	        }
1269	
1270	        if (masterTryPartialResynchronization(c, psync_offset) == C_OK) {
1271	            server.stat_sync_partial_ok++;
1272	            return; /* No full resync needed, return. */
1273	        } else {
1274	            char *master_replid = c->argv[1]->ptr;
1275	
1276	            /* Increment stats for failed PSYNCs, but only if the
1277	             * replid is not "?", as this is used by slaves to force a full
1278	             * resync on purpose when they are not able to partially
1279	             * resync. */
1280	            if (master_replid[0] != '?') server.stat_sync_partial_err++;
1281	            if (c->slave_capa & SLAVE_CAPA_RDB_CHANNEL_REPL) {
1282	                int len;
1283	                char buf[128];
1284	                /* Replica is capable of rdbchannel replication. This is
1285	                 * replica's main channel. Let replica know full sync is needed.
1286	                 * Replica will open another connection (rdbchannel). Once rdb
1287	                 * delivery starts, we'll stream repl data to the main channel.*/
1288	                c->flags |= CLIENT_SLAVE;
1289	                c->replstate = SLAVE_STATE_WAIT_RDB_CHANNEL;
1290	                c->repl_ack_time = server.unixtime;
1291	                listAddNodeTail(server.slaves, c);
1292	                createReplicationBacklogIfNeeded();
1293	
1294	                serverLog(LL_NOTICE,
1295	                          "Replica %s is capable of rdb channel synchronization, and partial sync isn't possible. "
1296	                          "Full sync will continue with dedicated rdb channel.",
1297	                          replicationGetSlaveName(c));
1298	
1299	                /* Send +RDBCHANNELSYNC with client id so we can associate replica connections on master.*/
1300	                len = snprintf(buf, sizeof(buf), "+RDBCHANNELSYNC %llu\r\n",
1301	                               (unsigned long long) c->id);
1302	                if (connWrite(c->conn, buf, strlen(buf)) != len)
1303	                    freeClientAsync(c);
1304	
1305	                return;
1306	            }
1307	        }
1308	    } else {
1309	        /* If a slave uses SYNC, we are dealing with an old implementation
1310	         * of the replication protocol (like redis-cli --slave). Flag the client
1311	         * so that we don't expect to receive REPLCONF ACK feedbacks. */
1312	        c->flags |= CLIENT_PRE_PSYNC;
1313	    }
1314	
1315	    /* Full resynchronization. */
1316	    server.stat_sync_full++;
1317	
1318	    /* Setup the slave as one waiting for BGSAVE to start. The following code
1319	     * paths will change the state if we handle the slave differently. */
1320	    c->replstate = SLAVE_STATE_WAIT_BGSAVE_START;
1321	    if (server.repl_disable_tcp_nodelay)
1322	        connDisableTcpNoDelay(c->conn); /* Non critical if it fails. */
1323	    c->repldbfd = -1;
1324	    c->flags |= CLIENT_SLAVE;
1325	    listAddNodeTail(server.slaves,c);
1326	
1327	    /* Create the replication backlog if needed. */
1328	    createReplicationBacklogIfNeeded();
1329	
1330	    /* Keep the client in the main thread to avoid data races between the
1331	     * connWrite call in startBgsaveForReplication and the client's event
1332	     * handler in IO threads. */
1333	    if (c->tid != IOTHREAD_MAIN_THREAD_ID) keepClientInMainThread(c);
1334	
1335	    /* CASE 1: BGSAVE is in progress, with disk target. */
1336	    if (server.child_type == CHILD_TYPE_RDB &&
1337	        server.rdb_child_type == RDB_CHILD_TYPE_DISK)
1338	    {
1339	        /* Ok a background save is in progress. Let's check if it is a good
1340	         * one for replication, i.e. if there is another slave that is
1341	         * registering differences since the server forked to save. */
1342	        client *slave;
1343	        listNode *ln;
1344	        listIter li;
1345	
1346	        listRewind(server.slaves,&li);
1347	        while((ln = listNext(&li))) {
1348	            slave = ln->value;
1349	            /* If the client needs a buffer of commands, we can't use
1350	             * a replica without replication buffer. */
1351	            if (slave->replstate == SLAVE_STATE_WAIT_BGSAVE_END &&
1352	                (!(slave->flags & CLIENT_REPL_RDBONLY) ||
1353	                 (c->flags & CLIENT_REPL_RDBONLY)))
1354	                break;
1355	        }
1356	        /* To attach this slave, we check that it has at least all the
1357	         * capabilities of the slave that triggered the current BGSAVE
1358	         * and its exact requirements. */
1359	        if (ln && ((c->slave_capa & slave->slave_capa) == slave->slave_capa) &&
1360	            c->slave_req == slave->slave_req) {
1361	            /* Perfect, the server is already registering differences for
1362	             * another slave. Set the right state, and copy the buffer.
1363	             * We don't copy buffer if clients don't want. */
1364	            if (!(c->flags & CLIENT_REPL_RDBONLY))
1365	                copyReplicaOutputBuffer(c,slave);
1366	            replicationSetupSlaveForFullResync(c,slave->psync_initial_offset);
1367	            serverLog(LL_NOTICE,"Waiting for end of BGSAVE for SYNC");
1368	        } else {
1369	            /* No way, we need to wait for the next BGSAVE in order to
1370	             * register differences. */
1371	            serverLog(LL_NOTICE,"Can't attach the replica to the current BGSAVE. Waiting for next BGSAVE for SYNC");
1372	        }
1373	
1374	    /* CASE 2: BGSAVE is in progress, with socket target. */
1375	    } else if (server.child_type == CHILD_TYPE_RDB &&
1376	               server.rdb_child_type == RDB_CHILD_TYPE_SOCKET)
1377	    {
1378	        /* There is an RDB child process but it is writing directly to
1379	         * children sockets. We need to wait for the next BGSAVE
1380	         * in order to synchronize. */
1381	        serverLog(LL_NOTICE,"Current BGSAVE has socket target. Waiting for next BGSAVE for SYNC");
1382	
1383	    /* CASE 3: There is no BGSAVE is in progress. */
1384	    } else {
1385	        if (server.repl_diskless_sync && (c->slave_capa & SLAVE_CAPA_EOF) &&
1386	            server.repl_diskless_sync_delay)
1387	        {
1388	            /* Diskless replication RDB child is created inside
1389	             * replicationCron() since we want to delay its start a
1390	             * few seconds to wait for more slaves to arrive. */
1391	            serverLog(LL_NOTICE,"Delay next BGSAVE for diskless SYNC");
1392	        } else {
1393	            /* We don't have a BGSAVE in progress, let's start one. Diskless
1394	             * or disk-based mode is determined by replica's capacity. */
1395	            if (!hasActiveChildProcess()) {
1396	                startBgsaveForReplication(c->slave_capa, c->slave_req);
1397	            } else {
1398	                serverLog(LL_NOTICE,
1399	                    "No BGSAVE in progress, but another BG operation is active. "
1400	                    "BGSAVE for replication delayed");
1401	            }
1402	        }
1403	    }
1404	    return;
1405	}
