1407	/* REPLCONF <option> <value> <option> <value> ...
1408	 * This command is used by a replica in order to configure the replication
1409	 * process before starting it with the SYNC command.
1410	 * This command is also used by a master in order to get the replication
1411	 * offset from a replica.
1412	 *
1413	 * Currently we support these options:
1414	 *
1415	 * - listening-port <port>
1416	 * - ip-address <ip>
1417	 * What is the listening ip and port of the Replica redis instance, so that
1418	 * the master can accurately lists replicas and their listening ports in the
1419	 * INFO output.
1420	 *
1421	 * - capa <eof|psync2|rdb-channel-repl>
1422	 * What is the capabilities of this instance.
1423	 * eof: supports EOF-style RDB transfer for diskless replication.
1424	 * psync2: supports PSYNC v2, so understands +CONTINUE <new repl ID>.
1425	 *
1426	 * - ack <offset> [fack <aofofs>]
1427	 * Replica informs the master the amount of replication stream that it
1428	 * processed so far, and optionally the replication offset fsynced to the AOF file.
1429	 * This special pattern doesn't reply to the caller.
1430	 *
1431	 * - getack <dummy>
1432	 * Unlike other subcommands, this is used by master to get the replication
1433	 * offset from a replica.
1434	 *
1435	 * - rdb-only <0|1>
1436	 * Only wants RDB snapshot without replication buffer.
1437	 *
1438	 * - rdb-filter-only <include-filters>
1439	 * Define "include" filters for the RDB snapshot. Currently we only support
1440	 * a single include filter: "functions". Passing an empty string "" will
1441	 * result in an empty RDB.
1442	 *
1443	 * - main-ch-client-id <client-id>
1444	 * Replica's main channel informs master that this is the main channel of the
1445	 * rdb channel identified by the client-id. */
1446	void replconfCommand(client *c) {
1447	    int j;
1448	
1449	    if ((c->argc % 2) == 0) {
1450	        /* Number of arguments must be odd to make sure that every
1451	         * option has a corresponding value. */
1452	        addReplyErrorObject(c,shared.syntaxerr);
1453	        return;
1454	    }
1455	
1456	    /* Process every option-value pair. */
1457	    for (j = 1; j < c->argc; j+=2) {
1458	        if (!strcasecmp(c->argv[j]->ptr,"listening-port")) {
1459	            long port;
1460	
1461	            if ((getLongFromObjectOrReply(c,c->argv[j+1],
1462	                    &port,NULL) != C_OK))
1463	                return;
1464	            c->slave_listening_port = port;
1465	        } else if (!strcasecmp(c->argv[j]->ptr,"ip-address")) {
1466	            sds addr = c->argv[j+1]->ptr;
1467	            if (sdslen(addr) < NET_HOST_STR_LEN) {
1468	                if (c->slave_addr) sdsfree(c->slave_addr);
1469	                c->slave_addr = sdsdup(addr);
1470	            } else {
1471	                addReplyErrorFormat(c,"REPLCONF ip-address provided by "
1472	                    "replica instance is too long: %zd bytes", sdslen(addr));
1473	                return;
1474	            }
1475	        } else if (!strcasecmp(c->argv[j]->ptr,"capa")) {
1476	            /* Ignore capabilities not understood by this master. */
1477	            if (!strcasecmp(c->argv[j+1]->ptr,"eof"))
1478	                c->slave_capa |= SLAVE_CAPA_EOF;
1479	            else if (!strcasecmp(c->argv[j+1]->ptr,"psync2"))
1480	                c->slave_capa |= SLAVE_CAPA_PSYNC2;
1481	            else if (!strcasecmp(c->argv[j+1]->ptr,"rdb-channel-repl") && server.repl_rdb_channel &&
1482	                     server.repl_diskless_sync) {
1483	                c->slave_capa |= SLAVE_CAPA_RDB_CHANNEL_REPL;
1484	            }
1485	        } else if (!strcasecmp(c->argv[j]->ptr,"ack")) {
1486	            /* REPLCONF ACK is used by slave to inform the master the amount
1487	             * of replication stream that it processed so far. It is an
1488	             * internal only command that normal clients should never use. */
1489	            long long offset;
1490	
1491	            if (!(c->flags & CLIENT_SLAVE)) return;
1492	            if ((getLongLongFromObject(c->argv[j+1], &offset) != C_OK))
1493	                return;
1494	            if (offset > c->repl_ack_off)
1495	                c->repl_ack_off = offset;
1496	            if (c->argc > j+3 && !strcasecmp(c->argv[j+2]->ptr,"fack")) {
1497	                if ((getLongLongFromObject(c->argv[j+3], &offset) != C_OK))
1498	                    return;
1499	                if (offset > c->repl_aof_off)
1500	                    c->repl_aof_off = offset;
1501	            }
1502	            c->repl_ack_time = server.unixtime;
1503	            /* If this was a diskless replication, we need to really put
1504	             * the slave online when the first ACK is received (which
1505	             * confirms slave is online and ready to get more data). This
1506	             * allows for simpler and less CPU intensive EOF detection
1507	             * when streaming RDB files.
1508	             * There's a chance the ACK got to us before we detected that the
1509	             * bgsave is done (since that depends on cron ticks), so run a
1510	             * quick check first (instead of waiting for the next ACK. */
1511	            if (server.child_type == CHILD_TYPE_RDB && c->replstate == SLAVE_STATE_WAIT_BGSAVE_END)
1512	                checkChildrenDone();
1513	            if (c->repl_start_cmd_stream_on_ack && c->replstate == SLAVE_STATE_ONLINE)
1514	                replicaStartCommandStream(c);
1515	            /* If state is send_bulk_and_stream, it means this is the main
1516	             * channel of the slave in rdbchannel replication. Normally, slave
1517	             * will be put online after rdb fork is completed. There is chance
1518	             * that 'ack' might be received before we detect bgsave is done. */
1519	            if (c->replstate == SLAVE_STATE_SEND_BULK_AND_STREAM)
1520	                replicaPutOnline(c);
1521	            /* Note: this command does not reply anything! */
1522	            return;
1523	        } else if (!strcasecmp(c->argv[j]->ptr,"getack")) {
1524	            /* REPLCONF GETACK is used in order to request an ACK ASAP
1525	             * to the slave. */
1526	            if (server.masterhost && server.master) replicationSendAck();
1527	            return;
1528	        } else if (!strcasecmp(c->argv[j]->ptr,"rdb-only")) {
1529	           /* REPLCONF RDB-ONLY is used to identify the client only wants
1530	            * RDB snapshot without replication buffer. */
1531	            long rdb_only = 0;
1532	            if (getRangeLongFromObjectOrReply(c,c->argv[j+1],
1533	                    0,1,&rdb_only,NULL) != C_OK)
1534	                return;
1535	            if (rdb_only == 1) {
1536	                c->flags |= CLIENT_REPL_RDBONLY;
1537	                /* If replicas ask for RDB only, We can apply the background
1538	                 * RDB transfer optimization based on the configurations. */
1539	                if (server.repl_rdb_channel && server.repl_diskless_sync)
1540	                    c->slave_req |= SLAVE_REQ_RDB_CHANNEL;
1541	            } else {
1542	                c->flags &= ~CLIENT_REPL_RDBONLY;
1543	                c->slave_req &= ~SLAVE_REQ_RDB_CHANNEL;
1544	            }
1545	        } else if (!strcasecmp(c->argv[j]->ptr,"rdb-filter-only")) {
1546	            /* REPLCONFG RDB-FILTER-ONLY is used to define "include" filters
1547	             * for the RDB snapshot. Currently we only support a single
1548	             * include filter: "functions". In the future we may want to add
1549	             * other filters like key patterns, key types, non-volatile, module
1550	             * aux fields, ...
1551	             * We might want to add the complementing "RDB-FILTER-EXCLUDE" to
1552	             * filter out certain data. */
1553	            int filter_count, i;
1554	            sds *filters;
1555	            if (!(filters = sdssplitargs(c->argv[j+1]->ptr, &filter_count))) {
1556	                addReplyError(c, "Missing rdb-filter-only values");
1557	                return;
1558	            }
1559	            /* By default filter out all parts of the rdb */
1560	            c->slave_req |= SLAVE_REQ_RDB_EXCLUDE_DATA;
1561	            c->slave_req |= SLAVE_REQ_RDB_EXCLUDE_FUNCTIONS;
1562	            for (i = 0; i < filter_count; i++) {
1563	                if (!strcasecmp(filters[i], "functions"))
1564	                    c->slave_req &= ~SLAVE_REQ_RDB_EXCLUDE_FUNCTIONS;
1565	                else {
1566	                    addReplyErrorFormat(c, "Unsupported rdb-filter-only option: %s", (char*)filters[i]);
1567	                    sdsfreesplitres(filters, filter_count);
1568	                    return;
1569	                }
1570	            }
1571	            sdsfreesplitres(filters, filter_count);
1572	        } else if (!strcasecmp(c->argv[j]->ptr, "rdb-channel")) {
1573	            long rdb_channel = 0;
1574	            if (getRangeLongFromObjectOrReply(c, c->argv[j + 1], 0, 1, &rdb_channel, NULL) != C_OK)
1575	                return;
1576	            if (rdb_channel == 1) {
1577	                c->flags |= CLIENT_REPL_RDB_CHANNEL;
1578	            } else {
1579	                c->flags &= ~CLIENT_REPL_RDB_CHANNEL;
1580	            }
1581	        } else if (!strcasecmp(c->argv[j]->ptr, "main-ch-client-id")) {
1582	            /* REPLCONF main-ch-client-id <client-id> is used to identify
1583	             * the current replica rdb channel with existing main channel
1584	             * connection. */
1585	            long long client_id = 0;
1586	            client *main_ch;
1587	            if (getLongLongFromObjectOrReply(c, c->argv[j + 1], &client_id, NULL) != C_OK)
1588	                return;
1589	            main_ch = lookupClientByID(client_id);
1590	            if (!main_ch || main_ch->replstate != SLAVE_STATE_WAIT_RDB_CHANNEL) {
1591	                addReplyErrorFormat(c, "Unrecognized RDB client id: %lld", client_id);
1592	                return;
1593	            }
1594	            c->main_ch_client_id = (uint64_t)client_id;
1595	            /* Inherit the rdb-no-compress and rdb-no-checksum request from the main channel. */
1596	            if (main_ch->slave_req & SLAVE_REQ_RDB_NO_COMPRESS)
1597	                c->slave_req |= SLAVE_REQ_RDB_NO_COMPRESS;
1598	            if (main_ch->slave_req & SLAVE_REQ_RDB_NO_CHECKSUM)
1599	                c->slave_req |= SLAVE_REQ_RDB_NO_CHECKSUM;
1600	        } else if (!strcasecmp(c->argv[j]->ptr, "rdb-no-compress")) {
1601	            long rdb_no_compress = 0;
1602	            if (getRangeLongFromObjectOrReply(c, c->argv[j + 1], 0, 1, &rdb_no_compress, NULL) != C_OK)
1603	                return;
1604	            if (rdb_no_compress == 1) {
1605	                c->slave_req |= SLAVE_REQ_RDB_NO_COMPRESS;
1606	            } else {
1607	                c->slave_req &= ~SLAVE_REQ_RDB_NO_COMPRESS;
1608	            }
1609	        } else if (!strcasecmp(c->argv[j]->ptr, "rdb-no-checksum")) {
1610	            long rdb_no_checksum = 0;
1611	            if (getRangeLongFromObjectOrReply(c, c->argv[j + 1], 0, 1, &rdb_no_checksum, NULL) != C_OK)
1612	                return;
1613	            if (rdb_no_checksum == 1) {
1614	                c->slave_req |= SLAVE_REQ_RDB_NO_CHECKSUM;
1615	            } else {
1616	                c->slave_req &= ~SLAVE_REQ_RDB_NO_CHECKSUM;
1617	            }
1618	        } else {
1619	            addReplyErrorFormat(c,"Unrecognized REPLCONF option: %s",
1620	                (char*)c->argv[j]->ptr);
1621	            return;
1622	        }
1623	    }
1624	    addReply(c,shared.ok);
1625	}
