1627	/* This function puts a replica in the online state, and should be called just
1628	 * after a replica received the RDB file for the initial synchronization.
1629	 *
1630	 * It does a few things:
1631	 * 1) Put the slave in ONLINE state.
1632	 * 2) Update the count of "good replicas".
1633	 * 3) Trigger the module event.
1634	 *
1635	 * the return value indicates that the replica should be disconnected.
1636	 * */
1637	int replicaPutOnline(client *slave) {
1638	    if (slave->flags & CLIENT_REPL_RDBONLY) {
1639	        slave->replstate = SLAVE_STATE_RDB_TRANSMITTED;
1640	        /* The client asked for RDB only so we should close it ASAP */
1641	        serverLog(LL_NOTICE,
1642	                  "RDB transfer completed, rdb only replica (%s) should be disconnected asap",
1643	                  replicationGetSlaveName(slave));
1644	        return 0;
1645	    }
1646	
1647	    /* Don't put migration destination client online. */
1648	    if (slave->flags & CLIENT_ASM_MIGRATING) return 0;
1649	
1650	    slave->replstate = SLAVE_STATE_ONLINE;
1651	    slave->repl_ack_time = server.unixtime; /* Prevent false timeout. */
1652	
1653	    refreshGoodSlavesCount();
1654	    /* Fire the replica change modules event. */
1655	    moduleFireServerEvent(REDISMODULE_EVENT_REPLICA_CHANGE,
1656	                          REDISMODULE_SUBEVENT_REPLICA_CHANGE_ONLINE,
1657	                          NULL);
1658	    serverLog(LL_NOTICE,"Synchronization with replica %s succeeded",
1659	        replicationGetSlaveName(slave));
1660	    return 1;
1661	}
1662	
1663	/* This function should be called just after a replica received the RDB file
1664	 * for the initial synchronization, and we are finally ready to send the
1665	 * incremental stream of commands.
1666	 *
1667	 * It does a few things:
1668	 * 1) Close the replica's connection async if it doesn't need replication
1669	 *    commands buffer stream, since it actually isn't a valid replica.
1670	 * 2) Make sure the writable event is re-installed, since when calling the SYNC
1671	 *    command we had no replies and it was disabled, and then we could
1672	 *    accumulate output buffer data without sending it to the replica so it
1673	 *    won't get mixed with the RDB stream. */
1674	void replicaStartCommandStream(client *slave) {
1675	    serverAssert(!(slave->flags & CLIENT_REPL_RDBONLY));
1676	    slave->repl_start_cmd_stream_on_ack = 0;
1677	
1678	    putClientInPendingWriteQueue(slave);
1679	}
1680	
1681	/* We call this function periodically to remove an RDB file that was
1682	 * generated because of replication, in an instance that is otherwise
1683	 * without any persistence. We don't want instances without persistence
1684	 * to take RDB files around, this violates certain policies in certain
1685	 * environments. */
1686	void removeRDBUsedToSyncReplicas(void) {
1687	    /* If the feature is disabled, return ASAP but also clear the
1688	     * RDBGeneratedByReplication flag in case it was set. Otherwise if the
1689	     * feature was enabled, but gets disabled later with CONFIG SET, the
1690	     * flag may remain set to one: then next time the feature is re-enabled
1691	     * via CONFIG SET we have it set even if no RDB was generated
1692	     * because of replication recently. */
1693	    if (!server.rdb_del_sync_files) {
1694	        RDBGeneratedByReplication = 0;
1695	        return;
1696	    }
1697	
1698	    if (allPersistenceDisabled() && RDBGeneratedByReplication) {
1699	        client *slave;
1700	        listNode *ln;
1701	        listIter li;
1702	
1703	        int delrdb = 1;
1704	        listRewind(server.slaves,&li);
1705	        while((ln = listNext(&li))) {
1706	            slave = ln->value;
1707	            if (slave->replstate == SLAVE_STATE_WAIT_BGSAVE_START ||
1708	                slave->replstate == SLAVE_STATE_WAIT_BGSAVE_END ||
1709	                slave->replstate == SLAVE_STATE_SEND_BULK)
1710	            {
1711	                delrdb = 0;
1712	                break; /* No need to check the other replicas. */
1713	            }
1714	        }
1715	        if (delrdb) {
1716	            struct stat sb;
1717	            if (lstat(server.rdb_filename,&sb) != -1) {
1718	                RDBGeneratedByReplication = 0;
1719	                serverLog(LL_NOTICE,
1720	                    "Removing the RDB file used to feed replicas "
1721	                    "in a persistence-less instance");
1722	                bg_unlink(server.rdb_filename);
1723	            }
1724	        }
1725	    }
1726	}
