1728	/* Close the repldbfd and reclaim the page cache if the client hold
1729	 * the last reference to replication DB */
1730	void closeRepldbfd(client *myself) {
1731	    listNode *ln;
1732	    listIter li;
1733	    int reclaim = 1;
1734	    listRewind(server.slaves,&li);
1735	    while((ln = listNext(&li))) {
1736	        client *slave = ln->value;
1737	        if (slave != myself && slave->replstate == SLAVE_STATE_SEND_BULK) {
1738	            reclaim = 0;
1739	            break;
1740	        }
1741	    }
1742	
1743	    if (reclaim) {
1744	        bioCreateCloseJob(myself->repldbfd, 0, 1);
1745	    } else {
1746	        close(myself->repldbfd);
1747	    }
1748	    myself->repldbfd = -1;
1749	}
1750	
1751	void sendBulkToSlave(connection *conn) {
1752	    client *slave = connGetPrivateData(conn);
1753	    char buf[PROTO_IOBUF_LEN];
1754	    ssize_t nwritten, buflen;
1755	
1756	    /* Before sending the RDB file, we send the preamble as configured by the
1757	     * replication process. Currently the preamble is just the bulk count of
1758	     * the file in the form "$<length>\r\n". */
1759	    if (slave->replpreamble) {
1760	        nwritten = connWrite(conn,slave->replpreamble,sdslen(slave->replpreamble));
1761	        if (nwritten == -1) {
1762	            serverLog(LL_WARNING,
1763	                "Write error sending RDB preamble to replica: %s",
1764	                connGetLastError(conn));
1765	            freeClient(slave);
1766	            return;
1767	        }
1768	        atomicIncr(server.stat_net_repl_output_bytes, nwritten);
1769	        sdsrange(slave->replpreamble,nwritten,-1);
1770	        if (sdslen(slave->replpreamble) == 0) {
1771	            sdsfree(slave->replpreamble);
1772	            slave->replpreamble = NULL;
1773	            /* fall through sending data. */
1774	        } else {
1775	            return;
1776	        }
1777	    }
1778	
1779	    /* If the preamble was already transferred, send the RDB bulk data. */
1780	    if (lseek(slave->repldbfd,slave->repldboff,SEEK_SET) == -1) {
1781		serverLog(LL_WARNING,"Failed to lseek the RDB file to offset %lld for replica %s: %s",
1782		    (long long)slave->repldboff, replicationGetSlaveName(slave), strerror(errno));
1783		freeClient(slave);
1784		return;
1785	    }
1786	    buflen = read(slave->repldbfd,buf,PROTO_IOBUF_LEN);
1787	    if (buflen <= 0) {
1788	        serverLog(LL_WARNING,"Read error sending DB to replica: %s",
1789	            (buflen == 0) ? "premature EOF" : strerror(errno));
1790	        freeClient(slave);
1791	        return;
1792	    }
1793	    if ((nwritten = connWrite(conn,buf,buflen)) == -1) {
1794	        if (connGetState(conn) != CONN_STATE_CONNECTED) {
1795	            serverLog(LL_WARNING,"Write error sending DB to replica: %s",
1796	                connGetLastError(conn));
1797	            freeClient(slave);
1798	        }
1799	        return;
1800	    }
1801	    slave->repldboff += nwritten;
1802	    atomicIncr(server.stat_net_repl_output_bytes, nwritten);
1803	    if (slave->repldboff == slave->repldbsize) {
1804	        closeRepldbfd(slave);
1805	        connSetWriteHandler(slave->conn,NULL);
1806	        if (!replicaPutOnline(slave)) {
1807	            freeClient(slave);
1808	            return;
1809	        }
1810	        replicaStartCommandStream(slave);
1811	    }
1812	}
