1814	/* Remove one write handler from the list of connections waiting to be writable
1815	 * during rdb pipe transfer. */
1816	void rdbPipeWriteHandlerConnRemoved(struct connection *conn) {
1817	    if (!connHasWriteHandler(conn))
1818	        return;
1819	    connSetWriteHandler(conn, NULL);
1820	    client *slave = connGetPrivateData(conn);
1821	    slave->repl_last_partial_write = 0;
1822	    server.rdb_pipe_numconns_writing--;
1823	    /* if there are no more writes for now for this conn, or write error: */
1824	    if (server.rdb_pipe_numconns_writing == 0) {
1825	        if (aeCreateFileEvent(server.el, server.rdb_pipe_read, AE_READABLE, rdbPipeReadHandler,NULL) == AE_ERR) {
1826	            serverPanic("Unrecoverable error creating server.rdb_pipe_read file event.");
1827	        }
1828	    }
1829	}
1830	
1831	/* Called in diskless master during transfer of data from the rdb pipe, when
1832	 * the replica becomes writable again. */
1833	void rdbPipeWriteHandler(struct connection *conn) {
1834	    serverAssert(server.rdb_pipe_bufflen>0);
1835	    client *slave = connGetPrivateData(conn);
1836	    ssize_t nwritten;
1837	    if ((nwritten = connWrite(conn, server.rdb_pipe_buff + slave->repldboff,
1838	                              server.rdb_pipe_bufflen - slave->repldboff)) == -1)
1839	    {
1840	        if (connGetState(conn) == CONN_STATE_CONNECTED)
1841	            return; /* equivalent to EAGAIN */
1842	        serverLog(LL_WARNING,"Write error sending DB to replica: %s",
1843	            connGetLastError(conn));
1844	        freeClient(slave);
1845	        return;
1846	    } else {
1847	        slave->repldboff += nwritten;
1848	        atomicIncr(server.stat_net_repl_output_bytes, nwritten);
1849	        if (slave->repldboff < server.rdb_pipe_bufflen) {
1850	            slave->repl_last_partial_write = server.unixtime;
1851	            return; /* more data to write.. */
1852	        }
1853	    }
1854	    rdbPipeWriteHandlerConnRemoved(conn);
1855	}
1856	
1857	/* Called in diskless master, when there's data to read from the child's rdb pipe */
1858	void rdbPipeReadHandler(struct aeEventLoop *eventLoop, int fd, void *clientData, int mask) {
1859	    UNUSED(mask);
1860	    UNUSED(clientData);
1861	    UNUSED(eventLoop);
1862	    int i;
1863	    if (!server.rdb_pipe_buff)
1864	        server.rdb_pipe_buff = zmalloc(PROTO_IOBUF_LEN);
1865	    serverAssert(server.rdb_pipe_numconns_writing==0);
1866	
1867	    while (1) {
1868	        server.rdb_pipe_bufflen = read(fd, server.rdb_pipe_buff, PROTO_IOBUF_LEN);
1869	        if (server.rdb_pipe_bufflen < 0) {
1870	            if (errno == EAGAIN || errno == EWOULDBLOCK)
1871	                return;
1872	            serverLog(LL_WARNING,"Diskless rdb transfer, read error sending DB to replicas: %s", strerror(errno));
1873	            for (i=0; i < server.rdb_pipe_numconns; i++) {
1874	                connection *conn = server.rdb_pipe_conns[i];
1875	                if (!conn)
1876	                    continue;
1877	                client *slave = connGetPrivateData(conn);
1878	                freeClient(slave);
1879	                server.rdb_pipe_conns[i] = NULL;
1880	            }
1881	            killRDBChild();
1882	            return;
1883	        }
1884	
1885	        if (server.rdb_pipe_bufflen == 0) {
1886	            /* EOF - write end was closed. */
1887	            int stillUp = 0;
1888	            aeDeleteFileEvent(server.el, server.rdb_pipe_read, AE_READABLE);
1889	            for (i=0; i < server.rdb_pipe_numconns; i++)
1890	            {
1891	                connection *conn = server.rdb_pipe_conns[i];
1892	                if (!conn)
1893	                    continue;
1894	                stillUp++;
1895	            }
1896	            serverLog(LL_NOTICE,"Diskless rdb transfer, done reading from pipe, %d replicas still up.", stillUp);
1897	            /* Now that the replicas have finished reading, notify the child that it's safe to exit. 
1898	             * When the server detects the child has exited, it can mark the replica as online, and
1899	             * start streaming the replication buffers. */
1900	            close(server.rdb_child_exit_pipe);
1901	            server.rdb_child_exit_pipe = -1;
1902	            return;
1903	        }
1904	
1905	        int stillAlive = 0;
1906	        for (i=0; i < server.rdb_pipe_numconns; i++)
1907	        {
1908	            ssize_t nwritten;
1909	            connection *conn = server.rdb_pipe_conns[i];
1910	            if (!conn)
1911	                continue;
1912	
1913	            client *slave = connGetPrivateData(conn);
1914	            if ((nwritten = connWrite(conn, server.rdb_pipe_buff, server.rdb_pipe_bufflen)) == -1) {
1915	                if (connGetState(conn) != CONN_STATE_CONNECTED) {
1916	                    serverLog(LL_WARNING,"Diskless rdb transfer, write error sending DB to replica: %s",
1917	                        connGetLastError(conn));
1918	                    freeClient(slave);
1919	                    server.rdb_pipe_conns[i] = NULL;
1920	                    continue;
1921	                }
1922	                /* An error and still in connected state, is equivalent to EAGAIN */
1923	                slave->repldboff = 0;
1924	            } else {
1925	                /* Note: when use diskless replication, 'repldboff' is the offset
1926	                 * of 'rdb_pipe_buff' sent rather than the offset of entire RDB. */
1927	                slave->repldboff = nwritten;
1928	                atomicIncr(server.stat_net_repl_output_bytes, nwritten);
1929	            }
1930	            /* If we were unable to write all the data to one of the replicas,
1931	             * setup write handler (and disable pipe read handler, below) */
1932	            if (nwritten != server.rdb_pipe_bufflen) {
1933	                slave->repl_last_partial_write = server.unixtime;
1934	                server.rdb_pipe_numconns_writing++;
1935	                connSetWriteHandler(conn, rdbPipeWriteHandler);
1936	            }
1937	            stillAlive++;
1938	        }
1939	
1940	        if (stillAlive == 0) {
1941	            serverLog(LL_WARNING,"Diskless rdb transfer, last replica dropped, killing fork child.");
1942	            /* Avoid deleting events after killRDBChild as it may trigger new bgsaves for other replicas. */
1943	            aeDeleteFileEvent(server.el, server.rdb_pipe_read, AE_READABLE); 
1944	            killRDBChild();
1945	            break;
1946	        }
1947	        /* Remove the pipe read handler if at least one write handler was set. */
1948	        else if (server.rdb_pipe_numconns_writing) {
1949	            aeDeleteFileEvent(server.el, server.rdb_pipe_read, AE_READABLE);
1950	            break;
1951	        }
1952	    }
1953	}
