1955	/* This function is called at the end of every background saving.
1956	 *
1957	 * The argument bgsaveerr is C_OK if the background saving succeeded
1958	 * otherwise C_ERR is passed to the function.
1959	 * The 'type' argument is the type of the child that terminated
1960	 * (if it had a disk or socket target). */
1961	void updateSlavesWaitingBgsave(int bgsaveerr, int type) {
1962	    listNode *ln;
1963	    listIter li;
1964	
1965	    /* Note: there's a chance we got here from within the REPLCONF ACK command
1966	     * so we must avoid using freeClient, otherwise we'll crash on our way up. */
1967	
1968	    listRewind(server.slaves,&li);
1969	    while((ln = listNext(&li))) {
1970	        client *slave = ln->value;
1971	
1972	        /* We can get here via freeClient()->killRDBChild()->checkChildrenDone(). skip disconnected slaves. */
1973	        if (!slave->conn) continue;
1974	
1975	        if (slave->replstate == SLAVE_STATE_SEND_BULK_AND_STREAM) {
1976	            /* This is the main channel of the slave that received the RDB.
1977	             * Put it online if RDB delivery is successful. */
1978	            if (bgsaveerr == C_OK) {
1979	                /* Notify the task that the snapshot bulk delivery is done */
1980	                if (slave->flags & CLIENT_ASM_MIGRATING)
1981	                    asmSlotSnapshotSucceed(slave->task);
1982	                replicaPutOnline(slave);
1983	            } else {
1984	                freeClientAsync(slave);
1985	            }
1986	        } else if (slave->replstate == SLAVE_STATE_WAIT_BGSAVE_END) {
1987	            struct redis_stat buf;
1988	
1989	            if (bgsaveerr != C_OK) {
1990	                /* Notify the task that the snapshot bulk delivery failed */
1991	                if (slave->flags & CLIENT_ASM_MIGRATING)
1992	                    asmSlotSnapshotFailed(slave->task);
1993	                freeClientAsync(slave);
1994	                serverLog(LL_WARNING,"SYNC failed. BGSAVE child returned an error");
1995	                continue;
1996	            }
1997	
1998	            /* If this was an RDB on disk save, we have to prepare to send
1999	             * the RDB from disk to the slave socket. Otherwise if this was

2000	             * already an RDB -> Slaves socket transfer, used in the case of
2001	             * diskless replication, our work is trivial, we can just put
2002	             * the slave online. */
2003	            if (type == RDB_CHILD_TYPE_SOCKET) {
2004	                /* Slots snapshot */
2005	                if (slave->slave_req & SLAVE_REQ_SLOTS_SNAPSHOT) {
2006	                    serverLog(LL_NOTICE, "Streamed slots snapshot transfer succeeded");
2007	                    freeClientAsync(slave);
2008	                    continue;
2009	                }
2010	
2011	                serverLog(LL_NOTICE,
2012	                    "Streamed RDB transfer with replica %s succeeded (socket). Waiting for REPLCONF ACK from replica to enable streaming",
2013	                        replicationGetSlaveName(slave));
2014	                /* Note: we wait for a REPLCONF ACK message from the replica in
2015	                 * order to really put it online (install the write handler
2016	                 * so that the accumulated data can be transferred). However
2017	                 * we change the replication state ASAP, since our slave
2018	                 * is technically online now.
2019	                 *
2020	                 * So things work like that:
2021	                 *
2022	                 * 1. We end transferring the RDB file via socket.
2023	                 * 2. The replica is put ONLINE but the write handler
2024	                 *    is not installed.
2025	                 * 3. The replica however goes really online, and pings us
2026	                 *    back via REPLCONF ACK commands.
2027	                 * 4. Now we finally install the write handler, and send
2028	                 *    the buffers accumulated so far to the replica.
2029	                 *
2030	                 * But why we do that? Because the replica, when we stream
2031	                 * the RDB directly via the socket, must detect the RDB
2032	                 * EOF (end of file), that is a special random string at the
2033	                 * end of the RDB (for streamed RDBs we don't know the length
2034	                 * in advance). Detecting such final EOF string is much
2035	                 * simpler and less CPU intensive if no more data is sent
2036	                 * after such final EOF. So we don't want to glue the end of
2037	                 * the RDB transfer with the start of the other replication
2038	                 * data. */
2039	                if (!replicaPutOnline(slave)) {
2040	                    freeClientAsync(slave);
2041	                    continue;
2042	                }
2043	                slave->repl_start_cmd_stream_on_ack = 1;
2044	            } else {
2045	                if ((slave->repldbfd = open(server.rdb_filename,O_RDONLY)) == -1 ||
2046	                    redis_fstat(slave->repldbfd,&buf) == -1) {
2047	                    freeClientAsync(slave);
2048	                    serverLog(LL_WARNING,"SYNC failed. Can't open/stat DB after BGSAVE: %s", strerror(errno));
2049	                    continue;
2050	                }
2051	                slave->repldboff = 0;
2052	                slave->repldbsize = buf.st_size;
2053	                slave->replstate = SLAVE_STATE_SEND_BULK;
2054	                slave->replpreamble = sdscatprintf(sdsempty(),"$%lld\r\n",
2055	                    (unsigned long long) slave->repldbsize);
2056	
2057	                connSetWriteHandler(slave->conn,NULL);
2058	                if (connSetWriteHandler(slave->conn,sendBulkToSlave) == C_ERR) {
2059	                    freeClientAsync(slave);
2060	                    continue;
2061	                }
2062	            }
2063	        }
2064	    }
2065	}
