2076	/* Clear (invalidate) the secondary replication ID. This happens, for
2077	 * example, after a full resynchronization, when we start a new replication
2078	 * history. */
2079	void clearReplicationId2(void) {
2080	    memset(server.replid2,'0',sizeof(server.replid));
2081	    server.replid2[CONFIG_RUN_ID_SIZE] = '\0';
2082	    server.second_replid_offset = -1;
2083	}
2084	
2085	/* Use the current replication ID / offset as secondary replication
2086	 * ID, and change the current one in order to start a new history.
2087	 * This should be used when an instance is switched from slave to master
2088	 * so that it can serve PSYNC requests performed using the master
2089	 * replication ID. */
2090	void shiftReplicationId(void) {
2091	    memcpy(server.replid2,server.replid,sizeof(server.replid));
2092	    /* We set the second replid offset to the master offset + 1, since
2093	     * the slave will ask for the first byte it has not yet received, so
2094	     * we need to add one to the offset: for example if, as a slave, we are
2095	     * sure we have the same history as the master for 50 bytes, after we
2096	     * are turned into a master, we can accept a PSYNC request with offset
2097	     * 51, since the slave asking has the same history up to the 50th
2098	     * byte, and is asking for the new bytes starting at offset 51. */
2099	    server.second_replid_offset = server.master_repl_offset+1;
2100	    changeReplicationId();
2101	    serverLog(LL_NOTICE,"Setting secondary replication ID to %s, valid up to offset: %lld. New replication ID is %s", server.replid2, server.second_replid_offset, server.replid);
2102	}
