2126	/* Avoid the master to detect the slave is timing out while loading the
2127	 * RDB file in initial synchronization. We send a single newline character
2128	 * that is valid protocol but is guaranteed to either be sent entirely or
2129	 * not, since the byte is indivisible.
2130	 *
2131	 * The function is called in two contexts: while we flush the current
2132	 * data with emptyData(), and while we load the new data received as an
2133	 * RDB file from the master. */
2134	void replicationSendNewlineToMaster(void) {
2135	    static time_t newline_sent;
2136	    if (time(NULL) != newline_sent) {
2137	        newline_sent = time(NULL);
2138	        /* Pinging back in this stage is best-effort. */
2139	        if (server.repl_transfer_s) connWrite(server.repl_transfer_s, "\n", 1);
2140	    }
2141	}
