2165	/* Once we have a link with the master and the synchronization was
2166	 * performed, this function materializes the master client we store
2167	 * at server.master, starting from the specified file descriptor. */
2168	void replicationCreateMasterClient(connection *conn, int dbid) {
2169	    server.master = createClient(conn);
2170	    if (conn)
2171	        connSetReadHandler(server.master->conn, readQueryFromClient);
2172	
2173	    /**
2174	     * Important note:
2175	     * The CLIENT_DENY_BLOCKING flag is not, and should not, be set here.
2176	     * For commands like BLPOP, it makes no sense to block the master
2177	     * connection, and such blocking attempt will probably cause deadlock and
2178	     * break the replication. We consider such a thing as a bug because
2179	     * commands as BLPOP should never be sent on the replication link.
2180	     * A possible use-case for blocking the replication link is if a module wants
2181	     * to pass the execution to a background thread and unblock after the
2182	     * execution is done. This is the reason why we allow blocking the replication
2183	     * connection. */
2184	    server.master->flags |= CLIENT_MASTER;
2185	
2186	    /* Allocate a private query buffer for the master client instead of using the reusable query buffer.
2187	     * This is done because the master's query buffer data needs to be preserved for my sub-replicas to use. */
2188	    server.master->querybuf = sdsempty();
2189	    server.master->authenticated = 1;
2190	    server.master->reploff = server.master_initial_offset;
2191	    server.master->read_reploff = server.master->reploff;
2192	    server.master->user = NULL; /* This client can do everything. */
2193	    memcpy(server.master->replid, server.master_replid,
2194	        sizeof(server.master_replid));
2195	    /* If master offset is set to -1, this master is old and is not
2196	     * PSYNC capable, so we flag it accordingly. */
2197	    if (server.master->reploff == -1)
2198	        server.master->flags |= CLIENT_PRE_PSYNC;
2199	    if (dbid != -1) selectDb(server.master,dbid);
2200	}
