2202	static int useDisklessLoad(void) {
2203	    /* compute boolean decision to use diskless load */
2204	    int enabled = server.repl_diskless_load == REPL_DISKLESS_LOAD_ALWAYS || server.repl_diskless_load == REPL_DISKLESS_LOAD_SWAPDB ||
2205	           (server.repl_diskless_load == REPL_DISKLESS_LOAD_WHEN_DB_EMPTY && dbTotalServerKeyCount()==0);
2206	
2207	    if (enabled) {
2208	        /* Check all modules handle read errors, otherwise it's not safe to use diskless load. */
2209	        if (server.repl_diskless_load != REPL_DISKLESS_LOAD_ALWAYS && !moduleAllDatatypesHandleErrors()) {
2210	            serverLog(LL_NOTICE,
2211	                "Skipping diskless-load because there are modules that don't handle read errors.");
2212	            enabled = 0;
2213	        }
2214	        /* Check all modules handle async replication, otherwise it's not safe to use diskless load. */
2215	        else if (server.repl_diskless_load == REPL_DISKLESS_LOAD_SWAPDB && !moduleAllModulesHandleReplAsyncLoad()) {
