2712	     * to the new file. */
2713	    if (server.aof_enabled) {
2714	        serverLog(LL_NOTICE, "MASTER <-> REPLICA sync: Starting AOF after a successful sync");
2715	        startAppendOnlyWithRetry();
2716	    }
2717	
2718	    /* Stream accumulated replication buffer to the db and finalize fullsync */
2719	    if (rdbchannel) {
2720	        if (server.repl_rdb_transfer_s) {
2721	            connClose(server.repl_rdb_transfer_s);
2722	            server.repl_rdb_transfer_s = NULL;
2723	        }
2724	        rdbChannelStreamReplDataToDb();
2725	    }
2726	
2727	    return;
2728	
2729	error:
2730	    cancelReplicationHandshake(1);
2731	    return;
2732	}
