2755	/* Compose a multi-bulk command and send it to the connection.
2756	 * Used to send AUTH and REPLCONF commands to the master before starting the
2757	 * replication.
2758	 *
2759	 * Takes a list of char* arguments, terminated by a NULL argument.
2760	 *
2761	 * The command returns an sds string representing the result of the
2762	 * operation. On error the first byte is a "-".
2763	 */
2764	char *sendCommand(connection *conn, ...) {
2765	    va_list ap;
2766	    sds cmd = sdsempty();
2767	    sds cmdargs = sdsempty();
2768	    size_t argslen = 0;
2769	    char *arg;
2770	
2771	    /* Create the command to send to the master, we use redis binary
2772	     * protocol to make sure correct arguments are sent. This function
2773	     * is not safe for all binary data. */
2774	    va_start(ap,conn);
2775	    while(1) {
2776	        arg = va_arg(ap, char*);
2777	        if (arg == NULL) break;
2778	        cmdargs = sdscatprintf(cmdargs,"$%zu\r\n%s\r\n",strlen(arg),arg);
2779	        argslen++;
2780	    }
2781	
2782	    cmd = sdscatprintf(cmd,"*%zu\r\n",argslen);
2783	    cmd = sdscatsds(cmd,cmdargs);
2784	    sdsfree(cmdargs);
2785	
2786	    va_end(ap);
2787	    char* err = sendCommandRaw(conn, cmd);
2788	    sdsfree(cmd);
2789	    if(err)
2790	        return err;
2791	    return NULL;
2792	}
