2794	/* Compose a multi-bulk command and send it to the connection. 
2795	 * Used to send AUTH and REPLCONF commands to the master before starting the
2796	 * replication.
2797	 *
2798	 * argv_lens is optional, when NULL, strlen is used.
2799	 *
2800	 * The command returns an sds string representing the result of the
2801	 * operation. On error the first byte is a "-".
2802	 */
2803	char *sendCommandArgv(connection *conn, int argc, char **argv, size_t *argv_lens) {
2804	    sds cmd = sdsempty();
2805	    char *arg;
2806	    int i;
2807	
2808	    /* Create the command to send to the master. */
2809	    cmd = sdscatfmt(cmd,"*%i\r\n",argc);
2810	    for (i=0; i<argc; i++) {
2811	        int len;
2812	        arg = argv[i];
2813	        len = argv_lens ? argv_lens[i] : strlen(arg);
2814	        cmd = sdscatfmt(cmd,"$%i\r\n",len);
2815	        cmd = sdscatlen(cmd,arg,len);
2816	        cmd = sdscatlen(cmd,"\r\n",2);
2817	    }
2818	    char* err = sendCommandRaw(conn, cmd);
2819	    sdsfree(cmd);
2820	    if (err)
2821	        return err;
2822	    return NULL;
2823	}
