2825	/* Try a partial resynchronization with the master if we are about to reconnect.
2826	 * If there is no cached master structure, at least try to issue a
2827	 * "PSYNC ? -1" command in order to trigger a full resync using the PSYNC
2828	 * command in order to obtain the master replid and the master replication
2829	 * global offset.
2830	 *
2831	 * This function is designed to be called from syncWithMaster(), so the
2832	 * following assumptions are made:
2833	 *
2834	 * 1) We pass the function an already connected socket "fd".
2835	 * 2) This function does not close the file descriptor "fd". However in case
2836	 *    of successful partial resynchronization, the function will reuse
2837	 *    'fd' as file descriptor of the server.master client structure.
2838	 *
2839	 * The function is split in two halves: if read_reply is 0, the function
2840	 * writes the PSYNC command on the socket, and a new function call is
2841	 * needed, with read_reply set to 1, in order to read the reply of the
2842	 * command. This is useful in order to support non blocking operations, so
2843	 * that we write, return into the event loop, and read when there are data.
2844	 *
2845	 * When read_reply is 0 the function returns PSYNC_WRITE_ERR if there
2846	 * was a write error, or PSYNC_WAIT_REPLY to signal we need another call
2847	 * with read_reply set to 1. However even when read_reply is set to 1
2848	 * the function may return PSYNC_WAIT_REPLY again to signal there were
2849	 * insufficient data to read to complete its work. We should re-enter
2850	 * into the event loop and wait in such a case.
2851	 *
2852	 * The function returns:
2853	 *
2854	 * PSYNC_CONTINUE: If the PSYNC command succeeded and we can continue.
2855	 * PSYNC_FULLRESYNC: If PSYNC is supported but a full resync is needed.
2856	 *                   In this case the master replid and global replication
2857	 *                   offset is saved.
2858	 * PSYNC_NOT_SUPPORTED: If the server does not understand PSYNC at all and
2859	 *                      the caller should fall back to SYNC.
2860	 * PSYNC_WRITE_ERROR: There was an error writing the command to the socket.
2861	 * PSYNC_WAIT_REPLY: Call again the function with read_reply set to 1.
2862	 * PSYNC_TRY_LATER: Master is currently in a transient error condition.
2863	 *
2864	 * Notable side effects:
2865	 *
2866	 * 1) As a side effect of the function call the function removes the readable
2867	 *    event handler from "fd", unless the return value is PSYNC_WAIT_REPLY.
2868	 * 2) server.master_initial_offset is set to the right value according
2869	 *    to the master reply. This will be used to populate the 'server.master'
2870	 *    structure replication offset.
2871	 */
2872	
2873	#define PSYNC_WRITE_ERROR 0
2874	#define PSYNC_WAIT_REPLY 1
2875	#define PSYNC_CONTINUE 2
2876	#define PSYNC_FULLRESYNC 3
2877	#define PSYNC_NOT_SUPPORTED 4
2878	#define PSYNC_TRY_LATER 5
2879	#define PSYNC_FULLRESYNC_RDBCHANNEL 6
2880	int slaveTryPartialResynchronization(connection *conn, int read_reply) {
2881	    char *psync_replid;
2882	    char psync_offset[32];
2883	    sds reply;
2884	
2885	    /* Writing half */
2886	    if (!read_reply) {
2887	        /* Initially set master_initial_offset to -1 to mark the current
2888	         * master replid and offset as not valid. Later if we'll be able to do
2889	         * a FULL resync using the PSYNC command we'll set the offset at the
2890	         * right value, so that this information will be propagated to the
2891	         * client structure representing the master into server.master. */
2892	        server.master_initial_offset = -1;
2893	
2894	        if (server.cached_master) {
2895	            psync_replid = server.cached_master->replid;
2896	            snprintf(psync_offset,sizeof(psync_offset),"%lld", server.cached_master->reploff+1);
2897	            serverLog(LL_NOTICE,"Trying a partial resynchronization (request %s:%s).", psync_replid, psync_offset);
2898	        } else {
2899	            serverLog(LL_NOTICE,"Partial resynchronization not possible (no cached master)");
2900	            psync_replid = "?";
2901	            memcpy(psync_offset,"-1",3);
2902	        }
2903	
2904	        /* Issue the PSYNC command, if this is a master with a failover in
2905	         * progress then send the failover argument to the replica to cause it
2906	         * to become a master */
2907	        if (server.failover_state == FAILOVER_IN_PROGRESS) {
2908	            reply = sendCommand(conn,"PSYNC",psync_replid,psync_offset,"FAILOVER",NULL);
2909	        } else {
2910	            reply = sendCommand(conn,"PSYNC",psync_replid,psync_offset,NULL);
2911	        }
2912	
2913	        if (reply != NULL) {
2914	            serverLog(LL_WARNING,"Unable to send PSYNC to master: %s",reply);
2915	            sdsfree(reply);
2916	            connSetReadHandler(conn, NULL);
2917	            return PSYNC_WRITE_ERROR;
2918	        }
2919	        return PSYNC_WAIT_REPLY;
2920	    }
2921	
2922	    /* Reading half */
2923	    reply = receiveSynchronousResponse(conn);
2924	    /* Master did not reply to PSYNC */
2925	    if (reply == NULL) {
2926	        connSetReadHandler(conn, NULL);
2927	        serverLog(LL_WARNING, "Master did not reply to PSYNC, will try later");
2928	        return PSYNC_TRY_LATER;
2929	    }
2930	
2931	    if (sdslen(reply) == 0) {
2932	        /* The master may send empty newlines after it receives PSYNC
2933	         * and before to reply, just to keep the connection alive. */
2934	        sdsfree(reply);
2935	        return PSYNC_WAIT_REPLY;
2936	    }
2937	
2938	    connSetReadHandler(conn, NULL);
2939	
2940	    if (!strncmp(reply,"+FULLRESYNC",11)) {
2941	        char *replid = NULL, *offset = NULL;
2942	
2943	        /* FULL RESYNC, parse the reply in order to extract the replid
2944	         * and the replication offset. */
2945	        replid = strchr(reply,' ');
2946	        if (replid) {
2947	            replid++;
2948	            offset = strchr(replid,' ');
2949	            if (offset) offset++;
2950	        }
2951	        if (!replid || !offset || (offset-replid-1) != CONFIG_RUN_ID_SIZE) {
2952	            serverLog(LL_WARNING,
2953	                "Master replied with wrong +FULLRESYNC syntax.");
2954	            /* This is an unexpected condition, actually the +FULLRESYNC
2955	             * reply means that the master supports PSYNC, but the reply
2956	             * format seems wrong. To stay safe we blank the master
2957	             * replid to make sure next PSYNCs will fail. */
2958	            memset(server.master_replid,0,CONFIG_RUN_ID_SIZE+1);
2959	        } else {
2960	            memcpy(server.master_replid, replid, offset-replid-1);
2961	            server.master_replid[CONFIG_RUN_ID_SIZE] = '\0';
2962	            server.master_initial_offset = strtoll(offset,NULL,10);
2963	            serverLog(LL_NOTICE,"Full resync from master: %s:%lld",
2964	                server.master_replid,
2965	                server.master_initial_offset);
2966	        }
2967	        sdsfree(reply);
2968	        return PSYNC_FULLRESYNC;
2969	    }
2970	
2971	    if (!strncmp(reply, "+RDBCHANNELSYNC", strlen("+RDBCHANNELSYNC"))) {
2972	        char *client_id = strchr(reply,' ');
2973	        if (client_id)
2974	            client_id++;
2975	
2976	        if (!client_id) {
2977	            serverLog(LL_WARNING,
2978	                      "Master replied with wrong +RDBCHANNELSYNC syntax: %s", reply);
2979	            sdsfree(reply);
2980	            return PSYNC_NOT_SUPPORTED;
2981	        }
2982	        server.repl_main_ch_client_id = strtoll(client_id, NULL, 10);;
2983	        /* A response of +RDBCHANNELSYNC from the master implies that partial
2984	         * synchronization is not possible and that the master supports full
2985	         * sync using dedicated RDB channel. Full sync will continue that way.*/
2986	        serverLog(LL_NOTICE, "PSYNC is not possible, initialize RDB channel.");
2987	        sdsfree(reply);
2988	        return PSYNC_FULLRESYNC_RDBCHANNEL;
2989	    }
2990	
2991	    if (!strncmp(reply,"+CONTINUE",9)) {
2992	        /* Partial resync was accepted. */
2993	        serverLog(LL_NOTICE,
2994	            "Successful partial resynchronization with master.");
2995	
2996	        /* Check the new replication ID advertised by the master. If it
2997	         * changed, we need to set the new ID as primary ID, and set
2998	         * secondary ID as the old master ID up to the current offset, so
2999	         * that our sub-slaves will be able to PSYNC with us after a

3000	         * disconnection. */
3001	        char *start = reply+10;
3002	        char *end = reply+9;
3003	        while(end[0] != '\r' && end[0] != '\n' && end[0] != '\0') end++;
3004	        if (end-start == CONFIG_RUN_ID_SIZE) {
3005	            char new[CONFIG_RUN_ID_SIZE+1];
3006	            memcpy(new,start,CONFIG_RUN_ID_SIZE);
3007	            new[CONFIG_RUN_ID_SIZE] = '\0';
3008	
3009	            if (strcmp(new,server.cached_master->replid)) {
3010	                /* Master ID changed. */
3011	                serverLog(LL_NOTICE,"Master replication ID changed to %s",new);
3012	
3013	                /* Set the old ID as our ID2, up to the current offset+1. */
3014	                memcpy(server.replid2,server.cached_master->replid,
3015	                    sizeof(server.replid2));
3016	                server.second_replid_offset = server.master_repl_offset+1;
3017	
3018	                /* Update the cached master ID and our own primary ID to the
3019	                 * new one. */
3020	                memcpy(server.replid,new,sizeof(server.replid));
3021	                memcpy(server.cached_master->replid,new,sizeof(server.replid));
3022	
3023	                /* Disconnect all the sub-slaves: they need to be notified. */
3024	                disconnectSlaves();
3025	            }
3026	        }
3027	
3028	        /* Setup the replication to continue. */
3029	        sdsfree(reply);
3030	        replicationResurrectCachedMaster(conn);
3031	
3032	        /* If this instance was restarted and we read the metadata to
3033	         * PSYNC from the persistence file, our replication backlog could
3034	         * be still not initialized. Create it. */
3035	        if (server.repl_backlog == NULL) createReplicationBacklog();
3036	        return PSYNC_CONTINUE;
3037	    }
3038	
3039	    /* If we reach this point we received either an error (since the master does
3040	     * not understand PSYNC or because it is in a special state and cannot
3041	     * serve our request), or an unexpected reply from the master.
3042	     *
3043	     * Return PSYNC_NOT_SUPPORTED on errors we don't understand, otherwise
3044	     * return PSYNC_TRY_LATER if we believe this is a transient error. */
3045	
3046	    if (!strncmp(reply,"-NOMASTERLINK",13) ||
3047	        !strncmp(reply,"-LOADING",8))
3048	    {
3049	        serverLog(LL_NOTICE,
3050	            "Master is currently unable to PSYNC "
3051	            "but should be in the future: %s", reply);
3052	        sdsfree(reply);
3053	        return PSYNC_TRY_LATER;
3054	    }
3055	
3056	    if (strncmp(reply,"-ERR",4)) {
3057	        /* If it's not an error, log the unexpected event. */
3058	        serverLog(LL_WARNING,
3059	            "Unexpected reply to PSYNC from master: %s", reply);
3060	    } else {
3061	        serverLog(LL_NOTICE,
3062	            "Master does not support PSYNC or is in "
3063	            "error state (reply: %s)", reply);
3064	    }
3065	    sdsfree(reply);
3066	    return PSYNC_NOT_SUPPORTED;
3067	}
