3069	/* This handler fires when the non blocking connect was able to
3070	 * establish a connection with the master. */
3071	void syncWithMaster(connection *conn) {
3072	    char tmpfile[256], *err = NULL;
3073	    int dfd = -1, maxtries = 5;
3074	    int psync_result;
3075	    static int no_compress_checksum = 0;
3076	
3077	    /* If this event fired after the user turned the instance into a master
3078	     * with SLAVEOF NO ONE we must just return ASAP. */
3079	    if (server.repl_state == REPL_STATE_NONE) {
3080	        connClose(conn);
3081	        return;
3082	    }
3083	
3084	    /* Check for errors in the socket: after a non blocking connect() we
3085	     * may find that the socket is in error state. */
3086	    if (connGetState(conn) != CONN_STATE_CONNECTED) {
3087	        serverLog(LL_WARNING,"Error condition on socket for SYNC: %s",
3088	                connGetLastError(conn));
3089	        goto error;
3090	    }
3091	
3092	    /* Send a PING to check the master is able to reply without errors. */
3093	    if (server.repl_state == REPL_STATE_CONNECTING) {
3094	        serverLog(LL_NOTICE,"Non blocking connect for SYNC fired the event.");
3095	        /* Delete the writable event so that the readable event remains
3096	         * registered and we can wait for the PONG reply. */
3097	        connSetReadHandler(conn, syncWithMaster);
3098	        connSetWriteHandler(conn, NULL);
3099	        server.repl_state = REPL_STATE_RECEIVE_PING_REPLY;
3100	        /* Send the PING, don't check for errors at all, we have the timeout
3101	         * that will take care about this. */
3102	        err = sendCommand(conn,"PING",NULL);
3103	        if (err) goto write_error;
3104	        return;
3105	    }
3106	
3107	    /* Receive the PONG command. */
3108	    if (server.repl_state == REPL_STATE_RECEIVE_PING_REPLY) {
3109	        err = receiveSynchronousResponse(conn);
3110	
3111	        /* The master did not reply */
3112	        if (err == NULL) goto no_response_error;
3113	
3114	        /* We accept only two replies as valid, a positive +PONG reply
3115	         * (we just check for "+") or an authentication error.
3116	         * Note that older versions of Redis replied with "operation not
3117	         * permitted" instead of using a proper error code, so we test
3118	         * both. */
3119	        if (err[0] != '+' &&
3120	            strncmp(err,"-NOAUTH",7) != 0 &&
3121	            strncmp(err,"-NOPERM",7) != 0 &&
3122	            strncmp(err,"-ERR operation not permitted",28) != 0)
3123	        {
3124	            serverLog(LL_WARNING,"Error reply to PING from master: '%s'",err);
3125	            sdsfree(err);
3126	            goto error;
3127	        } else {
3128	            serverLog(LL_NOTICE,
3129	                "Master replied to PING, replication can continue...");
3130	        }
3131	        sdsfree(err);
3132	        err = NULL;
3133	        server.repl_state = REPL_STATE_SEND_HANDSHAKE;
3134	    }
3135	
3136	    if (server.repl_state == REPL_STATE_SEND_HANDSHAKE) {
3137	        /* AUTH with the master if required. */
3138	        if (server.masterauth) {
3139	            char *args[3] = {"AUTH",NULL,NULL};
3140	            size_t lens[3] = {4,0,0};
3141	            int argc = 1;
3142	            if (server.masteruser) {
3143	                args[argc] = server.masteruser;
3144	                lens[argc] = strlen(server.masteruser);
3145	                argc++;
3146	            }
3147	            args[argc] = server.masterauth;
3148	            lens[argc] = sdslen(server.masterauth);
3149	            argc++;
3150	            err = sendCommandArgv(conn, argc, args, lens);
3151	            if (err) goto write_error;
3152	        }
3153	
3154	        /* Set the slave port, so that Master's INFO command can list the
3155	         * slave listening port correctly. */
3156	        {
3157	            char buf[LONG_STR_SIZE];
3158	
3159	            slaveGetPortStr(buf, sizeof(buf));
3160	            err = sendCommand(conn,"REPLCONF",
3161	                    "listening-port",buf, NULL);
3162	            if (err) goto write_error;
3163	        }
3164	
3165	        /* Set the slave ip, so that Master's INFO command can list the
3166	         * slave IP address port correctly in case of port forwarding or NAT.
3167	         * Skip REPLCONF ip-address if there is no slave-announce-ip option set. */
3168	        if (server.slave_announce_ip) {
3169	            err = sendCommand(conn,"REPLCONF",
3170	                    "ip-address",server.slave_announce_ip, NULL);
3171	            if (err) goto write_error;
3172	        }
3173	
3174	        /* If we are not going to save the RDB to disk, request that RDB
3175	         * compression and checksum be disabled, which speeds up RDB delivery
3176	         * and loading. */
3177	        no_compress_checksum = 0;
3178	        if (useDisklessLoad()) {
3179	            no_compress_checksum = 1;
3180	            err = sendCommand(conn, "REPLCONF", "rdb-no-compress", "1",
3181	                                    "rdb-no-checksum", "1", NULL);
3182	            if (err) goto write_error;
3183	        }
3184	
3185	        /* Inform the master of our (slave) capabilities.
3186	         *
3187	         * EOF: supports EOF-style RDB transfer for diskless replication.
3188	         * PSYNC2: supports PSYNC v2, so understands +CONTINUE <new repl ID>.
3189	         *
3190	         * The master will ignore capabilities it does not understand. */
3191	        err = sendCommand(conn,"REPLCONF",
3192	                          "capa","eof","capa","psync2",
3193	                          server.repl_rdb_channel ? "capa" : NULL, "rdb-channel-repl", NULL);
3194	
3195	        if (err) goto write_error;
3196	
3197	        server.repl_state = REPL_STATE_RECEIVE_AUTH_REPLY;
3198	        return;
3199	    }
3200	
3201	    if (server.repl_state == REPL_STATE_RECEIVE_AUTH_REPLY && !server.masterauth)
3202	        server.repl_state = REPL_STATE_RECEIVE_PORT_REPLY;
3203	
3204	    /* Receive AUTH reply. */
3205	    if (server.repl_state == REPL_STATE_RECEIVE_AUTH_REPLY) {
3206	        err = receiveSynchronousResponse(conn);
3207	        if (err == NULL) goto no_response_error;
3208	        if (err[0] == '-') {
3209	            serverLog(LL_WARNING,"Unable to AUTH to MASTER: %s",err);
3210	            sdsfree(err);
3211	            goto error;
3212	        }
3213	        sdsfree(err);
3214	        err = NULL;
3215	        server.repl_state = REPL_STATE_RECEIVE_PORT_REPLY;
3216	        return;
3217	    }
3218	
3219	    /* Receive REPLCONF listening-port reply. */
3220	    if (server.repl_state == REPL_STATE_RECEIVE_PORT_REPLY) {
3221	        err = receiveSynchronousResponse(conn);
3222	        if (err == NULL) goto no_response_error;
3223	        /* Ignore the error if any, not all the Redis versions support
3224	         * REPLCONF listening-port. */
3225	        if (err[0] == '-') {
3226	            serverLog(LL_NOTICE,"(Non critical) Master does not understand "
3227	                                "REPLCONF listening-port: %s", err);
3228	        }
3229	        sdsfree(err);
3230	        server.repl_state = REPL_STATE_RECEIVE_IP_REPLY;
3231	        return;
3232	    }
3233	
3234	    if (server.repl_state == REPL_STATE_RECEIVE_IP_REPLY && !server.slave_announce_ip)
3235	        server.repl_state = REPL_STATE_RECEIVE_REQ_REPLY;
3236	
3237	    /* Receive REPLCONF ip-address reply. */
3238	    if (server.repl_state == REPL_STATE_RECEIVE_IP_REPLY) {
3239	        err = receiveSynchronousResponse(conn);
3240	        if (err == NULL) goto no_response_error;
3241	        /* Ignore the error if any, not all the Redis versions support
3242	         * REPLCONF ip-address. */
3243	        if (err[0] == '-') {
3244	            serverLog(LL_NOTICE,"(Non critical) Master does not understand "
3245	                                "REPLCONF ip-address: %s", err);
3246	        }
3247	        sdsfree(err);
3248	        server.repl_state = REPL_STATE_RECEIVE_REQ_REPLY;
3249	        return;
3250	    }
3251	
3252	    if (server.repl_state == REPL_STATE_RECEIVE_REQ_REPLY && !no_compress_checksum)
3253	        server.repl_state = REPL_STATE_RECEIVE_CAPA_REPLY;
3254	
3255	    /* Receive REPLCONF REQUEST reply (rdb-no-compress and rdb-no-checksum). */
3256	    if (server.repl_state == REPL_STATE_RECEIVE_REQ_REPLY) {
3257	        err = receiveSynchronousResponse(conn);
3258	        if (err == NULL) goto no_response_error;
3259	        /* Ignore the error if any, not all the Redis versions support
3260	         * REPLCONF rdb-no-compress and rdb-no-checksum. */
3261	        if (err[0] == '-') {
3262	            serverLog(LL_NOTICE,"(Non critical) Master does not understand "
3263	                                "REPLCONF rdb-no-compress/checksum: %s", err);
3264	        }
3265	        sdsfree(err);
3266	        server.repl_state = REPL_STATE_RECEIVE_CAPA_REPLY;
3267	        return;
3268	    }
3269	
3270	    /* Receive CAPA reply. */
3271	    if (server.repl_state == REPL_STATE_RECEIVE_CAPA_REPLY) {
3272	        err = receiveSynchronousResponse(conn);
3273	        if (err == NULL) goto no_response_error;
3274	        /* Ignore the error if any, not all the Redis versions support
3275	         * REPLCONF capa. */
3276	        if (err[0] == '-') {
3277	            serverLog(LL_NOTICE,"(Non critical) Master does not understand "
3278	                                  "REPLCONF capa: %s", err);
3279	        }
3280	        sdsfree(err);
3281	        err = NULL;
3282	        server.repl_state = REPL_STATE_SEND_PSYNC;
3283	    }
3284	
3285	    /* Try a partial resynchronization. If we don't have a cached master
3286	     * slaveTryPartialResynchronization() will at least try to use PSYNC
3287	     * to start a full resynchronization so that we get the master replid
3288	     * and the global offset, to try a partial resync at the next
3289	     * reconnection attempt. */
3290	    if (server.repl_state == REPL_STATE_SEND_PSYNC) {
3291	        if (slaveTryPartialResynchronization(conn,0) == PSYNC_WRITE_ERROR) {
3292	            err = sdsnew("Write error sending the PSYNC command.");
3293	            abortFailover("Write error to failover target");
3294	            goto write_error;
3295	        }
3296	        server.repl_state = REPL_STATE_RECEIVE_PSYNC_REPLY;
3297	        return;
3298	    }
3299	
3300	    /* If reached this point, we should be in REPL_STATE_RECEIVE_PSYNC_REPLY. */
3301	    if (server.repl_state != REPL_STATE_RECEIVE_PSYNC_REPLY) {
3302	        serverLog(LL_WARNING,"syncWithMaster(): state machine error, "
3303	                             "state should be RECEIVE_PSYNC_REPLY but is %d",
3304	                             server.repl_state);
3305	        goto error;
3306	    }
3307	
3308	    psync_result = slaveTryPartialResynchronization(conn,1);
3309	    if (psync_result == PSYNC_WAIT_REPLY) return; /* Try again later... */
3310	
3311	    /* Check the status of the planned failover. We expect PSYNC_CONTINUE,
3312	     * but there is nothing technically wrong with a full resync which
3313	     * could happen in edge cases. */
3314	    if (server.failover_state == FAILOVER_IN_PROGRESS) {
3315	        if (psync_result == PSYNC_CONTINUE ||
3316	            psync_result == PSYNC_FULLRESYNC ||
3317	            psync_result == PSYNC_FULLRESYNC_RDBCHANNEL)
3318	        {
3319	            clearFailoverState();
3320	        } else {
3321	            abortFailover("Failover target rejected psync request");
3322	            return;
3323	        }
3324	    }
3325	
3326	    /* If the master is in an transient error, we should try to PSYNC
3327	     * from scratch later, so go to the error path. This happens when
3328	     * the server is loading the dataset or is not connected with its
3329	     * master and so forth. */
3330	    if (psync_result == PSYNC_TRY_LATER) goto error;
3331	
3332	    /* Note: if PSYNC does not return WAIT_REPLY, it will take care of
3333	     * uninstalling the read handler from the file descriptor. */
3334	
3335	    if (psync_result == PSYNC_CONTINUE) {
3336	        serverLog(LL_NOTICE, "MASTER <-> REPLICA sync: Master accepted a Partial Resynchronization.");
3337	        if (server.supervised_mode == SUPERVISED_SYSTEMD) {
3338	            redisCommunicateSystemd("STATUS=MASTER <-> REPLICA sync: Partial Resynchronization accepted. Ready to accept connections in read-write mode.\n");
3339	        }
3340	        return;
3341	    }
3342	
3343	    /* Fall back to SYNC if needed. Otherwise psync_result == PSYNC_FULLRESYNC
3344	     * and the server.master_replid and master_initial_offset are
3345	     * already populated. */
3346	    if (psync_result == PSYNC_NOT_SUPPORTED) {
3347	        serverLog(LL_NOTICE,"Retrying with SYNC...");
3348	        if (connSyncWrite(conn,"SYNC\r\n",6,server.repl_syncio_timeout*1000) == -1) {
3349	            serverLog(LL_WARNING,"I/O error writing to MASTER: %s",
3350	                connGetLastError(conn));
3351	            goto error;
3352	        }
3353	    }
3354	
3355	    /* Prepare a suitable temp file for bulk transfer */
3356	    if (!useDisklessLoad()) {
3357	        while(maxtries--) {
3358	            snprintf(tmpfile,256,
3359	                "temp-%d.%ld.rdb",(int)server.unixtime,(long int)getpid());
3360	            dfd = open(tmpfile,O_CREAT|O_WRONLY|O_EXCL,0644);
3361	            if (dfd != -1) break;
3362	            sleep(1);
3363	        }
3364	        if (dfd == -1) {
3365	            serverLog(LL_WARNING,"Opening the temp file needed for MASTER <-> REPLICA synchronization: %s",strerror(errno));
3366	            goto error;
3367	        }
3368	        server.repl_transfer_tmpfile = zstrdup(tmpfile);
3369	        server.repl_transfer_fd = dfd;
3370	    }
3371	
3372	    server.repl_transfer_size = -1;
3373	    server.repl_transfer_read = 0;
3374	    server.repl_transfer_last_fsync_off = 0;
3375	    server.repl_transfer_lastio = server.unixtime;
3376	
3377	    /* Using rdb channel replication, the master responded +RDBCHANNELSYNC.
3378	     * We need to initialize the RDB channel. */
3379	    if (psync_result == PSYNC_FULLRESYNC_RDBCHANNEL) {
3380	        /* Create RDB connection */
3381	        server.repl_rdb_transfer_s = connCreate(server.el, connTypeOfReplication());
3382	        if (connConnect(server.repl_rdb_transfer_s, server.masterhost,
3383	                        server.masterport, server.bind_source_addr,
3384	                        rdbChannelFullSyncWithMaster) == C_ERR) {
3385	            serverLog(LL_WARNING, "Unable to connect to master: %s", connGetLastError(server.repl_rdb_transfer_s));
3386	            goto error;
3387	        }
3388	        server.repl_rdb_ch_state = REPL_RDB_CH_SEND_HANDSHAKE;
3389	        connSetReadHandler(server.repl_transfer_s, NULL);
3390	        return;
3391	    }
3392	
3393	    /* Setup the non blocking download of the bulk file. */
3394	    if (connSetReadHandler(conn, readSyncBulkPayload)
3395	            == C_ERR)
3396	    {
3397	        char conninfo[CONN_INFO_LEN];
3398	        serverLog(LL_WARNING,
3399	            "Can't create readable event for SYNC: %s (%s)",
3400	            strerror(errno), connGetInfo(conn, conninfo, sizeof(conninfo)));
3401	        goto error;
3402	    }
3403	
3404	    server.repl_state = REPL_STATE_TRANSFER;
3405	    return;
3406	
3407	no_response_error: /* Handle receiveSynchronousResponse() error when master has no reply */
3408	    serverLog(LL_WARNING, "Master did not respond to command during SYNC handshake");
3409	    /* Fall through to regular error handling */
3410	
3411	error:
3412	    if (dfd != -1) close(dfd);
3413	    connClose(conn);
3414	    if (server.repl_rdb_transfer_s)
3415	        connClose(server.repl_rdb_transfer_s);
3416	    server.repl_rdb_transfer_s = NULL;
3417	    server.repl_transfer_s = NULL;
3418	    if (server.repl_transfer_fd != -1)
3419	        close(server.repl_transfer_fd);
3420	    if (server.repl_transfer_tmpfile)
3421	        zfree(server.repl_transfer_tmpfile);
3422	    server.repl_transfer_tmpfile = NULL;
3423	    server.repl_transfer_fd = -1;
3424	    server.repl_state = REPL_STATE_CONNECT;
3425	    return;
3426	
3427	write_error: /* Handle sendCommand() errors. */
3428	    serverLog(LL_WARNING,"Sending command to master in replication handshake: %s", err);
3429	    sdsfree(err);
3430	    goto error;
3431	}
