3433	int connectWithMaster(void) {
3434	    server.repl_current_sync_attempts++;
3435	    server.repl_total_sync_attempts++;
3436	    server.repl_transfer_s = connCreate(server.el, connTypeOfReplication());
3437	    if (connConnect(server.repl_transfer_s, server.masterhost, server.masterport,
3438	                server.bind_source_addr, syncWithMaster) == C_ERR) {
3439	        serverLog(LL_WARNING,"Unable to connect to MASTER: %s",
3440	                connGetLastError(server.repl_transfer_s));
3441	        connClose(server.repl_transfer_s);
3442	        server.repl_transfer_s = NULL;
3443	        return C_ERR;
3444	    }
3445	
3446	
3447	    server.repl_transfer_lastio = server.unixtime;
3448	    server.repl_state = REPL_STATE_CONNECTING;
3449	    serverLog(LL_NOTICE,"MASTER <-> REPLICA sync started");
3450	    return C_OK;
3451	}
