3453	/* This function can be called when a non blocking connection is currently
3454	 * in progress to undo it.
3455	 * Never call this function directly, use cancelReplicationHandshake() instead.
3456	 */
3457	void undoConnectWithMaster(void) {
3458	    connClose(server.repl_transfer_s);
3459	    server.repl_transfer_s = NULL;
