3462	/* Abort the async download of the bulk dataset while SYNC-ing with master.
3463	 * Never call this function directly, use cancelReplicationHandshake() instead.
3464	 */
3465	void replicationAbortSyncTransfer(void) {
3466	    serverAssert(server.repl_state == REPL_STATE_TRANSFER);
3467	    undoConnectWithMaster();
3468	    if (server.repl_disconnect_start_time == 0)
3469	        server.repl_disconnect_start_time = server.unixtime;
3470	    if (server.repl_transfer_fd!=-1) {
3471	        close(server.repl_transfer_fd);
3472	        bg_unlink(server.repl_transfer_tmpfile);
3473	        zfree(server.repl_transfer_tmpfile);
3474	        server.repl_transfer_tmpfile = NULL;
3475	        server.repl_transfer_fd = -1;
3476	    }
3477	}
