3479	/* This function aborts a non blocking replication attempt if there is one
3480	 * in progress, by canceling the non-blocking connect attempt or
3481	 * the initial bulk transfer.
3482	 *
3483	 * If there was a replication handshake in progress 1 is returned and
3484	 * the replication state (server.repl_state) set to REPL_STATE_CONNECT.
3485	 *
3486	 * Otherwise zero is returned and no operation is performed at all. */
3487	int cancelReplicationHandshake(int reconnect) {
3488	    if (rdbChannelAbort() != C_OK)
3489	        return 1;
3490	
3491	    if (server.repl_state == REPL_STATE_TRANSFER) {
3492	        replicationAbortSyncTransfer();
3493	        server.repl_state = REPL_STATE_CONNECT;
3494	    } else if (server.repl_state == REPL_STATE_CONNECTING ||
3495	               slaveIsInHandshakeState())
3496	    {
3497	        undoConnectWithMaster();
3498	        server.repl_state = REPL_STATE_CONNECT;
3499	    } else {
3500	        return 0;
3501	    }
3502	
3503	    if (!reconnect)
3504	        return 1;
3505	
3506	    /* try to re-connect without waiting for replicationCron, this is needed
3507	     * for the "diskless loading short read" test. */
3508	    serverLog(LL_NOTICE,"Reconnecting to MASTER %s:%d after failure",
3509	        server.masterhost, server.masterport);
3510	    connectWithMaster();
3511	
3512	    return 1;
3513	}
