3515	/* Set replication to the specified master address and port. */
3516	void replicationSetMaster(char *ip, int port) {
3517	    int was_master = server.masterhost == NULL;
3518	
3519	    sdsfree(server.masterhost);
3520	    server.masterhost = NULL;
3521	    if (server.master) {
3522	        freeClient(server.master);
3523	    }
3524	    disconnectAllBlockedClients(); /* Clients blocked in master, now slave. */
3525	
3526	    /* Setting masterhost only after the call to freeClient since it calls
3527	     * replicationHandleMasterDisconnection which can trigger a re-connect
3528	     * directly from within that call. */
3529	    server.masterhost = sdsnew(ip);
3530	    server.masterport = port;
3531	
3532	    /* Update oom_score_adj */
3533	    setOOMScoreAdj(-1);
3534	
3535	    /* Here we don't disconnect with replicas, since they may hopefully be able
3536	     * to partially resync with us. We will disconnect with replicas and force
3537	     * them to resync with us when changing replid on partially resync with new
3538	     * master, or finishing transferring RDB and preparing loading DB on full
3539	     * sync with new master. */
3540	
3541	    cancelReplicationHandshake(0);
3542	    /* Before destroying our master state, create a cached master using
3543	     * our own parameters, to later PSYNC with the new master. */
3544	    if (was_master) {
3545	        replicationDiscardCachedMaster();
3546	        replicationCacheMasterUsingMyself();
3547	    }
3548	
3549	    /* Fire the role change modules event. */
3550	    moduleFireServerEvent(REDISMODULE_EVENT_REPLICATION_ROLE_CHANGED,
3551	                          REDISMODULE_EVENT_REPLROLECHANGED_NOW_REPLICA,
3552	                          NULL);
3553	
3554	    /* Fire the master link modules event. */
3555	    if (server.repl_state == REPL_STATE_CONNECTED)
3556	        moduleFireServerEvent(REDISMODULE_EVENT_MASTER_LINK_CHANGE,
3557	                              REDISMODULE_SUBEVENT_MASTER_LINK_DOWN,
3558	                              NULL);
3559	
3560	    server.repl_state = REPL_STATE_CONNECT;
3561	    server.repl_current_sync_attempts = 0;
3562	    server.repl_total_sync_attempts = 0;
3563	    serverLog(LL_NOTICE,"Connecting to MASTER %s:%d",
3564	        server.masterhost, server.masterport);
3565	    connectWithMaster();
3566	}
