3568	/* Cancel replication, setting the instance as a master itself. */
3569	void replicationUnsetMaster(void) {
3570	    if (server.masterhost == NULL) return; /* Nothing to do. */
3571	
3572	    /* Fire the master link modules event. */
3573	    if (server.repl_state == REPL_STATE_CONNECTED)
3574	        moduleFireServerEvent(REDISMODULE_EVENT_MASTER_LINK_CHANGE,
3575	                              REDISMODULE_SUBEVENT_MASTER_LINK_DOWN,
3576	                              NULL);
3577	
3578	    /* Clear masterhost first, since the freeClient calls
3579	     * replicationHandleMasterDisconnection which can attempt to re-connect. */
3580	    sdsfree(server.masterhost);
3581	    server.masterhost = NULL;
3582	    if (server.master) freeClient(server.master);
3583	    replicationDiscardCachedMaster();
3584	    cancelReplicationHandshake(0);
3585	    /* When a slave is turned into a master, the current replication ID
3586	     * (that was inherited from the master at synchronization time) is
3587	     * used as secondary ID up to the current offset, and a new replication
3588	     * ID is created to continue with a new replication history. */
3589	    shiftReplicationId();
3590	    /* Disconnecting all the slaves is required: we need to inform slaves
3591	     * of the replication ID change (see shiftReplicationId() call). However
3592	     * the slaves will be able to partially resync with us, so it will be
3593	     * a very fast reconnection. */
3594	    disconnectSlaves();
3595	    server.repl_state = REPL_STATE_NONE;
3596	    /* Reset the attempts number. */
3597	    server.repl_current_sync_attempts = 0;
3598	    server.repl_total_sync_attempts = 0;
3599	    /* We need to make sure the new master will start the replication stream
3600	     * with a SELECT statement. This is forced after a full resync, but
3601	     * with PSYNC version 2, there is no need for full resync after a
3602	     * master switch. */
3603	    server.slaveseldb = -1;
3604	
3605	    /* Update oom_score_adj */
3606	    setOOMScoreAdj(-1);
3607	
3608	    /* Once we turn from slave to master, we consider the starting time without
3609	     * slaves (that is used to count the replication backlog time to live) as
3610	     * starting from now. Otherwise the backlog will be freed after a
3611	     * failover if slaves do not connect immediately. */
3612	    server.repl_no_slaves_since = server.unixtime;
3613	    
3614	    /* Reset up and down time so it'll be ready for when we turn into replica again. */
3615	    server.repl_down_since = 0;
3616	    server.repl_up_since = 0;
3617	    /* Fire the role change modules event. */
3618	    moduleFireServerEvent(REDISMODULE_EVENT_REPLICATION_ROLE_CHANGED,
3619	                          REDISMODULE_EVENT_REPLROLECHANGED_NOW_MASTER,
3620	                          NULL);
3621	
3622	    /* Restart the AOF subsystem in case we shut it down during a sync when
3623	     * we were still a slave. */
3624	    if (server.aof_enabled && server.aof_state == AOF_OFF) {
3625	        serverLog(LL_NOTICE, "Restarting AOF after becoming master");
3626	        startAppendOnlyWithRetry();
3627	    }
3628	}
