3630	/* This function is called when the slave lose the connection with the
3631	 * master into an unexpected way. */
3632	void replicationHandleMasterDisconnection(void) {
3633	    /* Fire the master link modules event. */
3634	    if (server.repl_state == REPL_STATE_CONNECTED)
3635	        moduleFireServerEvent(REDISMODULE_EVENT_MASTER_LINK_CHANGE,
3636	                              REDISMODULE_SUBEVENT_MASTER_LINK_DOWN,
3637	                              NULL);
3638	
3639	    server.master = NULL;
3640	    if (server.repl_state == REPL_STATE_CONNECTED)
3641	        server.repl_current_sync_attempts = 0;
3642	    server.repl_state = REPL_STATE_CONNECT;
3643	    server.repl_down_since = server.unixtime;
3644	    server.repl_up_since = 0;
3645	    server.repl_num_master_disconnection++;
3646	
3647	    /* If we are in the loop of streaming accumulated buffers, discard the
3648	     * buffer and clean up the rdbchannel state. The outer loop will abort once
3649	     * it detects that the master client has been disconnected. For details,
3650	     * see rdbChannelStreamReplDataToDb() */
3651	    if (server.repl_main_ch_state & REPL_MAIN_CH_STREAMING_BUF)
3652	        rdbChannelCleanup();
3653	
3654	    if (server.repl_disconnect_start_time == 0)
3655	        server.repl_disconnect_start_time = server.unixtime;
3656	    /* We lost connection with our master, don't disconnect slaves yet,
3657	     * maybe we'll be able to PSYNC with our master later. We'll disconnect
3658	     * the slaves only if we'll have to do a full resync with our master. */
3659	
3660	    /* Try to re-connect immediately rather than wait for replicationCron
3661	     * waiting 1 second may risk backlog being recycled. */
3662	    if (server.masterhost) {
3663	        serverLog(LL_NOTICE,"Reconnecting to MASTER %s:%d",
3664	            server.masterhost, server.masterport);
3665	        connectWithMaster();
3666	    }
3667	}
