3669	/* Rdb channel for full sync
3670	 *
3671	 * - During a full sync, when master is delivering RDB to the replica, incoming
3672	 *   write commands are kept in a replication buffer in order to be sent to the
3673	 *   replica once RDB delivery is completed. If RDB delivery takes a long time,
3674	 *   it might create memory pressure on master. Also, once a replica connection
3675	 *   accumulates replication data which is larger than output buffer limits,
3676	 *   master will kill replica connection. This may cause a replication failure.
3677	 *
3678	 *   The main benefit of the rdb channel replication is streaming incoming
3679	 *   commands in parallel to the RDB delivery. This approach shifts replication
3680	 *   stream buffering to the replica and reduces load on master. We do this by
3681	 *   opening another connection for RDB delivery. The main channel on replica
3682	 *   will be receiving replication stream while rdb channel is receiving the RDB.
3683	 *
3684	 *   This feature also helps to reduce master's main process CPU load. By
3685	 *   opening a dedicated connection for the RDB transfer, the bgsave process has
3686	 *   direct access to the new connection and it will stream RDB directly to the
3687	 *   replicas. Before this change, due to TLS connection restriction, the bgsave
3688	 *   process was writing RDB bytes to a pipe and the main process was forwarding
3689	 *   it to the replica. This is no longer necessary, the main process can avoid
3690	 *   these expensive socket read/write syscalls.
3691	 *
3692	 *  Implementation
3693	 *  - When replica connects to the master, it sends 'rdb-channel-repl' as part
3694	 *    of capability exchange to let master to know replica supports rdb channel.
3695	 *  - When replica lacks sufficient data for PSYNC, master sends +RDBCHANNELSYNC
3696	 *    reply with replica's client id. As the next step, the replica opens a new
3697	 *    connection (rdb-channel) and configures it against the master with the
3698	 *    appropriate capabilities and requirements. It also sends given client id
3699	 *    back to master over rdbchannel so that master can associate these
3700	 *    channels (initial replica connection will be referred as main-channel)
3701	 *    Then, replica requests fullsync using the RDB channel.
3702	 *  - Prior to forking, master attaches the replica's main channel to the
3703	 *    replication backlog to deliver replication stream starting at the snapshot
3704	 *    end offset.
3705	 *  - The master main process sends replication stream via the main channel,
3706	 *    while the bgsave process sends the RDB directly to the replica via the
3707	 *    rdb-channel. Replica accumulates replication stream in a local buffer,
3708	 *    while the RDB is being loaded into the memory.
3709	 *  - Once the replica completes loading the rdb, it drops the rdb channel and
3710	 *    streams the accumulated replication stream into the db. Sync is completed.
3711	 *
3712	 * * Replica state machine *
3713	 *
3714	 * Main channel state
3715	 * ┌───────────────────┐
3716	 * │RECEIVE_PING_REPLY │
3717	 * └────────┬──────────┘
3718	 *          │ +PONG
3719	 * ┌────────▼──────────┐
3720	 * │SEND_HANDSHAKE     │                     RDB channel state
3721	 * └────────┬──────────┘            ┌───────────────────────────────┐
3722	 *          │+OK                ┌───► RDB_CH_SEND_HANDSHAKE         │
3723	 * ┌────────▼──────────┐        │   └──────────────┬────────────────┘
3724	 * │RECEIVE_AUTH_REPLY │        │    REPLCONF main-ch-client-id <clientid>
3725	 * └────────┬──────────┘        │   ┌──────────────▼────────────────┐
3726	 *          │+OK                │   │ RDB_CH_RECEIVE_AUTH_REPLY     │
3727	 * ┌────────▼──────────┐        │   └──────────────┬────────────────┘
3728	 * │RECEIVE_PORT_REPLY │        │                  │ +OK
3729	 * └────────┬──────────┘        │   ┌──────────────▼────────────────┐
3730	 *          │+OK                │   │  RDB_CH_RECEIVE_REPLCONF_REPLY│
3731	 * ┌────────▼──────────┐        │   └──────────────┬────────────────┘
3732	 * │RECEIVE_IP_REPLY   │        │                  │ +OK
3733	 * └────────┬──────────┘        │   ┌──────────────▼────────────────┐
3734	 *          │+OK                │   │ RDB_CH_RECEIVE_FULLRESYNC     │
3735	 * ┌────────▼──────────┐        │   └──────────────┬────────────────┘
3736	 * │RECEIVE_CAPA_REPLY │        │                  │+FULLRESYNC
3737	 * └────────┬──────────┘        │                  │Rdb delivery
3738	 *          │                   │   ┌──────────────▼────────────────┐
3739	 * ┌────────▼──────────┐        │   │ RDB_CH_RDB_LOADING            │
3740	 * │SEND_PSYNC         │        │   └──────────────┬────────────────┘
3741	 * └─┬─────────────────┘        │                  │ Done loading
3742	 *   │PSYNC (use cached-master) │                  │
3743	 * ┌─▼─────────────────┐        │                  │
3744	 * │RECEIVE_PSYNC_REPLY│        │    ┌────────────►│ Replica streams replication
3745	 * └─┬─────────────────┘        │    │             │ buffer into memory
3746	 *   │                          │    │             │
3747	 *   │+RDBCHANNELSYNC client-id │    │             │
3748	 *   ├──────┬───────────────────┘    │             │
3749	 *   │      │ Main channel           │             │
3750	 *   │      │ accumulates repl data  │             │
3751	 *   │   ┌──▼────────────────┐       │     ┌───────▼───────────┐
3752	 *   │   │ REPL_TRANSFER     ├───────┘     │    CONNECTED      │
3753	 *   │   └───────────────────┘             └────▲───▲──────────┘
3754	 *   │                                          │   │
3755	 *   │                                          │   │
3756	 *   │  +FULLRESYNC    ┌───────────────────┐    │   │
3757	 *   ├────────────────► REPL_TRANSFER      ├────┘   │
3758	 *   │                 └───────────────────┘        │
3759	 *   │  +CONTINUE                                   │
3760	 *   └──────────────────────────────────────────────┘
3761	 */
3762	
3763	/* Replication: Replica side. */
3764	static int rdbChannelSendHandshake(connection *conn, sds *err) {
3765	    /* AUTH with the master if required. */
3766	    if (server.masterauth) {
3767	        char *args[] = {"AUTH", NULL, NULL};
3768	        size_t lens[] = {4, 0, 0};
3769	        int argc = 1;
3770	        if (server.masteruser) {
3771	            args[argc] = server.masteruser;
3772	            lens[argc] = strlen(server.masteruser);
3773	            argc++;
3774	        }
3775	        args[argc] = server.masterauth;
3776	        lens[argc] = sdslen(server.masterauth);
3777	        argc++;
3778	        *err = sendCommandArgv(conn, argc, args, lens);
3779	        if (*err) {
3780	            serverLog(LL_WARNING, "Error sending AUTH to master in rdb channel replication handshake: %s", *err);
3781	            return C_ERR;
3782	        }
3783	    }
3784	
3785	    char buf[LONG_STR_SIZE];
3786	    slaveGetPortStr(buf, sizeof(buf));
3787	
3788	    char cid[LONG_STR_SIZE];
3789	    ull2string(cid, sizeof(cid), server.repl_main_ch_client_id);
3790	
3791	    *err = sendCommand(conn, "REPLCONF", "capa", "eof", "rdb-only", "1",
3792	                       "rdb-channel", "1", "main-ch-client-id", cid,
3793	                       "listening-port", buf,
3794	                       server.slave_announce_ip ? "ip-address" : NULL,
3795	                       server.slave_announce_ip ? server.slave_announce_ip : NULL,
3796	                       NULL);
3797	    
3798	    if (*err) {
3799	        serverLog(LL_WARNING, "Error sending REPLCONF command to master in rdb channel handshake: %s", *err);
3800	        return C_ERR;
3801	    }
3802	
3803	    if (connSetReadHandler(conn, rdbChannelFullSyncWithMaster) == C_ERR) {
3804	        char conninfo[CONN_INFO_LEN];
3805	        serverLog(LL_WARNING, "Can't create readable event for SYNC: %s (%s)",
3806	                  strerror(errno), connGetInfo(conn, conninfo, sizeof(conninfo)));
3807	        return C_ERR;
3808	    }
3809	    return C_OK;
3810	}
