3812	/* Replication: Replica side. */
3813	static int rdbChannelHandleAuthReply(connection *conn, sds *err) {
3814	    *err = receiveSynchronousResponse(conn);
3815	    if (*err == NULL) {
3816	        serverLog(LL_WARNING, "Master did not respond to auth command during rdb channel handshake");
3817	        return C_ERR;
3818	    }
3819	    if ((*err)[0] == '-') {
3820	        serverLog(LL_WARNING, "Unable to AUTH to master: %s", *err);
3821	        return C_ERR;
3822	    }
3823	    server.repl_rdb_ch_state = REPL_RDB_CH_RECEIVE_REPLCONF_REPLY;
3824	    return C_OK;
3825	}
3826	
3827	/* Replication: Replica side. */
3828	static int rdbChannelHandleReplconfReply(connection *conn, sds *err) {
3829	    *err = receiveSynchronousResponse(conn);
3830	    if (*err == NULL) {
3831	        serverLog(LL_WARNING, "Master did not respond to replconf command during rdb channel handshake");
3832	        return C_ERR;
3833	    }
3834	    if (*err[0] == '-') {
3835	        serverLog(LL_WARNING, "Master replied error to replconf: %s", *err);
3836	        return C_ERR;
3837	    }
3838	    sdsfree(*err);
3839	
3840	    if (server.repl_debug_pause & REPL_DEBUG_BEFORE_RDB_CHANNEL)
3841	        debugPauseProcess();
3842	
3843	    /* Request rdb from master */
3844	    *err = sendCommand(conn, "PSYNC", "?", "-1", NULL);
3845	    if (*err) {
3846	        serverLog(LL_WARNING, "I/O error writing to Master: %s", *err);
3847	        return C_ERR;
3848	    }
3849	
3850	    return C_OK;
3851	}
