3853	/* Replication: Replica side. */
3854	static int rdbChannelHandleFullresyncReply(connection *conn, sds *err) {
3855	    char *replid = NULL, *offset = NULL;
3856	
3857	    *err = receiveSynchronousResponse(conn);
3858	    if (*err == NULL)
3859	        return C_ERR;
3860	
3861	    if (*err[0] == '\0') {
3862	        /* Retry again later */
3863	        serverLog(LL_DEBUG, "Received empty psync reply");
3864	        return C_RETRY;
3865	    }
3866	
3867	    /* FULL RESYNC, parse the reply in order to extract the replid
3868	     * and the replication offset. */
3869	    replid = strchr(*err,' ');
3870	    if (replid) {
3871	        replid++;
3872	        offset = strchr(replid, ' ');
3873	        if (offset) offset++;
3874	    }
3875	    if (!replid || !offset || (offset-replid-1) != CONFIG_RUN_ID_SIZE) {
3876	        serverLog(LL_WARNING, "Received unexpected psync reply: %s", *err);
3877	        return C_ERR;
3878	    }
3879	    memcpy(server.master_replid, replid, offset-replid-1);
3880	    server.master_replid[CONFIG_RUN_ID_SIZE] = '\0';
3881	    server.master_initial_offset = strtoll(offset,NULL,10);
3882	
3883	    /* Prepare the main and rdb channels for rdb and repl stream delivery.*/
3884	    server.repl_state = REPL_STATE_TRANSFER;
3885	    rdbChannelReplDataBufInit();
3886	
3887	    serverLog(LL_NOTICE, "Starting to receive RDB and replication stream in parallel.");
3888	
3889	    /* Setup connection to accumulate repl data.  */
3890	    server.repl_main_ch_state = REPL_MAIN_CH_ACCUMULATE_BUF;
3891	    if (connSetReadHandler(server.repl_transfer_s,
3892	                           rdbChannelBufferReplData) != C_OK)
3893	    {
3894	        serverLog(LL_WARNING, "Can't set read handler for main channel: %s",
3895	                  strerror(errno));
3896	        return C_ERR;
3897	    }
3898	
3899	    /* Prepare RDB channel connection for RDB download. */
3900	    if (connSetReadHandler(server.repl_rdb_transfer_s,
3901	                           readSyncBulkPayload) != C_OK)
3902	    {
3903	        char inf[CONN_INFO_LEN];
3904	        serverLog(LL_WARNING,
3905	                  "Can't create readable event for rdb channel connection: %s (%s)",
3906	                  strerror(errno),
3907	                  connGetInfo(server.repl_rdb_transfer_s, inf, sizeof(inf)));
3908	        return C_ERR;
3909	    }
3910	
3911	    return C_OK;
3912	}
3913	
3914	/* Replication: Replica side.
3915	 * This connection handler is used to initialize the RDB channel connection.*/
3916	static void rdbChannelFullSyncWithMaster(connection *conn) {
3917	    int ret = 0;
3918	    char *err = NULL;
3919	    serverAssert(conn == server.repl_rdb_transfer_s);
3920	
3921	    /* Check for errors in the socket: after a non blocking connect() we
3922	     * may find that the socket is in error state. */
3923	    if (connGetState(conn) != CONN_STATE_CONNECTED) {
3924	        serverLog(LL_WARNING, "Error condition on socket for rdb channel replication: %s",
3925	                  connGetLastError(conn));
3926	        goto error;
3927	    }
3928	    switch (server.repl_rdb_ch_state) {
3929	        case REPL_RDB_CH_SEND_HANDSHAKE:
3930	            ret = rdbChannelSendHandshake(conn, &err);
3931	            if (ret == C_OK)
3932	                server.repl_rdb_ch_state = REPL_RDB_CH_RECEIVE_AUTH_REPLY;
3933	            break;
3934	        case REPL_RDB_CH_RECEIVE_AUTH_REPLY:
3935	            if (server.masterauth) {
3936	                ret = rdbChannelHandleAuthReply(conn, &err);
3937	                if (ret == C_OK)
3938	                    server.repl_rdb_ch_state = REPL_RDB_CH_RECEIVE_REPLCONF_REPLY;
3939	                /* Wait for next bulk before trying to read replconf reply. */
3940	                break;
3941	            }
3942	            server.repl_rdb_ch_state = REPL_RDB_CH_RECEIVE_REPLCONF_REPLY;
3943	            /* fall through */
3944	        case REPL_RDB_CH_RECEIVE_REPLCONF_REPLY:
3945	            ret = rdbChannelHandleReplconfReply(conn, &err);
3946	            if (ret == C_OK)
3947	                server.repl_rdb_ch_state = REPL_RDB_CH_RECEIVE_FULLRESYNC;
3948	            break;
3949	        case REPL_RDB_CH_RECEIVE_FULLRESYNC:
3950	            ret = rdbChannelHandleFullresyncReply(conn, &err);
3951	            if (ret == C_OK)
3952	                server.repl_rdb_ch_state = REPL_RDB_CH_RDB_LOADING;
3953	            break;
3954	        default:
3955	            serverPanic("Unknown rdb channel state: %d", server.repl_rdb_ch_state);
3956	    }
3957	
3958	    if (ret == C_ERR)
3959	        goto error;
3960	
3961	    sdsfree(err);
3962	    return;
3963	
3964	error:
3965	    if (err) {
3966	        serverLog(LL_WARNING, "rdb channel sync failed with error: %s", err);
3967	        sdsfree(err);
3968	    }
3969	    if (server.repl_transfer_s) {
3970	        connClose(server.repl_transfer_s);
3971	        server.repl_transfer_s = NULL;
3972	    }
3973	    server.repl_state = REPL_STATE_CONNECT;
3974	    rdbChannelAbort();
3975	}
