3995	
3996	/* Replication: Replica side.
3997	 * Initialize replica's local replication buffer to accumulate repl stream
3998	 * during rdb channel sync. */
3999	static void rdbChannelReplDataBufInit(void) {

5000	
5001	    /* Second, send a newline to all the slaves in pre-synchronization
5002	     * stage, that is, slaves waiting for the master to create the RDB file.
5003	     *
5004	     * Also send the a newline to all the chained slaves we have, if we lost
5005	     * connection from our master, to keep the slaves aware that their
5006	     * master is online. This is needed since sub-slaves only receive proxied
5007	     * data from top-level masters, so there is no explicit pinging in order
5008	     * to avoid altering the replication offsets. This special out of band
5009	     * pings (newlines) can be sent, they will have no effect in the offset.
5010	     *
5011	     * The newline will be ignored by the slave but will refresh the
5012	     * last interaction timer preventing a timeout. In this case we ignore the
5013	     * ping period and refresh the connection once per second since certain
5014	     * timeouts are set at a few seconds (example: PSYNC response). */
5015	    listRewind(server.slaves,&li);
5016	    while((ln = listNext(&li))) {
5017	        client *slave = ln->value;
5018	
5019	        int is_presync =
5020	            (slave->replstate == SLAVE_STATE_WAIT_BGSAVE_START ||
5021	            (slave->replstate == SLAVE_STATE_WAIT_BGSAVE_END &&
5022	             server.rdb_child_type != RDB_CHILD_TYPE_SOCKET));
5023	
5024	        if (is_presync && !(slave->flags & CLIENT_CLOSE_ASAP)) {
5025	            connWrite(slave->conn, "\n", 1);
5026	        }
5027	    }
5028	
5029	    /* Disconnect timedout slaves. */
5030	    if (listLength(server.slaves)) {
5031	        listIter li;
5032	        listNode *ln;
5033	
5034	        listRewind(server.slaves,&li);
5035	        while((ln = listNext(&li))) {
5036	            client *slave = ln->value;
5037	
5038	            if (slave->replstate == SLAVE_STATE_ONLINE) {
5039	                if (slave->flags & CLIENT_PRE_PSYNC)
5040	                    continue;
5041	                if ((server.unixtime - slave->repl_ack_time) > server.repl_timeout) {
5042	                    serverLog(LL_WARNING, "Disconnecting timedout replica (streaming sync): %s",
5043	                          replicationGetSlaveName(slave));
5044	                    freeClient(slave);
5045	                    continue;
5046	                }
5047	            }
5048	            /* We consider disconnecting only diskless replicas because disk-based replicas aren't fed
5049	             * by the fork child so if a disk-based replica is stuck it doesn't prevent the fork child
5050	             * from terminating. */
5051	            if (slave->replstate == SLAVE_STATE_WAIT_BGSAVE_END && server.rdb_child_type == RDB_CHILD_TYPE_SOCKET) {
5052	                if (slave->repl_last_partial_write != 0 &&
5053	                    (server.unixtime - slave->repl_last_partial_write) > server.repl_timeout)
5054	                {
5055	                    serverLog(LL_WARNING, "Disconnecting timedout replica (full sync): %s",
5056	                          replicationGetSlaveName(slave));
5057	                    freeClient(slave);
5058	                    continue;
5059	                }
5060	            }
5061	        }
5062	    }
5063	
5064	    /* If this is a master without attached slaves and there is a replication
5065	     * backlog active, in order to reclaim memory we can free it after some
5066	     * (configured) time. Note that this cannot be done for slaves: slaves
5067	     * without sub-slaves attached should still accumulate data into the
5068	     * backlog, in order to reply to PSYNC queries if they are turned into
5069	     * masters after a failover. */
5070	    if (listLength(server.slaves) == 0 && server.repl_backlog_time_limit &&
5071	        server.repl_backlog && server.masterhost == NULL)
5072	    {
5073	        time_t idle = server.unixtime - server.repl_no_slaves_since;
5074	
5075	        if (idle > server.repl_backlog_time_limit) {
5076	            /* When we free the backlog, we always use a new
5077	             * replication ID and clear the ID2. This is needed
5078	             * because when there is no backlog, the master_repl_offset
5079	             * is not updated, but we would still retain our replication
5080	             * ID, leading to the following problem:
5081	             *
5082	             * 1. We are a master instance.
5083	             * 2. Our slave is promoted to master. It's repl-id-2 will
5084	             *    be the same as our repl-id.
5085	             * 3. We, yet as master, receive some updates, that will not
5086	             *    increment the master_repl_offset.
5087	             * 4. Later we are turned into a slave, connect to the new
5088	             *    master that will accept our PSYNC request by second
5089	             *    replication ID, but there will be data inconsistency
5090	             *    because we received writes. */
5091	            changeReplicationId();
5092	            clearReplicationId2();
5093	            freeReplicationBacklog();
5094	            serverLog(LL_NOTICE,
5095	                "Replication backlog freed after %d seconds "
5096	                "without connected replicas.",
5097	                (int) server.repl_backlog_time_limit);
5098	        }
5099	    }
5100	
5101	    replicationStartPendingFork();
5102	
5103	    /* Remove the RDB file used for replication if Redis is not running
5104	     * with any persistence. */
5105	    removeRDBUsedToSyncReplicas();
5106	
5107	    /* Sanity check replication buffer, the first block of replication buffer blocks
5108	     * must be referenced by someone, since it will be freed when not referenced,
5109	     * otherwise, server will OOM. also, its refcount must not be more than
5110	     * replicas number + 1(replication backlog). */
5111	    if (listLength(server.repl_buffer_blocks) > 0) {
5112	        replBufBlock *o = listNodeValue(listFirst(server.repl_buffer_blocks));
5113	        serverAssert(o->refcount > 0 &&
5114	            o->refcount <= (int)listLength(server.slaves)+1);
5115	    }
5116	
5117	    /* Refresh the number of slaves with lag <= min-slaves-max-lag. */
5118	    refreshGoodSlavesCount();
5119	}
