5121	int shouldStartChildReplication(int *mincapa_out, int *req_out) {
5122	    /* We should start a BGSAVE good for replication if we have slaves in
5123	     * WAIT_BGSAVE_START state.
5124	     *
5125	     * In case of diskless replication, we make sure to wait the specified
5126	     * number of seconds (according to configuration) so that other slaves
5127	     * have the time to arrive before we start streaming. */
5128	    if (!hasActiveChildProcess()) {
5129	        time_t idle, max_idle = 0;
5130	        int slaves_waiting = 0;
5131	        int mincapa;
5132	        int req;
5133	        int first = 1;
5134	        listNode *ln;
5135	        listIter li;
5136	
5137	        listRewind(server.slaves,&li);
5138	        while((ln = listNext(&li))) {
5139	            client *slave = ln->value;
5140	            if (slave->replstate == SLAVE_STATE_WAIT_BGSAVE_START) {
5141	                if (first) {
5142	                    /* Get first slave's requirements */
5143	                    req = slave->slave_req;
5144	                } else if (req != slave->slave_req) {
5145	                    /* Skip slaves that don't match */
5146	                    continue;
5147	                }
5148	                idle = server.unixtime - slave->lastinteraction;
5149	                /* If the slave requests a slots snapshot, we should start BGSAVE
5150	                 * immediately since it can't share the RDB with other slaves. */
5151	                if (slave->slave_req & SLAVE_REQ_SLOTS_SNAPSHOT)
5152	                    idle = server.repl_diskless_sync_delay; /* Threshold for BGSAVE */
5153	                if (idle > max_idle) max_idle = idle;
5154	                slaves_waiting++;
5155	                mincapa = first ? slave->slave_capa : (mincapa & slave->slave_capa);
5156	                first = 0;
5157	            }
5158	        }
5159	
5160	        if (slaves_waiting &&
5161	            (!server.repl_diskless_sync ||
5162	             (server.repl_diskless_sync_max_replicas > 0 &&
5163	              slaves_waiting >= server.repl_diskless_sync_max_replicas) ||
5164	             max_idle >= server.repl_diskless_sync_delay))
5165	        {
5166	            if (mincapa_out)
5167	                *mincapa_out = mincapa;
5168	            if (req_out)
5169	                *req_out = req;
5170	            return 1;
5171	        }
5172	    }
5173	
5174	    return 0;
5175	}
5176	
5177	void replicationStartPendingFork(void) {
5178	    int mincapa = -1;
5179	    int req = -1;
5180	
5181	    if (shouldStartChildReplication(&mincapa, &req)) {
5182	        /* Start the BGSAVE. The called function may start a
5183	         * BGSAVE with socket target or disk target depending on the
5184	         * configuration and slaves capabilities and requirements. */
5185	        startBgsaveForReplication(mincapa, req);
5186	    }
5187	}
