5189	/* Find replica at IP:PORT from replica list */
5190	static client *findReplica(char *host, int port) {
5191	    listIter li;
5192	    listNode *ln;
5193	    client *replica;
5194	
5195	    listRewind(server.slaves,&li);
5196	    while((ln = listNext(&li))) {
5197	        replica = ln->value;
5198	        char ip[NET_IP_STR_LEN], *replicaip = replica->slave_addr;
5199	
5200	        if (!replicaip) {
5201	            if (connAddrPeerName(replica->conn, ip, sizeof(ip), NULL) == -1)
5202	                continue;
5203	            replicaip = ip;
5204	        }
5205	
5206	        if (!strcasecmp(host, replicaip) &&
5207	                (port == replica->slave_listening_port))
5208	            return replica;
5209	    }
5210	
5211	    return NULL;
5212	}
