5236	/* Abort an ongoing failover if one is going on. */
5237	void abortFailover(const char *err) {
5238	    if (server.failover_state == NO_FAILOVER) return;
5239	
5240	    if (server.target_replica_host) {
5241	        serverLog(LL_NOTICE,"FAILOVER to %s:%d aborted: %s",
5242	            server.target_replica_host,server.target_replica_port,err);  
