5252	/* 
5253	 * FAILOVER [TO <HOST> <PORT> [FORCE]] [ABORT] [TIMEOUT <timeout>]
5254	 * 
5255	 * This command will coordinate a failover between the master and one
5256	 * of its replicas. The happy path contains the following steps:
5257	 * 1) The master will initiate a client pause write, to stop replication
5258	 * traffic.
5259	 * 2) The master will periodically check if any of its replicas has
5260	 * consumed the entire replication stream through acks. 
5261	 * 3) Once any replica has caught up, the master will itself become a replica.
5262	 * 4) The master will send a PSYNC FAILOVER request to the target replica, which
5263	 * if accepted will cause the replica to become the new master and start a sync.
5264	 * 
5265	 * FAILOVER ABORT is the only way to abort a failover command, as replicaof
5266	 * will be disabled. This may be needed if the failover is unable to progress. 
5267	 * 
5268	 * The optional arguments [TO <HOST> <IP>] allows designating a specific replica
5269	 * to be failed over to.
5270	 * 
5271	 * FORCE flag indicates that even if the target replica is not caught up,
5272	 * failover to it anyway. This must be specified with a timeout and a target
5273	 * HOST and IP.
5274	 * 
5275	 * TIMEOUT <timeout> indicates how long should the primary wait for 
5276	 * a replica to sync up before aborting. If not specified, the failover
5277	 * will attempt forever and must be manually aborted.
5278	 */
5279	void failoverCommand(client *c) {
5280	    if (!clusterAllowFailoverCmd(c)) {
5281	        return;
5282	    }
5283	
5284	    /* Handle special case for abort */
5285	    if ((c->argc == 2) && !strcasecmp(c->argv[1]->ptr,"abort")) {
5286	        if (server.failover_state == NO_FAILOVER) {
5287	            addReplyError(c, "No failover in progress.");
5288	            return;
5289	        }
5290	
5291	        abortFailover("Failover manually aborted");
5292	        addReply(c,shared.ok);
5293	        return;
5294	    }
5295	
5296	    long timeout_in_ms = 0;
5297	    int force_flag = 0;
5298	    long port = 0;
5299	    char *host = NULL;
5300	
5301	    /* Parse the command for syntax and arguments. */
5302	    for (int j = 1; j < c->argc; j++) {
5303	        if (!strcasecmp(c->argv[j]->ptr,"timeout") && (j + 1 < c->argc) &&
5304	            timeout_in_ms == 0)
5305	        {
5306	            if (getLongFromObjectOrReply(c,c->argv[j + 1],
5307	                        &timeout_in_ms,NULL) != C_OK) return;
5308	            if (timeout_in_ms <= 0) {
5309	                addReplyError(c,"FAILOVER timeout must be greater than 0");
5310	                return;
5311	            }
5312	            j++;
5313	        } else if (!strcasecmp(c->argv[j]->ptr,"to") && (j + 2 < c->argc) &&
5314	            !host) 
5315	        {
5316	            if (getLongFromObjectOrReply(c,c->argv[j + 2],&port,NULL) != C_OK)
5317	                return;
5318	            host = c->argv[j + 1]->ptr;
5319	            j += 2;
5320	        } else if (!strcasecmp(c->argv[j]->ptr,"force") && !force_flag) {
5321	            force_flag = 1;
5322	        } else {
5323	            addReplyErrorObject(c,shared.syntaxerr);
5324	            return;
5325	        }
5326	    }
5327	
5328	    if (server.failover_state != NO_FAILOVER) {
5329	        addReplyError(c,"FAILOVER already in progress.");
5330	        return;
5331	    }
5332	
5333	    if (server.masterhost) {
5334	        addReplyError(c,"FAILOVER is not valid when server is a replica.");
5335	        return;
5336	    }
5337	
5338	    if (listLength(server.slaves) == 0) {
5339	        addReplyError(c,"FAILOVER requires connected replicas.");
5340	        return; 
5341	    }
5342	
5343	    if (force_flag && (!timeout_in_ms || !host)) {
5344	        addReplyError(c,"FAILOVER with force option requires both a timeout "
5345	            "and target HOST and IP.");
5346	        return;     
5347	    }
5348	
5349	    /* If a replica address was provided, validate that it is connected. */
5350	    if (host) {
5351	        client *replica = findReplica(host, port);
5352	
5353	        if (replica == NULL) {
5354	            addReplyError(c,"FAILOVER target HOST and PORT is not "
5355	                            "a replica.");
5356	            return;
5357	        }
5358	
5359	        /* Check if requested replica is online */
5360	        if (replica->replstate != SLAVE_STATE_ONLINE) {
5361	            addReplyError(c,"FAILOVER target replica is not online.");
5362	            return;
5363	        }
5364	
5365	        server.target_replica_host = zstrdup(host);
5366	        server.target_replica_port = port;
5367	        serverLog(LL_NOTICE,"FAILOVER requested to %s:%ld.",host,port);
5368	    } else {
5369	        serverLog(LL_NOTICE,"FAILOVER requested to any replica.");
5370	    }
5371	
5372	    mstime_t now = commandTimeSnapshot();
5373	    if (timeout_in_ms) {
5374	        server.failover_end_time = now + timeout_in_ms;
5375	    }
5376	    
5377	    server.force_failover = force_flag;
5378	    server.failover_state = FAILOVER_WAIT_FOR_SYNC;
5379	    /* Cancel all ASM tasks when starting failover */
5380	    clusterAsmCancel(NULL, "failover requested");
5381	    /* Cluster failover will unpause eventually */
5382	    pauseActions(PAUSE_DURING_FAILOVER,
5383	                 LLONG_MAX,
5384	                 PAUSE_ACTIONS_CLIENT_WRITE_SET);
5385	    addReply(c,shared.ok);
5386	}
