5388	/* Failover cron function, checks coordinated failover state. 
5389	 *
5390	 * Implementation note: The current implementation calls replicationSetMaster()
5391	 * to start the failover request, this has some unintended side effects if the
5392	 * failover doesn't work like blocked clients will be unblocked and replicas will
5393	 * be disconnected. This could be optimized further.
5394	 */
5395	void updateFailoverStatus(void) {
5396	    if (server.failover_state != FAILOVER_WAIT_FOR_SYNC) return;
5397	    mstime_t now = server.mstime;
5398	
5399	    /* Check if failover operation has timed out */
5400	    if (server.failover_end_time && server.failover_end_time <= now) {
5401	        if (server.force_failover) {
5402	            serverLog(LL_NOTICE,
5403	                "FAILOVER to %s:%d time out exceeded, failing over.",
5404	                server.target_replica_host, server.target_replica_port);
5405	            server.failover_state = FAILOVER_IN_PROGRESS;
5406	            /* If timeout has expired force a failover if requested. */
5407	            replicationSetMaster(server.target_replica_host,
5408	                server.target_replica_port);
5409	            return;
5410	        } else {
5411	            /* Force was not requested, so timeout. */
5412	            abortFailover("Replica never caught up before timeout");
5413	            return;
5414	        }
5415	    }
5416	
5417	    /* Check to see if the replica has caught up so failover can start */
5418	    client *replica = NULL;
5419	    if (server.target_replica_host) {
5420	        replica = findReplica(server.target_replica_host, 
5421	            server.target_replica_port);
5422	    } else {
5423	        listIter li;
5424	        listNode *ln;
5425	
5426	        listRewind(server.slaves,&li);
5427	        /* Find any replica that has matched our repl_offset */
5428	        while((ln = listNext(&li))) {
5429	            replica = ln->value;
5430	            if (replica->repl_ack_off == server.master_repl_offset) {
5431	                char ip[NET_IP_STR_LEN], *replicaaddr = replica->slave_addr;
5432	
5433	                if (!replicaaddr) {
5434	                    if (connAddrPeerName(replica->conn,ip,sizeof(ip),NULL) == -1)
5435	                        continue;
5436	                    replicaaddr = ip;
5437	                }
5438	
5439	                /* We are now failing over to this specific node */
5440	                server.target_replica_host = zstrdup(replicaaddr);
5441	                server.target_replica_port = replica->slave_listening_port;
5442	                break;
5443	            }
5444	        }
5445	    }
5446	
5447	    /* We've found a replica that is caught up */
5448	    if (replica && (replica->repl_ack_off == server.master_repl_offset)) {
5449	        server.failover_state = FAILOVER_IN_PROGRESS;
5450	        serverLog(LL_NOTICE,
5451	                "Failover target %s:%d is synced, failing over.",
5452	                server.target_replica_host, server.target_replica_port);
5453	        /* Designated replica is caught up, failover to it. */
5454	        replicationSetMaster(server.target_replica_host,
5455	            server.target_replica_port);
5456	    }
5457	}
5458

4000	    replDataBufInit(&server.repl_full_sync_buffer);
4001	}
