4009	/* Generic function to read data from connection into the last block. */
4010	static int replDataBufReadIntoLastBlock(connection *conn, replDataBuf *buf,
4011	                                    void (*error_handler)(connection *conn))
4012	{
4013	    atomicIncr(IOThreads[IOTHREAD_MAIN_THREAD_ID].io_reads_processed, 1);
4014	
4015	    replDataBufBlock *block = listNodeValue(listLast(buf->blocks));
4016	    serverAssert(block && block->size > block->used);
4017	
4018	    int nread = connRead(conn, block->buf + block->used, block->size - block->used);
4019	    if (nread <= 0) {
4020	        if (nread == 0 || connGetState(conn) != CONN_STATE_CONNECTED) {
4021	            error_handler(conn);
4022	        }
4023	        return -1;
4024	    }
4025	
4026	    block->used += nread;
4027	    if (buf) buf->used += nread;
4028	    atomicIncr(server.stat_net_repl_input_bytes, nread);
4029	
4030	    return nread;
4031	}
4032	
4033	/* Generic function to read data from connection into a buffer. */
4034	void replDataBufReadFromConn(connection *conn, replDataBuf *buf, void (*error_handler)(connection *conn)) {
4035	    const int buflen = 1024 * 1024;
4036	    const int minread = 16 * 1024;
4037	    int nread = 0;
4038	    int needs_read = 1;
4039	
4040	    listNode *ln = listLast(buf->blocks);
4041	    replDataBufBlock *tail = ln ? listNodeValue(ln) : NULL;
4042	
4043	    /* Try to append last node. */
4044	    if (tail && tail->size > tail->used) {
4045	        nread = replDataBufReadIntoLastBlock(conn, buf, error_handler);
4046	        if (nread <= 0)
4047	            return;
4048	
4049	        /* If buffer is filled fully, there might be more data in socket buffer.
4050	         * Only read again if we've read small amount (less than minread). */
4051	        needs_read = (tail->size == tail->used) && nread < minread;
4052	    }
4053	
4054	    if (needs_read) {
4055	        unsigned long long limit;
4056	        size_t usable_size;
4057	
4058	        /* For accumulation limit, if 'replica-full-sync-buffer-limit' is set,
4059	         * we'll use it. Otherwise, 'client-output-buffer-limit <replica>' is
4060	         * the limit.*/
4061	        limit = server.repl_full_sync_buffer_limit;
4062	        if (limit == 0)
4063	            limit = server.client_obuf_limits[CLIENT_TYPE_SLAVE].hard_limit_bytes;
4064	
4065	        if (limit != 0 && buf->size > limit) {
4066	            /* Currently this function is only used for replication and slots sync.
4067	             * Log accordingly, maybe should be extendable in the future. */
4068	            if (server.masterhost)
4069	                serverLog(LL_NOTICE, "Replication buffer limit has been reached (%llu bytes), "
4070	                    "stopped buffering replication stream. Further accumulation may occur on master side.", limit);
4071	            else
4072	                serverLog(LL_NOTICE, "Slots sync buffer limit has been reached (%llu bytes), "
4073	                    "stopped buffering slots sync stream. Further accumulation may occur on source side.", limit);
4074	
4075	            connSetReadHandler(conn, NULL);
4076	            return;
4077	        }
4078	
4079	        tail = zmalloc_usable(buflen, &usable_size);
4080	        tail->size = usable_size - sizeof(replDataBufBlock);
4081	        tail->used = 0;
4082	
4083	        listAddNodeTail(buf->blocks, tail);
4084	        buf->size += tail->size;
4085	        buf->mem_used += usable_size + sizeof(listNode);
4086	
4087	        /* Update buffer's peak */
4088	        if (buf->peak < buf->size)
4089	            buf->peak = buf->size;
4090	
4091	        replDataBufReadIntoLastBlock(conn, buf, error_handler);
4092	    }
4093	}
