4103	/* Replication: Replica side.
4104	 * Read handler for buffering incoming repl data during RDB download/loading. */
4105	static void rdbChannelBufferReplData(connection *conn) {
4106	    replDataBuf *buf = &server.repl_full_sync_buffer;
4107	
4108	    if (server.repl_main_ch_state & REPL_MAIN_CH_STREAMING_BUF) {
4109	        /* While streaming accumulated buffers, we continue reading from the
4110	         * master to prevent accumulation on master side as much as possible.
4111	         * However, we aim to drain buffer eventually. To ensure we consume more
4112	         * than we read, we'll read at most one block after two blocks of
4113	         * buffers are consumed. */
4114	        if (listLength(buf->blocks) + 1 >= buf->last_num_blocks)
4115	            return;
4116	        buf->last_num_blocks = listLength(buf->blocks);
4117	    }
4118	
4119	    replDataBufReadFromConn(conn, buf, readReplBufferErrorHandler);
4120	}
