4122	/* Generic function to stream replDataBuf data into database
4123	 * Returns C_OK on success, C_ERR on error */
4124	int replDataBufStreamToDb(replDataBuf *buf, replDataBufToDbCtx *ctx) {
4125	    listNode *n;
4126	    int ret = C_OK;
4127	    client *c = ctx->client;
4128	
4129	    blockingOperationStarts();
4130	    while ((n = listFirst(buf->blocks))) {
4131	        replDataBufBlock *o = listNodeValue(n);
4132	        listUnlinkNode(buf->blocks, n);
4133	        zfree(n);
4134	
4135	        size_t processed = 0;
4136	        while (processed < o->used) {
4137	            size_t bytes = min(PROTO_IOBUF_LEN, o->used - processed);
4138	            c->querybuf = sdscatlen(c->querybuf, &o->buf[processed], bytes);
4139	            c->read_reploff += (long long int) bytes;
4140	            c->lastinteraction = server.unixtime;
4141	
4142	            /* We don't expect error return value but just in case. */
4143	            ret = processInputBuffer(c);
4144	            if (ret != C_OK) break;
4145	
4146	            processed += bytes;
4147	            buf->used -= bytes;
4148	
4149	            if (server.repl_debug_pause & REPL_DEBUG_ON_STREAMING_REPL_BUF)
4150	                debugPauseProcess();
4151	
4152	            /* Check if we should yield back to the event loop */
4153	            if (server.loading_process_events_interval_bytes &&
4154	                ((ctx->applied_offset + bytes) / server.loading_process_events_interval_bytes >
4155	                  ctx->applied_offset / server.loading_process_events_interval_bytes))
4156	            {
4157	                ctx->yield_callback(ctx);
4158	                processEventsWhileBlocked();
4159	            }
4160	            ctx->applied_offset += bytes;
4161	
4162	            /* Check if we should continue processing */
4163	            if (!ctx->should_continue(ctx)) {
4164	                ret = C_ERR;
4165	                break;
4166	            }
4167	
4168	            /* Streaming buffer into the database more slowly is useful in order
4169	             * to test certain edge cases. */
4170	            if (server.key_load_delay) debugDelay(server.key_load_delay);
4171	        }
4172	        size_t size = o->size;
4173	        zfree(o);
4174	
4175	        /* Break the loop if there is an error. */
4176	        if (ret != C_OK) break;
4177	
4178	        /* Update stats */
4179	        buf->size -= size;
4180	        buf->mem_used -= (size + sizeof(listNode) + sizeof(replDataBufBlock));
4181	    }
4182	    blockingOperationEnds();
4183	
4184	    return ret;
4185	}
