4199	/* Replication: Replica side.
4200	 * Check if we should continue streaming replDataBuf to database */
4201	static int rdbChannelStreamShouldContinue(void *ctx) {
4202	    replDataBufToDbCtx *context = ctx;
4203	
4204	    /* Check if master client was freed in processEventsWhileBlocked().
4205	     * It can happen if we receive 'replicaof' command or 'client kill'
4206	     * command for the master. */
4207	    if (ReplNumMasterDisconnection != server.repl_num_master_disconnection ||
4208	        !server.repl_full_sync_buffer.blocks ||
4209	        context->client->flags & CLIENT_CLOSE_ASAP)
4210	    {
4211	        return 0;
4212	    }
4213	    return 1;
4214	}
