4216	/* Replication: Replica side.
4217	 * Streams accumulated replication data into the database. */
4218	static void rdbChannelStreamReplDataToDb(void) {
4219	    int ret = C_OK, close_asap = 0;
4220	    client *c = server.master;
4221	
4222	    /* Save repl_num_master_disconnection to figure out if master gets
4223	     * disconnected when we yield back to processEventsWhileBlocked() */
4224	    ReplNumMasterDisconnection = server.repl_num_master_disconnection;
4225	
4226	    server.repl_main_ch_state |= REPL_MAIN_CH_STREAMING_BUF;
4227	    serverLog(LL_NOTICE, "MASTER <-> REPLICA sync: Starting to stream replication buffer into the db"
4228	                         " (%zu bytes).", server.repl_full_sync_buffer.used);
4229	    if (!server.repl_full_sync_buffer.blocks)
4230	        goto out;
4231	
4232	    /* Mark the peek buffer block count. We'll use it to verify we consume
4233	     * faster than we read from the master. */
4234	    server.repl_full_sync_buffer.last_num_blocks = listLength(server.repl_full_sync_buffer.blocks);
4235	    /* Set read handler to continue accumulating during streaming */
4236	    connSetReadHandler(c->conn, rdbChannelBufferReplData);
4237	
4238	    replDataBufToDbCtx ctx = {
4239	        .client = c,
4240	        .applied_offset = 0,
4241	        .should_continue = rdbChannelStreamShouldContinue,
4242	        .yield_callback = rdbChannelStreamYieldCallback,
4243	    };
4244	
4245	    ret = replDataBufStreamToDb(&server.repl_full_sync_buffer, &ctx);
4246	
4247	out:
4248	    /* If main channel state is CLOSE_ASAP, it means main channel faced a
4249	     * problem while RDB is being loaded or while we are applying the
4250	     * accumulated buffer. It stopped replication stream buffering. It's okay
4251	     * though. We streamed whatever we have into the db, now we can free master
4252	     * client and replica can try psync. */
4253	    close_asap = (server.repl_main_ch_state & REPL_MAIN_CH_CLOSE_ASAP);
4254	
4255	    if (ret == C_OK) {
4256	        serverLog(LL_NOTICE, "MASTER <-> REPLICA sync: Successfully streamed replication buffer into the db (%zu bytes in total)",
4257	                             ctx.applied_offset);
4258	        /* Revert the read handler */
4259	        if (!close_asap && connSetReadHandler(c->conn, readQueryFromClient) != C_OK) {
4260	            serverLog(LL_WARNING,
4261	                      "Can't create readable event for master client: %s",
4262	                      strerror(errno));
4263	            close_asap = 1;
4264	        }
4265	    } else {
4266	        serverLog(LL_WARNING, "Master client was freed while streaming accumulated replication data to db.");
4267	        close_asap = 1;
4268	    }
4269	
4270	    /* If master is disconnected, state should have been cleaned up
4271	     * already. Otherwise, we do it here. */
4272	    if (ReplNumMasterDisconnection == server.repl_num_master_disconnection) {
4273	        rdbChannelCleanup();
4274	        if (server.master && close_asap)
4275	            freeClient(server.master);
4276	    }
4277	}
