4279	static void rdbChannelCleanup(void) {
4280	    server.repl_rdb_ch_state = REPL_RDB_CH_STATE_NONE;
4281	    server.repl_main_ch_state = REPL_MAIN_CH_NONE;
4282	    rdbChannelReplDataBufClear();
4283	}
