4285	/* Replication: Replica side.
4286	 * On rdb channel failure, close rdb-connection and reset state.
4287	 * Return C_OK if cleanup is done. Otherwise, returns C_ERR which means cleanup
4288	 * will be done asynchronously. */
4289	static int rdbChannelAbort(void) {
4290	    if (server.repl_rdb_ch_state == REPL_RDB_CH_STATE_NONE)
4291	        return C_OK;
4292	
4293	    /* This function may also be called if a problem is detected on the main
4294	     * channel. In this case, we handle the situation differently based on
4295	     * the current state:
4296	     * - If we started loading the RDB file and the RDB is disk-based, we mark
4297	     *   the main channel's state as CLOSE_ASAP and defer the failure handling
4298	     *   until after the RDB has been loaded. This way we allow the replica to
4299	     *   retry psync after the RDB is loaded.
4300	     * - For diskless loading, we cannot safely free the rdb channel connection
4301	     *   object. Instead, we mark the RIO object as aborted so the next
4302	     *   rioRead() will fail safely.
4303	     * - If the RDB has already been loaded, and we are streaming the
4304	     *   accumulated buffer to the database, we mark the main connection
4305	     *   as CLOSE_ASAP and wait until the accumulated buffer is drained.
4306	     *   Once done, the replica can attempt psync with the offset it has. */
4307	    int async_cleanup = (server.repl_rdb_transfer_s && server.loading) ||
4308	                        (server.repl_main_ch_state & REPL_MAIN_CH_STREAMING_BUF);
4309	    if (async_cleanup) {
4310	        if (server.repl_rdb_transfer_s && server.loading) {
4311	            serverLog(LL_NOTICE, "Aborting rdb channel sync while loading the RDB.");
4312	
4313	            if (disklessLoadingRio)
4314	                /* Mark rio with abort flag, next rioRead() will return error.*/
4315	                rioAbort(disklessLoadingRio);
4316	            else {
4317	                /* For disk based loading, we can wait until loading is done.
4318	                 * This way, replica will have a chance for a successful psync
4319	                 * later.*/
4320	                serverLog(LL_NOTICE, "After loading RDB, replica will try psync with master.");
4321	            }
4322	        }
4323	
4324	        if (server.repl_transfer_s)
4325	            connSetReadHandler(server.repl_transfer_s, NULL);
4326	
4327	        server.repl_main_ch_state |= REPL_MAIN_CH_CLOSE_ASAP;
4328	        return C_ERR;
4329	    }
4330	
4331	    serverLog(LL_NOTICE, "Aborting rdb channel sync");
4332	
4333	    if (server.repl_rdb_transfer_s) {
4334	        connClose(server.repl_rdb_transfer_s);
4335	        server.repl_rdb_transfer_s = NULL;
4336	    }
4337	    if (server.repl_transfer_fd != -1) {
4338	        close(server.repl_transfer_fd);
4339	        server.repl_transfer_fd = -1;
4340	    }
4341	    if (server.repl_transfer_tmpfile) {
4342	        bg_unlink(server.repl_transfer_tmpfile);
4343	        zfree(server.repl_transfer_tmpfile);
4344	        server.repl_transfer_tmpfile = NULL;
4345	    }
4346	    rdbChannelCleanup();
4347	    return C_OK;
4348	}
