4350	void replicaofCommand(client *c) {
4351	    /* SLAVEOF is not allowed in cluster mode as replication is automatically
4352	     * configured using the current address of the master node. */
4353	    if (server.cluster_enabled) {
4354	        addReplyError(c,"REPLICAOF not allowed in cluster mode.");
4355	        return;
4356	    }
4357	
4358	    if (server.failover_state != NO_FAILOVER) {
4359	        addReplyError(c,"REPLICAOF not allowed while failing over.");
4360	        return;
4361	    }
4362	
4363	    /* The special host/port combination "NO" "ONE" turns the instance
4364	     * into a master. Otherwise the new master address is set. */
4365	    if (!strcasecmp(c->argv[1]->ptr,"no") &&
4366	        !strcasecmp(c->argv[2]->ptr,"one")) {
4367	        if (server.masterhost) {
4368	            replicationUnsetMaster();
4369	            sds client = catClientInfoString(sdsempty(),c);
4370	            serverLog(LL_NOTICE,"MASTER MODE enabled (user request from '%s')",
4371	                client);
4372	            sdsfree(client);
4373	        }
4374	    } else {
4375	        long port;
4376	
4377	        if (c->flags & CLIENT_SLAVE)
4378	        {
4379	            /* If a client is already a replica they cannot run this command,
4380	             * because it involves flushing all replicas (including this
4381	             * client) */
4382	            addReplyError(c, "Command is not valid when client is a replica.");
4383	            return;
4384	        }
4385	
4386	        if (getRangeLongFromObjectOrReply(c, c->argv[2], 0, 65535, &port,
4387	                                          "Invalid master port") != C_OK)
4388	            return;
4389	
4390	        /* Check if we are already attached to the specified master */
4391	        if (server.masterhost && !strcasecmp(server.masterhost,c->argv[1]->ptr)
4392	            && server.masterport == port) {
4393	            serverLog(LL_NOTICE,"REPLICAOF would result into synchronization "
4394	                                "with the master we are already connected "
4395	                                "with. No operation performed.");
4396	            addReplySds(c,sdsnew("+OK Already connected to specified "
4397	                                 "master\r\n"));
4398	            return;
4399	        }
4400	        /* There was no previous master or the user specified a different one,
4401	         * we can continue. */
4402	        replicationSetMaster(c->argv[1]->ptr, port);
4403	        sds client = catClientInfoString(sdsempty(),c);
4404	        serverLog(LL_NOTICE,"REPLICAOF %s:%d enabled (user request from '%s')",
4405	            server.masterhost, server.masterport, client);
4406	        sdsfree(client);
4407	    }
4408	    addReply(c,shared.ok);
4409	}
