4411	/* ROLE command: provide information about the role of the instance
4412	 * (master or slave) and additional information related to replication
4413	 * in an easy to process format. */
4414	void roleCommand(client *c) {
4415	    if (server.sentinel_mode) {
4416	        sentinelRoleCommand(c);
4417	        return;
4418	    }
4419	
4420	    if (server.masterhost == NULL) {
4421	        listIter li;
4422	        listNode *ln;
4423	        void *mbcount;
4424	        int slaves = 0;
4425	
4426	        addReplyArrayLen(c,3);
4427	        addReplyBulkCBuffer(c,"master",6);
4428	        addReplyLongLong(c,server.master_repl_offset);
4429	        mbcount = addReplyDeferredLen(c);
4430	        listRewind(server.slaves,&li);
4431	        while((ln = listNext(&li))) {
4432	            client *slave = ln->value;
4433	            char ip[NET_IP_STR_LEN], *slaveaddr = slave->slave_addr;
4434	
4435	            if (!slaveaddr) {
4436	                if (connAddrPeerName(slave->conn,ip,sizeof(ip),NULL) == -1)
4437	                    continue;
4438	                slaveaddr = ip;
4439	            }
4440	            if (slave->replstate != SLAVE_STATE_ONLINE) continue;
4441	            addReplyArrayLen(c,3);
4442	            addReplyBulkCString(c,slaveaddr);
4443	            addReplyBulkLongLong(c,slave->slave_listening_port);
4444	            addReplyBulkLongLong(c,slave->repl_ack_off);
4445	            slaves++;
4446	        }
4447	        setDeferredArrayLen(c,mbcount,slaves);
4448	    } else {
4449	        char *slavestate = NULL;
4450	
4451	        addReplyArrayLen(c,5);
4452	        addReplyBulkCBuffer(c,"slave",5);
4453	        addReplyBulkCString(c,server.masterhost);
4454	        addReplyLongLong(c,server.masterport);
4455	        if (slaveIsInHandshakeState()) {
4456	            slavestate = "handshake";
4457	        } else {
4458	            switch(server.repl_state) {
4459	            case REPL_STATE_NONE: slavestate = "none"; break;
4460	            case REPL_STATE_CONNECT: slavestate = "connect"; break;
4461	            case REPL_STATE_CONNECTING: slavestate = "connecting"; break;
4462	            case REPL_STATE_TRANSFER: slavestate = "sync"; break;
4463	            case REPL_STATE_CONNECTED: slavestate = "connected"; break;
4464	            default: slavestate = "unknown"; break;
4465	            }
4466	        }
4467	        addReplyBulkCString(c,slavestate);
4468	        addReplyLongLong(c,server.master ? server.master->reploff : -1);
4469	    }
4470	}
