4472	/* Send a REPLCONF ACK command to the master to inform it about the current
4473	 * processed offset. If we are not connected with a master, the command has
4474	 * no effects. */
4475	void replicationSendAck(void) {
4476	    client *c = server.master;
4477	
4478	    if (c != NULL) {
4479	        int send_fack = server.fsynced_reploff != -1;
4480	        c->flags |= CLIENT_MASTER_FORCE_REPLY;
4481	        addReplyArrayLen(c,send_fack ? 5 : 3);
4482	        addReplyBulkCString(c,"REPLCONF");
4483	        addReplyBulkCString(c,"ACK");
4484	        addReplyBulkLongLong(c,c->reploff);
4485	        if (send_fack) {
4486	            addReplyBulkCString(c,"FACK");
4487	            addReplyBulkLongLong(c,server.fsynced_reploff);
4488	        }
4489	        c->flags &= ~CLIENT_MASTER_FORCE_REPLY;
4490	        /* Accumulation from above replies must be reset back to 0 manually,
