4496	/* ---------------------- MASTER CACHING FOR PSYNC -------------------------- */
4497	
4498	/* In order to implement partial synchronization we need to be able to cache
4499	 * our master's client structure after a transient disconnection.
4500	 * It is cached into server.cached_master and flushed away using the following
4501	 * functions. */
4502	
4503	/* This function is called by freeClient() in order to cache the master
4504	 * client structure instead of destroying it. freeClient() will return
4505	 * ASAP after this function returns, so every action needed to avoid problems
4506	 * with a client that is really "suspended" has to be done by this function.
4507	 *
4508	 * The other functions that will deal with the cached master are:
4509	 *
4510	 * replicationDiscardCachedMaster() that will make sure to kill the client
4511	 * as for some reason we don't want to use it in the future.
4512	 *
4513	 * replicationResurrectCachedMaster() that is used after a successful PSYNC
4514	 * handshake in order to reactivate the cached master.
4515	 */
4516	void replicationCacheMaster(client *c) {
4517	    serverAssert(server.master != NULL && server.cached_master == NULL);
4518	    serverAssert(server.master->tid == IOTHREAD_MAIN_THREAD_ID);
4519	    serverLog(LL_NOTICE,"Caching the disconnected master state.");
4520	
4521	    /* Unlink the client from the server structures. */
4522	    unlinkClient(c);
4523	
4524	    /* Reset the master client so that's ready to accept new commands:
4525	     * we want to discard the non processed query buffers and non processed
4526	     * offsets, including pending transactions, already populated arguments,
4527	     * pending outputs to the master. */
4528	    sdsclear(server.master->querybuf);
4529	    server.master->qb_pos = 0;
4530	    server.master->repl_applied = 0;
4531	    server.master->read_reploff = server.master->reploff;
4532	    server.master->reploff_next = 0;
4533	    if (c->flags & CLIENT_MULTI) discardTransaction(c);
4534	    listEmpty(c->reply);
4535	    c->sentlen = 0;
4536	    c->reply_bytes = c->reply_bytes_shared = c->reply_bytes_unshared = 0;
4537	    c->bufpos = 0;
4538	    resetClient(c, -1);
4539	    resetClientQbufState(c);
4540	
4541	    /* Save the master. Server.master will be set to null later by
4542	     * replicationHandleMasterDisconnection(). */
4543	    server.cached_master = server.master;
4544	
4545	    /* Invalidate the Peer ID cache. */
4546	    if (c->peerid) {
4547	        sdsfree(c->peerid);
4548	        c->peerid = NULL;
4549	    }
4550	    /* Invalidate the Sock Name cache. */
4551	    if (c->sockname) {
4552	        sdsfree(c->sockname);
4553	        c->sockname = NULL;
4554	    }
4555	
4556	    /* Caching the master happens instead of the actual freeClient() call,
4557	     * so make sure to adjust the replication state. This function will
4558	     * also set server.master to NULL. */
4559	    replicationHandleMasterDisconnection();
4560	}
4561	
4562	/* This function is called when a master is turned into a slave, in order to
4563	 * create from scratch a cached master for the new client, that will allow
4564	 * to PSYNC with the slave that was promoted as the new master after a
4565	 * failover.
4566	 *
4567	 * Assuming this instance was previously the master instance of the new master,
4568	 * the new master will accept its replication ID, and potential also the
4569	 * current offset if no data was lost during the failover. So we use our
4570	 * current replication ID and offset in order to synthesize a cached master. */
4571	void replicationCacheMasterUsingMyself(void) {
4572	    serverLog(LL_NOTICE,
4573	        "Before turning into a replica, using my own master parameters "
4574	        "to synthesize a cached master: I may be able to synchronize with "
4575	        "the new master with just a partial transfer.");
4576	
4577	    /* This will be used to populate the field server.master->reploff
4578	     * by replicationCreateMasterClient(). We'll later set the created
4579	     * master as server.cached_master, so the replica will use such
4580	     * offset for PSYNC. */
4581	    server.master_initial_offset = server.master_repl_offset;
4582	
4583	    /* The master client we create can be set to any DBID, because
4584	     * the new master will start its replication stream with SELECT. */
4585	    replicationCreateMasterClient(NULL,-1);
4586	
4587	    /* Use our own ID / offset. */
4588	    memcpy(server.master->replid, server.replid, sizeof(server.replid));
4589	
4590	    /* Set as cached master. */
4591	    unlinkClient(server.master);
4592	    server.cached_master = server.master;
4593	    server.master = NULL;
4594	}
