4596	/* Free a cached master, called when there are no longer the conditions for
4597	 * a partial resync on reconnection. */
4598	void replicationDiscardCachedMaster(void) {
4599	    if (server.cached_master == NULL) return;
4600	
4601	    serverLog(LL_NOTICE,"Discarding previously cached master state.");
4602	    server.cached_master->flags &= ~CLIENT_MASTER;
4603	    freeClient(server.cached_master);
4604	    server.cached_master = NULL;
4605	}
