4607	/* Turn the cached master into the current master, using the file descriptor
4608	 * passed as argument as the socket for the new master.
4609	 *
4610	 * This function is called when successfully setup a partial resynchronization
4611	 * so the stream of data that we'll receive will start from where this
4612	 * master left. */
4613	void replicationResurrectCachedMaster(connection *conn) {
4614	    serverAssert(server.cached_master->tid == IOTHREAD_MAIN_THREAD_ID);
4615	
4616	    server.master = server.cached_master;
4617	    server.cached_master = NULL;
4618	    server.master->conn = conn;
4619	    connSetPrivateData(server.master->conn, server.master);
4620	    server.master->flags &= ~(CLIENT_CLOSE_AFTER_REPLY|CLIENT_CLOSE_ASAP);
4621	    server.master->authenticated = 1;
4622	    server.master->lastinteraction = server.unixtime;
4623	    server.repl_state = REPL_STATE_CONNECTED;
4624	    server.repl_down_since = 0;
4625	    server.repl_up_since = server.unixtime;
4626	    if (server.repl_disconnect_start_time != 0) {
4627	        server.repl_total_disconnect_time += server.unixtime - server.repl_disconnect_start_time;
4628	        server.repl_disconnect_start_time = 0;
4629	    }
4630	    /* Fire the master link modules event. */
4631	    moduleFireServerEvent(REDISMODULE_EVENT_MASTER_LINK_CHANGE,
4632	                          REDISMODULE_SUBEVENT_MASTER_LINK_UP,
4633	                          NULL);
4634	
4635	    /* Re-add to the list of clients. */
4636	    linkClient(server.master);
4637	    if (connSetReadHandler(server.master->conn, readQueryFromClient)) {
4638	        serverLog(LL_WARNING,"Error resurrecting the cached master, impossible to add the readable handler: %s", strerror(errno));
4639	        freeClientAsync(server.master); /* Close ASAP. */
4640	    }
4641	
4642	    /* We may also need to install the write handler as well if there is
4643	     * pending data in the write buffers. */
4644	    if (clientHasPendingReplies(server.master)) {
4645	        if (connSetWriteHandler(server.master->conn, sendReplyToClient)) {
4646	            serverLog(LL_WARNING,"Error resurrecting the cached master, impossible to add the writable handler: %s", strerror(errno));
4647	            freeClientAsync(server.master); /* Close ASAP. */
4648	        }
4649	    }
4650	}
