4653	
4654	/* This function counts the number of slaves with lag <= min-slaves-max-lag.
4655	 * If the option is active, the server will prevent writes if there are not
4656	 * enough connected slaves with the specified lag (or less). */
4657	void refreshGoodSlavesCount(void) {
4658	    listIter li;
4659	    listNode *ln;
4660	    int good = 0;
4661	
4662	    if (!server.repl_min_slaves_to_write ||
4663	        !server.repl_min_slaves_max_lag) return;
4664	
4665	    listRewind(server.slaves,&li);
4666	    while((ln = listNext(&li))) {
4667	        client *slave = ln->value;
4668	        time_t lag = server.unixtime - slave->repl_ack_time;
4669	
4670	        if (slave->replstate == SLAVE_STATE_ONLINE &&
4671	            lag <= server.repl_min_slaves_max_lag) good++;
4672	    }
4673	    server.repl_good_slaves_count = good;
4674	}
