4676	/* return true if status of good replicas is OK. otherwise false */
4677	int checkGoodReplicasStatus(void) {
4678	    return server.masterhost || /* not a primary status should be OK */
4679	           !server.repl_min_slaves_max_lag || /* Min slave max lag not configured */
4680	           !server.repl_min_slaves_to_write || /* Min slave to write not configured */
4681	           server.repl_good_slaves_count >= server.repl_min_slaves_to_write; /* check if we have enough slaves */
