4683	
4684	/* ----------------------- SYNCHRONOUS REPLICATION --------------------------
4685	 * Redis synchronous replication design can be summarized in points:
4686	 *
4687	 * - Redis masters have a global replication offset, used by PSYNC.
4688	 * - Master increment the offset every time new commands are sent to slaves.
4689	 * - Slaves ping back masters with the offset processed so far.
4690	 *
4691	 * So synchronous replication adds a new WAIT command in the form:
4692	 *
4693	 *   WAIT <num_replicas> <milliseconds_timeout>
4694	 *
4695	 * That returns the number of replicas that processed the query when
4696	 * we finally have at least num_replicas, or when the timeout was
4697	 * reached.
4698	 *
4699	 * The command is implemented in this way:
4700	 *
4701	 * - Every time a client processes a command, we remember the replication
4702	 *   offset after sending that command to the slaves.
4703	 * - When WAIT is called, we ask slaves to send an acknowledgement ASAP.
4704	 *   The client is blocked at the same time (see blocked.c).
4705	 * - Once we receive enough ACKs for a given offset or when the timeout
4706	 *   is reached, the WAIT command is unblocked and the reply sent to the
4707	 *   client.
4708	 */
4709	
4710	/* This just set a flag so that we broadcast a REPLCONF GETACK command
4711	 * to all the slaves in the beforeSleep() function. Note that this way
4712	 * we "group" all the clients that want to wait for synchronous replication
4713	 * in a given event loop iteration, and send a single GETACK for them all. */
4714	void replicationRequestAckFromSlaves(void) {
4715	    server.get_ack_from_slaves = 1;
4716	}
4717	
4718	/* Return the number of slaves that already acknowledged the specified
4719	 * replication offset. */
4720	int replicationCountAcksByOffset(long long offset) {
4721	    listIter li;
4722	    listNode *ln;
4723	    int count = 0;
4724	
4725	    listRewind(server.slaves,&li);
4726	    while((ln = listNext(&li))) {
4727	        client *slave = ln->value;
4728	
4729	        if (slave->replstate != SLAVE_STATE_ONLINE) continue;
4730	        if (slave->repl_ack_off >= offset) count++;
4731	    }
4732	    return count;
4733	}
4734	
4735	/* Return the number of replicas that already acknowledged the specified
4736	 * replication offset being AOF fsynced. */
4737	int replicationCountAOFAcksByOffset(long long offset) {
4738	    listIter li;
4739	    listNode *ln;
4740	    int count = 0;
4741	
4742	    listRewind(server.slaves,&li);
4743	    while((ln = listNext(&li))) {
4744	        client *slave = ln->value;
4745	
4746	        if (slave->replstate != SLAVE_STATE_ONLINE) continue;
4747	        if (slave->repl_aof_off >= offset) count++;
4748	    }
4749	    return count;
4750	}
4751	
4752	/* WAIT for N replicas to acknowledge the processing of our latest
4753	 * write command (and all the previous commands). */
4754	void waitCommand(client *c) {
4755	    mstime_t timeout;
4756	    long numreplicas, ackreplicas;
4757	    long long offset = c->woff;
4758	
4759	    if (server.masterhost) {
4760	        addReplyError(c,"WAIT cannot be used with replica instances. Please also note that since Redis 4.0 if a replica is configured to be writable (which is not the default) writes to replicas are just local and are not propagated.");
4761	        return;
4762	    }
4763	
4764	    /* Argument parsing. */
4765	    if (getLongFromObjectOrReply(c,c->argv[1],&numreplicas,NULL) != C_OK)
4766	        return;
4767	    if (getTimeoutFromObjectOrReply(c,c->argv[2],&timeout,UNIT_MILLISECONDS)
4768	        != C_OK) return;
4769	
4770	    /* First try without blocking at all. */
4771	    ackreplicas = replicationCountAcksByOffset(c->woff);
4772	    if (ackreplicas >= numreplicas || c->flags & CLIENT_DENY_BLOCKING) {
4773	        addReplyLongLong(c,ackreplicas);
4774	        return;
4775	    }
4776	
4777	    /* Otherwise block the client and put it into our list of clients
4778	     * waiting for ack from slaves. */
4779	    blockForReplication(c,timeout,offset,numreplicas);
4780	
4781	    /* Make sure that the server will send an ACK request to all the slaves
4782	     * before returning to the event loop. */
4783	    replicationRequestAckFromSlaves();
4784	}
4785	
4786	/* WAIT for N replicas and / or local master to acknowledge our latest
4787	 * write command got synced to the disk. */
4788	void waitaofCommand(client *c) {
4789	    mstime_t timeout;
4790	    long numreplicas, numlocal, ackreplicas, acklocal;
4791	
4792	    /* Argument parsing. */
4793	    if (getRangeLongFromObjectOrReply(c,c->argv[1],0,1,&numlocal,NULL) != C_OK)
4794	        return;
4795	    if (getPositiveLongFromObjectOrReply(c,c->argv[2],&numreplicas,NULL) != C_OK)
4796	        return;
4797	    if (getTimeoutFromObjectOrReply(c,c->argv[3],&timeout,UNIT_MILLISECONDS) != C_OK)
4798	        return;
4799	
4800	    if (server.masterhost) {
4801	        addReplyError(c,"WAITAOF cannot be used with replica instances. Please also note that writes to replicas are just local and are not propagated.");
4802	        return;
4803	    }
4804	    if (numlocal && !server.aof_enabled) {
4805	        addReplyError(c, "WAITAOF cannot be used when numlocal is set but appendonly is disabled.");
4806	        return;
4807	    }
4808	
4809	    /* First try without blocking at all. */
4810	    ackreplicas = replicationCountAOFAcksByOffset(c->woff);
4811	    acklocal = server.fsynced_reploff >= c->woff;
4812	    if ((ackreplicas >= numreplicas && acklocal >= numlocal) || c->flags & CLIENT_DENY_BLOCKING) {
4813	        addReplyArrayLen(c,2);
4814	        addReplyLongLong(c,acklocal);
4815	        addReplyLongLong(c,ackreplicas);
4816	        return;
4817	    }
4818	
4819	    /* Otherwise block the client and put it into our list of clients
4820	     * waiting for ack from slaves. */
4821	    blockForAofFsync(c,timeout,c->woff,numlocal,numreplicas);
4822	
4823	    /* Make sure that the server will send an ACK request to all the slaves
4824	     * before returning to the event loop. */
4825	    replicationRequestAckFromSlaves();
4826	}
4827	
4828	/* This is called by unblockClient() to perform the blocking op type
4829	 * specific cleanup. We just remove the client from the list of clients
4830	 * waiting for replica acks. Never call it directly, call unblockClient()
4831	 * instead. */
4832	void unblockClientWaitingReplicas(client *c) {
4833	    listNode *ln = listSearchKey(server.clients_waiting_acks,c);
4834	    serverAssert(ln != NULL);
4835	    listDelNode(server.clients_waiting_acks,ln);
4836	    updateStatsOnUnblock(c, 0, 0, 0);
4837	}
4838	
4839	/* Check if there are clients blocked in WAIT or WAITAOF that can be unblocked
4840	 * since we received enough ACKs from slaves. */
4841	void processClientsWaitingReplicas(void) {
4842	    long long last_offset = 0;
4843	    long long last_aof_offset = 0;
4844	    int last_numreplicas = 0;
4845	    int last_aof_numreplicas = 0;
4846	
4847	    listIter li;
4848	    listNode *ln;
4849	
4850	    listRewind(server.clients_waiting_acks,&li);
4851	    while((ln = listNext(&li))) {
4852	        int numlocal = 0;
4853	        int numreplicas = 0;
4854	
4855	        client *c = ln->value;
4856	        int is_wait_aof = c->bstate.btype == BLOCKED_WAITAOF;
4857	
4858	        if (is_wait_aof && c->bstate.numlocal && !server.aof_enabled) {
4859	            addReplyError(c, "WAITAOF cannot be used when numlocal is set but appendonly is disabled.");
4860	            unblockClient(c, 1);
4861	            continue;
4862	        }
4863	
4864	        /* Every time we find a client that is satisfied for a given
4865	         * offset and number of replicas, we remember it so the next client
4866	         * may be unblocked without calling replicationCountAcksByOffset()
4867	         * or calling replicationCountAOFAcksByOffset()
4868	         * if the requested offset / replicas were equal or less. */
4869	        if (!is_wait_aof && last_offset && last_offset >= c->bstate.reploffset &&
4870	                           last_numreplicas >= c->bstate.numreplicas)
4871	        {
4872	            numreplicas = last_numreplicas;
4873	        } else if (is_wait_aof && last_aof_offset && last_aof_offset >= c->bstate.reploffset &&
4874	                    last_aof_numreplicas >= c->bstate.numreplicas)
4875	        {
4876	            numreplicas = last_aof_numreplicas;
4877	        } else {
4878	            numreplicas = is_wait_aof ?
4879	                replicationCountAOFAcksByOffset(c->bstate.reploffset) :
4880	                replicationCountAcksByOffset(c->bstate.reploffset);
4881	
4882	            /* Check if the number of replicas is satisfied. */
4883	            if (numreplicas < c->bstate.numreplicas) continue;
4884	
4885	            if (is_wait_aof) {
4886	                last_aof_offset = c->bstate.reploffset;
4887	                last_aof_numreplicas = numreplicas;
4888	            } else {
4889	                last_offset = c->bstate.reploffset;
4890	                last_numreplicas = numreplicas;
4891	            }
4892	        }
4893	
4894	        /* Check if the local constraint of WAITAOF is served */
4895	        if (is_wait_aof) {
4896	            numlocal = server.fsynced_reploff >= c->bstate.reploffset;
4897	            if (numlocal < c->bstate.numlocal) continue;
4898	        }
4899	
4900	        /* Reply before unblocking, because unblock client calls reqresAppendResponse */
4901	        if (is_wait_aof) {
4902	            /* WAITAOF has an array reply */
4903	            addReplyArrayLen(c, 2);
4904	            addReplyLongLong(c, numlocal);
4905	            addReplyLongLong(c, numreplicas);
4906	        } else {
4907	            addReplyLongLong(c, numreplicas);
4908	        }
4909	
4910	        unblockClient(c, 1);
4911	    }
4912	}
