4914	/* Return the slave replication offset for this instance, that is
4915	 * the offset for which we already processed the master replication stream. */
4916	long long replicationGetSlaveOffset(void) {
4917	    long long offset = 0;
4918	
4919	    if (server.masterhost != NULL) {
4920	        if (server.master) {
4921	            offset = server.master->reploff;
4922	        } else if (server.cached_master) {
4923	            offset = server.cached_master->reploff;
4924	        }
4925	    }
4926	    /* offset may be -1 when the master does not support it at all, however
4927	     * this function is designed to return an offset that can express the
4928	     * amount of data processed by the master, so we return a positive
4929	     * integer. */
4930	    if (offset < 0) offset = 0;
4931	    return offset;
4932	}
