4934	/* --------------------------- REPLICATION CRON  ---------------------------- */
4935	
4936	/* Replication cron function, called 1 time per second. */
4937	void replicationCron(void) {
4938	    /* Check failover status first, to see if we need to start
4939	     * handling the failover. */
4940	    updateFailoverStatus();
4941	
4942	    /* Non blocking connection timeout? */
4943	    if (server.masterhost &&
4944	        (server.repl_state == REPL_STATE_CONNECTING ||
4945	         slaveIsInHandshakeState()) &&
4946	         (time(NULL)-server.repl_transfer_lastio) > server.repl_timeout)
4947	    {
4948	        serverLog(LL_WARNING,"Timeout connecting to the MASTER...");
4949	        cancelReplicationHandshake(1);
4950	    }
4951	
4952	    /* Bulk transfer I/O timeout? */
4953	    if (server.masterhost && server.repl_state == REPL_STATE_TRANSFER &&
4954	        (time(NULL)-server.repl_transfer_lastio) > server.repl_timeout)
4955	    {
4956	        serverLog(LL_WARNING,"Timeout receiving bulk data from MASTER... If the problem persists try to set the 'repl-timeout' parameter in redis.conf to a larger value.");
4957	        cancelReplicationHandshake(1);
4958	    }
4959	
4960	    /* Check if we should connect to a MASTER */
4961	    if (server.repl_state == REPL_STATE_CONNECT) {
4962	        serverLog(LL_NOTICE,"Connecting to MASTER %s:%d",
4963	            server.masterhost, server.masterport);
4964	        connectWithMaster();
4965	    }
4966	
4967	    replicationCronRunMasterClient();
4968	
4969	    /* If we have attached slaves, PING them from time to time.
4970	     * So slaves can implement an explicit timeout to masters, and will
4971	     * be able to detect a link disconnection even if the TCP connection
4972	     * will not actually go down. */
4973	    listIter li;
4974	    listNode *ln;
4975	    robj *ping_argv[1];
4976	
4977	    /* First, send PING according to ping_slave_period. The reason why master
4978	     * sends PING is to keep the connection with replica active, so master need
4979	     * not send PING to replicas if already sent replication stream in the past
4980	     * repl_ping_slave_period time. */
4981	    if (server.masterhost == NULL && listLength(server.slaves) &&
4982	        server.unixtime >= server.repl_stream_lastio + server.repl_ping_slave_period)
4983	    {
4984	        /* Note that we don't send the PING if the clients are paused during
4985	         * a Redis Cluster manual failover: the PING we send will otherwise
4986	         * alter the replication offsets of master and slave, and will no longer
4987	         * match the one stored into 'mf_master_offset' state. */
4988	        int manual_failover_in_progress =
4989	            ((server.cluster_enabled &&
4990	              clusterManualFailoverTimeLimit()) ||
4991	            server.failover_end_time) &&
4992	            isPausedActionsWithUpdate(PAUSE_ACTION_REPLICA);
4993	
4994	        if (!manual_failover_in_progress) {
4995	            ping_argv[0] = shared.ping;
4996	            replicationFeedSlaves(server.slaves, -1,
4997	                ping_argv, 1);
4998	        }
4999	    }

