1050	/* Add a double as a bulk reply */
1051	void addReplyDouble(client *c, double d) {
1052	    if (c->resp == 3) {
1053	        char dbuf[MAX_D2STRING_CHARS+3];
1054	        dbuf[0] = ',';
1055	        const int dlen = d2string(dbuf+1,sizeof(dbuf)-1,d);
1056	        dbuf[dlen+1] = '\r';
1057	        dbuf[dlen+2] = '\n';
1058	        dbuf[dlen+3] = '\0';
1059	        addReplyProto(c,dbuf,dlen+3);
1060	    } else {
1061	        char dbuf[MAX_LONG_DOUBLE_CHARS+32];
1062	        /* In order to prepend the string length before the formatted number,
1063	         * but still avoid an extra memcpy of the whole number, we reserve space
1064	         * for maximum header `$0000\r\n`, print double, add the resp header in
1065	         * front of it, and then send the buffer with the right `start` offset. */
1066	        const int dlen = d2string(dbuf+7,sizeof(dbuf)-7,d);
1067	        int digits = digits10(dlen);
1068	        int start = 4 - digits;
1069	        serverAssert(start >= 0);
1070	        dbuf[start] = '$';
1071	
1072	        /* Convert `dlen` to string, putting it's digits after '$' and before the
1073	            * formatted double string. */
1074	        for(int i = digits, val = dlen; val && i > 0 ; --i, val /= 10) {
1075	            dbuf[start + i] = "0123456789"[val % 10];
1076	        }
1077	        dbuf[5] = '\r';
1078	        dbuf[6] = '\n';
1079	        dbuf[dlen+7] = '\r';
1080	        dbuf[dlen+8] = '\n';
1081	        dbuf[dlen+9] = '\0';
1082	        addReplyProto(c,dbuf+start,dlen+9-start);
1083	    }
1084	}
