1273	static int isCopyAvoidPreferred(client *c, robj *obj, size_t len) {
1274	    /* Don't use copy avoidance for fake clients. */
1275	    if (!c->conn || !server.reply_copy_avoidance_enabled) return 0;
1276	
1277	    int type = getClientType(c);
1278	    if (type != CLIENT_TYPE_NORMAL) return 0;
1279	
1280	    /* Don't use copy avoidance for push messages. Push messages need to be deferred
1281	     * to server.pending_push_messages when CLIENT_PUSHING is set. */
1282	    if (c->flags & CLIENT_PUSHING) return 0;
1283	
1284	    if (obj->encoding != OBJ_ENCODING_RAW || obj->refcount >= OBJ_FIRST_SPECIAL_REFCOUNT) return 0;
1285	
1286	    /* Copy avoidance is preferred for any string size starting certain number of I/O threads  */
1287	    if (server.io_threads_num >= COPY_AVOID_MIN_IO_THREADS) return 1;
1288	
1289	    /* Main thread only. No I/O threads */
1290	    if (server.io_threads_num == 1) {
1291	        /* Copy avoidance is preferred starting certain string size */
1292	        return len >= COPY_AVOID_MIN_STRING_SIZE;
1293	    }
1294	
1295	    /* Main thread + I/O threads */
1296	    return len >= COPY_AVOID_MIN_STRING_SIZE_THREADED;
1297	}
