1299	/* Try to avoid whole bulk string copy to a reply buffer
1300	 * If copy avoidance allowed then only pointer to object and string will be copied to the buffer */
1301	static int tryAvoidBulkStrCopyToReply(client *c, robj *obj, size_t len) {
1302	    if (!isCopyAvoidPreferred(c, obj, len)) return C_ERR;
1303	    _addBulkStrRefToBufferOrList(c, obj, len);
1304	    return C_OK;
