1307	/* Add a Redis Object as a bulk reply.
1308	 * If avoid_copy is non-zero, attempt to use copy avoidance optimization. */
1309	void addReplyBulkWithFlag(client *c, robj *obj, int avoid_copy) {
1310	    if (_prepareClientToWrite(c) != C_OK) return;
1311	
1312	    if (sdsEncodedObject(obj)) {
1313	        const size_t len = sdslen(obj->ptr);
1314	        if (avoid_copy && tryAvoidBulkStrCopyToReply(c, obj, len) == C_OK)
1315	            return;
1316	        _addReplyLongLongBulk(c, len);
1317	        _addReplyToBufferOrList(c,obj->ptr,len);
1318	        _addReplyToBufferOrList(c,"\r\n",2);
1319	    } else if (obj->encoding == OBJ_ENCODING_INT) {
1320	        /* For integer encoded strings we just convert it into a string
1321	         * using our optimized function, and attach the resulting string
1322	         * to the output buffer. */
1323	        char buf[34];
1324	        size_t len = ll2string(buf,sizeof(buf),(long)obj->ptr);
1325	        buf[len] = '\r';
1326	        buf[len+1] = '\n';
1327	        _addReplyLongLongBulk(c, len);
1328	        _addReplyToBufferOrList(c,buf,len+2);
1329	    } else {
1330	        serverPanic("Wrong obj->encoding in addReply()");
1331	    }
1332	}
