1385	/* Reply with a verbatim type having the specified extension.
1386	 *
1387	 * The 'ext' is the "extension" of the file, actually just a three
1388	 * character type that describes the format of the verbatim string.
1389	 * For instance "txt" means it should be interpreted as a text only
1390	 * file by the receiver, "md " as markdown, and so forth. Only the
1391	 * three first characters of the extension are used, and if the
1392	 * provided one is shorter than that, the remaining is filled with
1393	 * spaces. */
1394	void addReplyVerbatim(client *c, const char *s, size_t len, const char *ext) {
1395	    if (c->resp == 2) {
