1397	    } else {
1398	        char buf[32];
1399	        size_t preflen = snprintf(buf,sizeof(buf),"=%zu\r\nxxx:",len+4);
1400	        char *p = buf+preflen-4;
1401	        for (int i = 0; i < 3; i++) {
1402	            if (*ext == '\0') {
1403	                p[i] = ' ';
1404	            } else {
1405	                p[i] = *ext++;
1406	            }
1407	        }
1408	        addReplyProto(c,buf,preflen);
1409	        addReplyProto(c,s,len);
1410	        addReplyProto(c,"\r\n",2);
1411	    }
1412	}
