1466	/* Append 'src' client output buffers into 'dst' client output buffers.
1467	 * This function clears the output buffers of 'src' */
1468	void AddReplyFromClient(client *dst, client *src) {
1469	    /* If the source client contains a partial response due to client output
1470	     * buffer limits, propagate that to the dest rather than copy a partial
1471	     * reply. We don't wanna run the risk of copying partial response in case
1472	     * for some reason the output limits don't reach the same decision (maybe
1473	     * they changed) */
1474	    if (src->flags & CLIENT_CLOSE_ASAP) {
1475	        sds client = catClientInfoString(sdsempty(),dst);
1476	        freeClientAsync(dst);
1477	        serverLog(LL_WARNING,"Client %s scheduled to be closed ASAP for overcoming of output buffer limits.", client);
1478	        sdsfree(client);
1479	        return;
1480	    }
1481	
1482	    /* First add the static buffer (either into the static buffer or reply list) */
1483	    addReplyProto(dst,src->buf, src->bufpos);
1484	
1485	    /* We need to check with _prepareClientToWrite again (after addReplyProto)
1486	     * since addReplyProto may have changed something (like CLIENT_CLOSE_ASAP) */
1487	    if (_prepareClientToWrite(dst) != C_OK)
1488	        return;
1489	
1490	    /* We're bypassing _addReplyProtoToList, so we need to add the pre/post
1491	     * checks in it. */
1492	    if (dst->flags & CLIENT_CLOSE_AFTER_REPLY) return;
1493	
1494	    /* Concatenate the reply list into the dest */
1495	    if (listLength(src->reply))
1496	        listJoin(dst->reply,src->reply);
1497	    serverAssert(src->reply_bytes_shared == 0); /* It is non-normal client, never has references. */
1498	    dst->reply_bytes += src->reply_bytes;
1499	    src->reply_bytes = 0;

2500	                offset -= str_len;
2501	            }
2502	
2503	            /* Add crlf */
2504	            if (offset < 2) {
2505	                if (replyIOVReachLimit(reply_iov)) return;
2506	                reply_iov->iov[reply_iov->iovcnt].iov_base = str_ref->crlf + offset;
2507	                reply_iov->iov[reply_iov->iovcnt].iov_len = 2 - offset;
2508	                reply_iov->iov_bytes_len += reply_iov->iov[reply_iov->iovcnt++].iov_len;
2509	            }
2510	        }
2511	
2512	        offset = 0;
2513	        ptr += sizeof(payloadHeader) + head->payload_len;
2514	    }
2515	}
