2564	/* This function should be called from _writeToClient when the reply list is not empty,
2565	 * it gathers the scattered buffers from reply list and sends them away with connWritev.
2566	 * If we write successfully, it returns C_OK, otherwise, C_ERR is returned,
2567	 * and 'nwritten' is an output parameter, it means how many bytes server write
2568	 * to client. */
2569	static int _writevToClient(client *c, ssize_t *nwritten) {
2570	    int iovmax = min(IOV_MAX, c->conn->iovcnt);
2571	    struct iovec iov[iovmax];
2572	    ReplyIOV reply_iov = {iov, iovmax};
2573	
2574	    /* Add c->buf to iov array */
2575	    if (c->bufpos > 0) {
2576	        if (likely(!c->buf_encoded)) {
2577	            /* Non-encoded buffer - add directly */
2578	            iov[reply_iov.iovcnt].iov_base = c->buf + c->sentlen;
2579	            iov[reply_iov.iovcnt].iov_len = c->bufpos - c->sentlen;
2580	            reply_iov.iov_bytes_len += iov[reply_iov.iovcnt++].iov_len;
2581	        } else {
2582	            /* Encoded buffer */
2583	            char *start_ptr = c->last_header ? (char *)c->last_header : c->buf;
2584	            serverAssert(start_ptr >= c->buf && start_ptr < (c->buf + c->bufpos));
2585	            processEncodedBufferForWrite(&reply_iov, start_ptr, c->buf + c->bufpos, c->sentlen);
2586	        }
2587	    }
2588	
2589	    /* Add c->reply list nodes to iov array */
2590	    if (!replyIOVReachLimit(&reply_iov)) {
2591	        /* The first node of reply list might be incomplete from the last call,
2592	         * thus it needs to be calibrated to get the actual data address and length. */
2593	        size_t offset = c->bufpos > 0 ? 0 : c->sentlen;
2594	        payloadHeader *last_header = c->bufpos > 0 ? NULL : c->last_header;
2595	        listIter iter;
2596	        listNode *next;
2597	        listRewind(c->reply, &iter);
2598	        while ((next = listNext(&iter)) && !replyIOVReachLimit(&reply_iov)) {
2599	            clientReplyBlock *o = listNodeValue(next);
2600	            if (o->used == 0) { /* empty node, just release it and skip. */
2601	                c->reply_bytes -= o->size;
2602	                listDelNode(c->reply, next);
2603	                offset = 0;
2604	                last_header = NULL;
2605	                continue;
2606	            }
2607	
2608	            if (!o->buf_encoded) {
2609	                serverAssert(!last_header);
2610	                /* Non-encoded reply block - add directly */
2611	                iov[reply_iov.iovcnt].iov_base = o->buf + offset;
2612	                iov[reply_iov.iovcnt].iov_len = o->used - offset;
2613	                reply_iov.iov_bytes_len += iov[reply_iov.iovcnt++].iov_len;
2614	                offset = 0;
2615	            } else {
2616	                /* Encoded reply block */
2617	                char *start_ptr = last_header ? (char *)last_header : o->buf;
2618	                processEncodedBufferForWrite(&reply_iov, start_ptr, o->buf + o->used, offset);
2619	                offset = 0;
2620	                last_header = NULL;
2621	            }
2622	        }
2623	    }
2624	
2625	    if (reply_iov.iovcnt == 0) return C_OK;
2626	    *nwritten = connWritev(c->conn, iov, reply_iov.iovcnt);
2627	    if (*nwritten <= 0) return C_ERR;
2628	
2629	    /* Locate the new node which has leftover data and
2630	     * release all nodes in front of it. */
2631	    ssize_t remaining = *nwritten;
2632	    if (c->bufpos > 0) {
2633	        if (likely(!c->buf_encoded)) {
2634	            int buf_len = c->bufpos - c->sentlen;
2635	            c->sentlen += remaining;
2636	            /* If the buffer was sent, set bufpos to zero to continue with
2637	            * the remainder of the reply. */
2638	            if (remaining >= buf_len) {
2639	                c->bufpos = 0;
2640	                c->sentlen = 0;
2641	            }
2642	            remaining -= buf_len;
2643	        } else {
2644	            /* For encoded buffers */
2645	            char *start_ptr = c->last_header ? (char *)c->last_header : c->buf;
2646	            c->last_header = processSentDataInEncodedBuffer(c, start_ptr, c->buf + c->bufpos, &c->sentlen, &remaining);
2647	            if (!c->last_header) { /* reach end */
2648	                c->bufpos = 0;
2649	                c->buf_encoded = 0;
2650	                c->sentlen = 0;
2651	            }
2652	        }
2653	    }
2654	
2655	    /* Process c->reply list nodes */
2656	    listIter iter;
2657	    listNode *next;
2658	    listRewind(c->reply, &iter);
2659	    while (remaining > 0) {
2660	        next = listNext(&iter);
2661	        clientReplyBlock *o = listNodeValue(next);
2662	
2663	        if (!o->buf_encoded) {
2664	            if (remaining < (ssize_t)(o->used - c->sentlen)) {
2665	                c->sentlen += remaining;
2666	                break;
2667	            }
2668	            remaining -= (ssize_t)(o->used - c->sentlen);
2669	            c->reply_bytes -= o->size;
2670	            listDelNode(c->reply, next);
2671	            c->sentlen = 0;
2672	        } else {
2673	            /* Encoded reply block */
2674	            char *start_ptr = c->last_header ? (char *)c->last_header : o->buf;
2675	            c->last_header = processSentDataInEncodedBuffer(c, start_ptr, o->buf + o->used, &c->sentlen, &remaining);
2676	            if (!c->last_header) { /* reach end */
2677	                /* Block fully consumed, remove it */
2678	                c->reply_bytes -= o->size;
2679	                listDelNode(c->reply, next);
2680	                c->sentlen = 0;
2681	            } else {
2682	                /* Partial write, c->sentlen and o->last_header already updated, stop processing */
2683	                break;
2684	            }
2685	        }
2686	    }
2687	
2688	    return C_OK;
2689	}
