2691	/* This function does actual writing output buffers for non slave client types,
2692	 * it is called by writeToClient.
2693	 * If we write successfully, it returns C_OK, otherwise, C_ERR is returned,
2694	 * and 'nwritten' is an output parameter, it means how many bytes server write
2695	 * to client. */
2696	static inline int _writeToClientNonSlave(client *c, ssize_t *nwritten) {
2697	    *nwritten = 0;
2698	    /* When the reply list is not empty, it's better to use writev to save us some
2699	     * system calls and TCP packets. */
2700	    if (listLength(c->reply) > 0) {
2701	        int ret = _writevToClient(c, nwritten);
2702	        if (ret != C_OK) return ret;
2703	
2704	        /* If there are no longer objects in the list, we expect
2705	         * the count of reply bytes to be exactly zero. */
2706	        if (listLength(c->reply) == 0)
2707	            serverAssert(c->reply_bytes == 0 && c->reply_bytes_shared == 0);
2708	    } else if (c->bufpos > 0) {
2709	        /* For encoded buffers, we need to use writev to handle bulk string references */
2710	        if (c->buf_encoded) {
2711	            int ret = _writevToClient(c, nwritten);
2712	            return ret;
2713	        }
2714	
2715	        *nwritten = connWrite(c->conn, c->buf + c->sentlen, c->bufpos - c->sentlen);
2716	        if (*nwritten <= 0) return C_ERR;
2717	        c->sentlen += *nwritten;
2718	
2719	        /* If the buffer was sent, set bufpos to zero to continue with
2720	         * the remainder of the reply. */
2721	        if (c->sentlen == c->bufpos) {
2722	            c->bufpos = 0;
2723	            c->sentlen = 0;
2724	        }
2725	    }
2726	    return C_OK;
2727	}
