2949	static inline void resetClientInternal(client *c, int num_pcmds_to_free) {
2950	    redisCommandProc *prevcmd = c->cmd ? c->cmd->proc : NULL;
2951	
2952	    /* We may get here with no pending commands but with an argv that needs freeing.
2953	     * An example is in the case of modules (RM_Call) */
2954	    if (c->current_pending_cmd) {
2955	        freeClientPendingCommands(c, num_pcmds_to_free);
2956	        if (c->pending_cmds.len == 0)
2957	            serverAssert(c->all_argv_len_sum == 0);
2958	        c->current_pending_cmd = NULL;
2959	    } else if (c->argv) {
2960	        freeClientArgvInternal(c, 1 /* free_argv */);
2961	        /* If we're dealing with a client that doesn't create pendingCommand structs (e.g.: a Lua client),
2962	         * clear the all_argv_len_sum counter so we don't get to freeing the client with it non-zero. */
2963	        c->all_argv_len_sum = 0;
2964	    }
2965	
2966	    c->argc = 0;
2967	    c->cmd = NULL;
2968	    c->argv_len = 0;
2969	    c->argv = NULL;
2970	    c->cur_script = NULL;
2971	    c->slot = -1;
2972	    c->cluster_compatibility_check_slot = -2;
2973	    if (c->flags & CLIENT_EXECUTING_COMMAND)
2974	        c->flags &= ~CLIENT_EXECUTING_COMMAND;
2975	
2976	    /* Make sure the duration has been recorded to some command. */
2977	    serverAssert(c->duration == 0);
2978	#ifdef LOG_REQ_RES
2979	    reqresReset(c, 1);
2980	#endif
2981	
2982	    if (c->deferred_reply_errors)
2983	        listRelease(c->deferred_reply_errors);
2984	    c->deferred_reply_errors = NULL;
2985	
2986	    /* We clear the ASKING flag as well if we are not inside a MULTI, and
2987	     * if what we just executed is not the ASKING command itself. */
2988	    if (c->flags & CLIENT_ASKING && !(c->flags & CLIENT_MULTI) &&
2989	        prevcmd != askingCommand)
2990	    {
2991	        c->flags &= ~CLIENT_ASKING;
2992	    }
2993	
2994	    /* We do the same for the CACHING command as well. It also affects
2995	     * the next command or transaction executed, in a way very similar
2996	     * to ASKING. */
2997	    if (c->flags & CLIENT_TRACKING_CACHING && !(c->flags & CLIENT_MULTI) &&
2998	        prevcmd != clientCommand)
2999	    {

3000	        c->flags &= ~CLIENT_TRACKING_CACHING;
3001	    }
3002	
3003	    /* Remove the CLIENT_REPLY_SKIP flag if any so that the reply
3004	     * to the next command will be sent, but set the flag if the command
3005	     * we just processed was "CLIENT REPLY SKIP". */
3006	    if (c->flags & CLIENT_REPLY_SKIP)
3007	        c->flags &= ~CLIENT_REPLY_SKIP;
3008	
3009	    if (c->flags & CLIENT_REPLY_SKIP_NEXT) {
3010	        c->flags |= CLIENT_REPLY_SKIP;
3011	        c->flags &= ~CLIENT_REPLY_SKIP_NEXT;
3012	    }
3013	
3014	    c->net_input_bytes_curr_cmd = 0;
3015	    c->net_output_bytes_curr_cmd = 0;
3016	}
