3023	/* This function is used when we want to re-enter the event loop but there
3024	 * is the risk that the client we are dealing with will be freed in some
3025	 * way. This happens for instance in:
3026	 *
3027	 * * DEBUG RELOAD and similar.
3028	 * * When a Lua script is in -BUSY state.
3029	 *
3030	 * So the function will protect the client by doing two things:
3031	 *
3032	 * 1) It removes the file events. This way it is not possible that an
3033	 *    error is signaled on the socket, freeing the client.
3034	 * 2) Moreover it makes sure that if the client is freed in a different code
3035	 *    path, it is not really released, but only marked for later release. */
3036	void protectClient(client *c) {
3037	    c->flags |= CLIENT_PROTECTED;
3038	    if (c->conn && c->tid == IOTHREAD_MAIN_THREAD_ID) {
3039	        connSetReadHandler(c->conn,NULL);
3040	        connSetWriteHandler(c->conn,NULL);
3041	    }
3042	}
3043	
3044	/* This will undo the client protection done by protectClient() */
3045	void unprotectClient(client *c) {
3046	    if (c->flags & CLIENT_PROTECTED) {
3047	        c->flags &= ~CLIENT_PROTECTED;
3048	        if (c->conn) {
3049	            if (c->tid == IOTHREAD_MAIN_THREAD_ID)
3050	                connSetReadHandler(c->conn,readQueryFromClient);
3051	            if (clientHasPendingReplies(c)) putClientInPendingWriteQueue(c);
3052	        }
3053	    }
3054	}
