3166	/* Helper function. Record protocol error details in server log,
3167	 * and set the client as CLIENT_CLOSE_AFTER_REPLY and
3168	 * CLIENT_PROTOCOL_ERROR. */
3169	#define PROTO_DUMP_LEN 128
3170	static void setProtocolError(const char *errstr, client *c) {
3171	    if (server.verbosity <= LL_VERBOSE || c->flags & CLIENT_MASTER) {
3172	        sds client = catClientInfoString(sdsempty(),c);
3173	
3174	        /* Sample some protocol to given an idea about what was inside. */
3175	        char buf[256];
3176	        if (server.hide_user_data_from_log) {
3177	            snprintf(buf,sizeof(buf),"Query buffer during protocol error: '*redacted*'");  
3178	        } else if (sdslen(c->querybuf)-c->qb_pos < PROTO_DUMP_LEN) {
3179	            snprintf(buf,sizeof(buf),"Query buffer during protocol error: '%s'", c->querybuf+c->qb_pos);  
3180	        } else {
3181	            snprintf(buf,sizeof(buf),"Query buffer during protocol error: '%.*s' (... more %zu bytes ...) '%.*s'", PROTO_DUMP_LEN/2, c->querybuf+c->qb_pos, sdslen(c->querybuf)-c->qb_pos-PROTO_DUMP_LEN, PROTO_DUMP_LEN/2, c->querybuf+sdslen(c->querybuf)-PROTO_DUMP_LEN/2);  
3182	        }
3183	
3184	        /* Remove non printable chars. */  
3185	        if (!server.hide_user_data_from_log) {
3186	            char *p = buf;
3187	            while (*p != '\0') {
3188	                if (!isprint(*p)) *p = '.';
3189	                p++;
3190	            }
3191	        }
3192	
3193	        /* Log all the client and protocol info. */
3194	        int loglevel = (c->flags & CLIENT_MASTER) ? LL_WARNING :
3195	                                                    LL_VERBOSE;
3196	        serverLog(loglevel,
3197	            "Protocol error (%s) from client: %s. %s", errstr, client, buf);
3198	        sdsfree(client);
3199	    }
3200	    c->flags |= (CLIENT_CLOSE_AFTER_REPLY|CLIENT_PROTOCOL_ERROR);
3201	}
3202	
3203	/* Process the query buffer for client 'c', setting up the client argument
3204	 * vector for command execution. Returns C_OK if after running the function
3205	 * the client has a well-formed ready to be processed command, otherwise
3206	 * C_ERR if there is still to read more buffer to get the full command.
3207	 * The function also returns C_ERR when there is a protocol error: in such a
3208	 * case the client structure is setup to reply with the error and close
3209	 * the connection.
3210	 *
3211	 * This function is called if processInputBuffer() detects that the next
3212	 * command is in RESP format, so the first byte in the command is found
3213	 * to be '*'. Otherwise for inline commands processInlineBuffer() is called. */
3214	static int processMultibulkBuffer(client *c, pendingCommand *pcmd) {
3215	    char *newline = NULL;
3216	    int ok;
3217	    long long ll;
3218	    size_t querybuf_len = sdslen(c->querybuf); /* Cache sdslen */
3219	
3220	    if (c->multibulklen == 0) {
3221	        /* The pending command should have been reset */
3222	        serverAssertWithInfo(c,NULL,pcmd->argc == 0);
3223	
3224	        /* Multi bulk length cannot be read without a \r\n */
3225	        newline = strchr(c->querybuf+c->qb_pos,'\r');
3226	        if (newline == NULL) {
3227	            if (querybuf_len-c->qb_pos > PROTO_INLINE_MAX_SIZE) {
3228	                pcmd->read_error = CLIENT_READ_TOO_BIG_MBULK_COUNT_STRING;
3229	            }
3230	            return C_ERR;
3231	        }
3232	
3233	        /* Buffer should also contain \n */
3234	        if (newline-(c->querybuf+c->qb_pos) > (ssize_t)(querybuf_len-c->qb_pos-2))
3235	            return C_ERR;
3236	
3237	        /* We know for sure there is a whole line since newline != NULL,
3238	         * so go ahead and find out the multi bulk length. */
3239	        serverAssertWithInfo(c,NULL,c->querybuf[c->qb_pos] == '*');
3240	        size_t multibulklen_slen = newline - (c->querybuf + 1 + c->qb_pos);
3241	        ok = string2ll(c->querybuf+1+c->qb_pos,newline-(c->querybuf+1+c->qb_pos),&ll);
3242	        if (!ok || ll > INT_MAX) {
3243	            pcmd->read_error = CLIENT_READ_INVALID_MULTIBUCK_LENGTH;
3244	            return C_ERR;
3245	        } else if (ll > 10 && authRequired(c)) {
3246	            pcmd->read_error = CLIENT_READ_UNAUTH_MBUCK_COUNT;
3247	            return C_ERR;
3248	        }
3249	
3250	        c->qb_pos = (newline-c->querybuf)+2;
3251	
3252	        if (ll <= 0) return C_OK;
3253	
3254	        c->multibulklen = ll;
3255	        c->bulklen = -1;
3256	
3257	        /* Setup argv array on pending command structure.
3258	         * Reallocate argv array when the requested size is greater than current size. */
3259	        if (c->multibulklen > pcmd->argv_len) {
3260	            zfree(pcmd->argv);
3261	            pcmd->argv_len = min(c->multibulklen, 1024);
3262	            pcmd->argv = zmalloc(sizeof(robj*)*(pcmd->argv_len));
3263	            pcmd->argv_len_sum = 0;
3264	        }
3265	
3266	        /* Per-slot network bytes-in calculation.
3267	         *
3268	         * We calculate and store the current command's ingress bytes under
3269	         * c->net_input_bytes_curr_cmd, for which its per-slot aggregation is deferred
3270	         * until c->slot is parsed later within processCommand().
3271	         *
3272	         * Calculation: For multi bulk buffer, we accumulate four factors, namely;
3273	         *
3274	         * 1) multibulklen_slen + 3
3275	         *    Cumulative string length (and not the value of) of multibulklen,
3276	         *    including the first "*" byte and last "\r\n" 2 bytes from RESP.
3277	         * 2) bulklen_slen + 3
3278	         *    Cumulative string length (and not the value of) of bulklen,
3279	         *    including +3 from RESP first "$" byte and last "\r\n" 2 bytes per argument count.
3280	         * 3) c->argv_len_sum
3281	         *    Cumulative string length of all argument vectors.
3282	         * 4) c->argc * 2
3283	         *    Cumulative string length of the arguments' white-spaces, for which there exists a total of
3284	         *    "\r\n" 2 bytes per argument.
3285	         *
3286	         * For example;
3287	         * Command) SET key value
3288	         * RESP) *3\r\n$3\r\nSET\r\n$3\r\nkey\r\n$5\r\nvalue\r\n
3289	         *
3290	         * 1) String length of "*3\r\n" is 4, obtained from (multibulklen_slen + 3).
3291	         * 2) String length of "$3\r\n" "$3\r\n" "$5\r\n" is 12, obtained from (bulklen_slen + 3).
3292	         * 3) String length of "SET" "key" "value" is 11, obtained from (c->argv_len_sum).
3293	         * 4) String length of the 3 arguments' white-spaces "\r\n" is 6, obtained from (c->argc * 2).
3294	         *
3295	         * The 1st component is calculated within the below line.
3296	         * */
3297	        pcmd->input_bytes += (multibulklen_slen + 3);
3298	    }
3299	
3300	    serverAssertWithInfo(c,NULL,c->multibulklen > 0);
3301	    while(c->multibulklen) {
3302	        /* Read bulk length if unknown */
3303	        if (c->bulklen == -1) {
3304	            newline = memchr(c->querybuf+c->qb_pos,'\r',sdslen(c->querybuf) - c->qb_pos);
3305	            if (newline == NULL) {
3306	                if (querybuf_len-c->qb_pos > PROTO_INLINE_MAX_SIZE) {
3307	                    pcmd->read_error = CLIENT_READ_TOO_BIG_BUCK_COUNT_STRING;
3308	                    return C_ERR;
3309	                }
3310	                break;
3311	            }
3312	
3313	            /* Buffer should also contain \n */
3314	            if (newline-(c->querybuf+c->qb_pos) > (ssize_t)(querybuf_len-c->qb_pos-2))
3315	                break;
3316	
3317	            if (c->querybuf[c->qb_pos] != '$') {
3318	                pcmd->read_error = CLIENT_READ_EXPECTED_DOLLAR;
3319	                return C_ERR;
3320	            }
3321	
3322	            size_t bulklen_slen = newline - (c->querybuf + c->qb_pos + 1);
3323	            ok = string2ll(c->querybuf+c->qb_pos+1,newline-(c->querybuf+c->qb_pos+1),&ll);
3324	            if (!ok || ll < 0 ||
3325	                (!(c->flags & CLIENT_MASTER) && ll > server.proto_max_bulk_len)) {
3326	                pcmd->read_error = CLIENT_READ_INVALID_BUCK_LENGTH;
3327	                return C_ERR;
3328	            } else if (ll > 16384 && authRequired(c)) {
3329	                pcmd->read_error = CLIENT_READ_UNAUTH_BUCK_LENGTH;
3330	                return C_ERR;
3331	            }
3332	
3333	            c->qb_pos = newline-c->querybuf+2;
3334	            if (!(c->flags & CLIENT_MASTER) && ll >= PROTO_MBULK_BIG_ARG) {
3335	                /* When the client is not a master client (because master
3336	                 * client's querybuf can only be trimmed after data applied
3337	                 * and sent to replicas).
3338	                 *
3339	                 * If we are going to read a large object from network
3340	                 * try to make it likely that it will start at c->querybuf
3341	                 * boundary so that we can optimize object creation
3342	                 * avoiding a large copy of data.
3343	                 *
3344	                 * But only when the data we have not parsed is less than
3345	                 * or equal to ll+2. If the data length is greater than
3346	                 * ll+2, trimming querybuf is just a waste of time, because
3347	                 * at this time the querybuf contains not only our bulk. */
3348	                if (querybuf_len-c->qb_pos <= (size_t)ll+2) {
3349	                    sdsrange(c->querybuf,c->qb_pos,-1);
3350	                    querybuf_len = sdslen(c->querybuf);
3351	                    c->qb_pos = 0;
3352	                    /* Hint the sds library about the amount of bytes this string is
3353	                     * going to contain. */
3354	                    c->querybuf = sdsMakeRoomForNonGreedy(c->querybuf,ll+2-querybuf_len);
3355	                    /* We later set the peak to the used portion of the buffer, but here we over
3356	                     * allocated because we know what we need, make sure it'll not be shrunk before used. */
3357	                    if (c->querybuf_peak < (size_t)ll + 2) c->querybuf_peak = ll + 2;
3358	                    querybuf_len = sdslen(c->querybuf); /* Update cached length */
3359	                }
3360	            }
3361	            c->bulklen = ll;
3362	            /* Per-slot network bytes-in calculation, 2nd component. */
3363	            pcmd->input_bytes += (bulklen_slen + 3);
3364	        } else {
3365	            serverAssert(pcmd->flags & PENDING_CMD_FLAG_INCOMPLETE);
3366	        }
3367	
3368	        /* Read bulk argument */
3369	        if (querybuf_len-c->qb_pos < (size_t)(c->bulklen+2)) {
3370	            break;
3371	        } else {
3372	            /* Check if we have space in argv, grow if needed */
3373	            if (pcmd->argc >= pcmd->argv_len) {
3374	                pcmd->argv_len = min(pcmd->argv_len < INT_MAX/2 ? (pcmd->argv_len)*2 : INT_MAX, pcmd->argc+c->multibulklen);
3375	                pcmd->argv = zrealloc(pcmd->argv, sizeof(robj*)*(pcmd->argv_len));
3376	            }
3377	
3378	            /* Optimization: if a non-master client's buffer contains JUST our bulk element
3379	             * instead of creating a new object by *copying* the sds we
3380	             * just use the current sds string. */
3381	            if (!(c->flags & CLIENT_MASTER) &&
3382	                c->qb_pos == 0 &&
3383	                c->bulklen >= PROTO_MBULK_BIG_ARG &&
3384	                querybuf_len == (size_t)(c->bulklen+2))
3385	            {
3386	                (pcmd->argv)[(pcmd->argc)++] = createObject(OBJ_STRING,c->querybuf);
3387	                pcmd->argv_len_sum += c->bulklen;
3388	                c->all_argv_len_sum += c->bulklen;
3389	                sdsIncrLen(c->querybuf,-2); /* remove CRLF */
3390	                /* Assume that if we saw a fat argument we'll see another one likely...
3391	                 * But only if that fat argument is not too big compared to the memory limit. */
3392	                if (!server.maxmemory || (size_t)c->bulklen < server.maxmemory / 32) {
3393	                    c->querybuf = sdsnewlen(SDS_NOINIT,c->bulklen+2);
3394	                } else {
3395	                    c->querybuf = sdsnewlen(SDS_NOINIT, PROTO_IOBUF_LEN);
3396	                }
3397	                sdsclear(c->querybuf);
3398	                querybuf_len = sdslen(c->querybuf); /* Update cached length */
3399	            } else {
3400	                (pcmd->argv)[(pcmd->argc)++] =
3401	                    createStringObject(c->querybuf+c->qb_pos,c->bulklen);
3402	                pcmd->argv_len_sum += c->bulklen;
3403	                c->all_argv_len_sum += c->bulklen;
3404	                c->qb_pos += c->bulklen+2;
3405	            }
3406	            c->bulklen = -1;
3407	            c->multibulklen--;
3408	        }
3409	    }
3410	
3411	    /* We're done when c->multibulk == 0 */
3412	    if (c->multibulklen == 0) {
3413	        /* Per-slot network bytes-in calculation, 3rd and 4th components. */
3414	        pcmd->input_bytes += (pcmd->argv_len_sum + (pcmd->argc * 2));
3415	        pcmd->flags &= ~PENDING_CMD_FLAG_INCOMPLETE;
3416	        return C_OK;
3417	    }
3418	
3419	    /* Still not ready to process the command */
3420	    pcmd->flags |= PENDING_CMD_FLAG_INCOMPLETE;
3421	    return C_OK;
3422	}
