3424	/* Prepare the client for executing the next command:
3425	 *
3426	 * 1. Append the response, if necessary.
3427	 * 2. Reset the client.
3428	 * 3. Update the all_argv_len_sum counter and advance the pending_cmd cyclic buffer.
3429	 * 4. Update the cluster slot stats, if necessary.
3430	 */
3431	void prepareForNextCommand(client *c, int update_slot_stats) {
3432	    reqresAppendResponse(c);
3433	    if (update_slot_stats) {
3434	        /* We should do this before reset client. */
3435	        clusterSlotStatsAddNetworkBytesInForUserClient(c);
3436	    }
3437	    resetClientInternal(c, 1);
3438	}
3439	
3440	/* Perform necessary tasks after a command was executed:
3441	 *
3442	 * 1. The client is reset unless there are reasons to avoid doing it.
3443	 * 2. In the case of master clients, the replication offset is updated.
3444	 * 3. Propagate commands we got from our master to replicas down the line. */
3445	void commandProcessed(client *c) {
3446	    /* If client is blocked(including paused), just return avoid reset and replicate.
3447	     *
3448	     * 1. Don't reset the client structure for blocked clients, so that the reply
3449	     *    callback will still be able to access the client argv and argc fields.
3450	     *    The client will be reset in unblockClient().
3451	     * 2. Don't update replication offset or propagate commands to replicas,
3452	     *    since we have not applied the command. */
3453	    if (c->flags & CLIENT_BLOCKED) return;
3454	
3455	    prepareForNextCommand(c, 1);
3456	
3457	    long long prev_offset = c->reploff;
3458	    if (c->flags & CLIENT_MASTER && !(c->flags & CLIENT_MULTI)) {
3459	        /* Update the applied replication offset of our master. */
3460	        serverAssert(c->reploff_next > 0);
3461	        c->reploff = c->reploff_next;
3462	    }
3463	
3464	    /* If the client is a master we need to compute the difference
3465	     * between the applied offset before and after processing the buffer,
3466	     * to understand how much of the replication stream was actually
3467	     * applied to the master state: this quantity, and its corresponding
3468	     * part of the replication stream, will be propagated to the
3469	     * sub-replicas and to the replication backlog. */
3470	    if (c->flags & CLIENT_MASTER) {
3471	        long long applied = c->reploff - prev_offset;
3472	        if (applied) {
3473	            replicationFeedStreamFromMasterStream(c->querybuf+c->repl_applied,applied);
3474	            c->repl_applied += applied;
3475	
3476	            /* Update the atomic slot migration task's applied bytes. */
3477	            if (c->flags & CLIENT_ASM_IMPORTING)
3478	                asmImportIncrAppliedBytes(c->task, applied);
3479	        }
3480	    }
3481	}
3482	
3483	/* This function calls processCommand(), but also performs a few sub tasks
3484	 * for the client that are useful in that context:
3485	 *
3486	 * 1. It sets the current client to the client 'c'.
3487	 * 2. calls commandProcessed() if the command was handled.
3488	 *
3489	 * The function returns C_ERR in case the client was freed as a side effect
3490	 * of processing the command, otherwise C_OK is returned. */
3491	int processCommandAndResetClient(client *c) {
3492	    int deadclient = 0;
3493	    client *old_client = server.current_client;
3494	    server.current_client = c;
3495	    if (processCommand(c) == C_OK) {
3496	        commandProcessed(c);
3497	        /* Update the client's memory to include output buffer growth following the
3498	         * processed command. */
3499	        if (c->conn) updateClientMemUsageAndBucket(c);

3500	    }
3501	
3502	    if (server.current_client == NULL) deadclient = 1;
3503	    /*
3504	     * Restore the old client, this is needed because when a script
3505	     * times out, we will get into this code from processEventsWhileBlocked.
3506	     * Which will cause to set the server.current_client. If not restored
3507	     * we will return 1 to our caller which will falsely indicate the client
3508	     * is dead and will stop reading from its buffer.
3509	     */
3510	    server.current_client = old_client;
3511	    /* performEvictions may flush slave output buffers. This may
3512	     * result in a slave, that may be the active client, to be
3513	     * freed. */
3514	    return deadclient ? C_ERR : C_OK;
3515	}
3516	
3517	
3518	/* This function will execute any fully parsed commands pending on
3519	 * the client. Returns C_ERR if the client is no longer valid after executing
3520	 * the command, and C_OK for all other cases. */
3521	int processPendingCommandAndInputBuffer(client *c) {
3522	    /* Notice, this code is also called from 'processUnblockedClients'.
3523	     * But in case of a module blocked client (see RM_Call 'K' flag) we do not reach this code path.
3524	     * So whenever we change the code here we need to consider if we need this change on module
3525	     * blocked client as well */
3526	    if (c->flags & CLIENT_PENDING_COMMAND) {
3527	        c->flags &= ~CLIENT_PENDING_COMMAND;
3528	        if (processCommandAndResetClient(c) == C_ERR) {
3529	            return C_ERR;
3530	        }
3531	    }
3532	
3533	    /* Now process client if it has more data in it's buffer.
3534	     *
3535	     * Note: when a master client steps into this function,
3536	     * it can always satisfy this condition, because its querybuf
3537	     * contains data not applied. */
3538	    if ((c->querybuf && sdslen(c->querybuf) > 0) || c->pending_cmds.ready_len > 0) {
3539	        return processInputBuffer(c);
3540	    }
3541	    return C_OK;
3542	}
