3544	void handleClientReadError(client *c) {
3545	    switch (c->read_error) {
3546	        case CLIENT_READ_TOO_BIG_INLINE_REQUEST:
3547	            addReplyError(c,"Protocol error: too big inline request");
3548	            setProtocolError("too big inline request",c);
3549	            break;
3550	        case CLIENT_READ_UNBALANCED_QUOTES:
3551	            addReplyError(c,"Protocol error: unbalanced quotes in request");
3552	            setProtocolError("unbalanced quotes in request",c);
3553	            break;
3554	        case CLIENT_READ_MASTER_USING_INLINE_PROTOCAL:
3555	            serverLog(LL_WARNING,"WARNING: Receiving inline protocol from master, master stream corruption? Closing the master connection and discarding the cached master.");
3556	            setProtocolError("Master using the inline protocol. Desync?",c);
3557	            break;
3558	        case CLIENT_READ_TOO_BIG_MBULK_COUNT_STRING:
3559	            addReplyError(c,"Protocol error: too big mbulk count string");
3560	            setProtocolError("too big mbulk count string",c);
3561	            break;
3562	        case CLIENT_READ_TOO_BIG_BUCK_COUNT_STRING:
3563	            addReplyError(c, "Protocol error: too big bulk count string");
3564	            setProtocolError("too big bulk count string",c);
3565	            break;
3566	        case CLIENT_READ_EXPECTED_DOLLAR:
3567	            addReplyErrorFormat(c,
3568	                "Protocol error: expected '$', got '%c'",
3569	                c->querybuf[c->qb_pos]);
3570	            setProtocolError("expected $ but got something else",c);
3571	            break;
3572	        case CLIENT_READ_INVALID_BUCK_LENGTH:
3573	            addReplyError(c,"Protocol error: invalid bulk length");
3574	            setProtocolError("invalid bulk length",c);
3575	            break;
3576	        case CLIENT_READ_UNAUTH_BUCK_LENGTH:
3577	            addReplyError(c, "Protocol error: unauthenticated bulk length");
3578	            setProtocolError("unauth bulk length", c);
3579	            break;
3580	        case CLIENT_READ_INVALID_MULTIBUCK_LENGTH:
3581	            addReplyError(c,"Protocol error: invalid multibulk length");
3582	            setProtocolError("invalid mbulk count",c);
3583	            break;
3584	        case CLIENT_READ_UNAUTH_MBUCK_COUNT:
3585	            addReplyError(c, "Protocol error: unauthenticated multibulk length");
3586	            setProtocolError("unauth mbulk count", c);
3587	            break;
3588	        case CLIENT_READ_CONN_DISCONNECTED:
3589	            serverLog(LL_VERBOSE, "Reading from client: %s",connGetLastError(c->conn));
3590	            break;
3591	        case CLIENT_READ_CONN_CLOSED:
3592	            if (server.verbosity <= LL_VERBOSE) {
3593	                sds info = catClientInfoString(sdsempty(), c);
3594	                serverLog(LL_VERBOSE, "Client closed connection %s", info);
3595	                sdsfree(info);
3596	            }
3597	            break;
3598	        case CLIENT_READ_REACHED_MAX_QUERYBUF: {
3599	            sds ci = catClientInfoString(sdsempty(),c), bytes = sdsempty();
3600	            bytes = sdscatrepr(bytes,c->querybuf,64);
3601	            serverLog(LL_WARNING,"Closing client that reached max query buffer length: %s (qbuf initial bytes: %s)", ci, bytes);
3602	            sdsfree(ci);
3603	            sdsfree(bytes);
3604	            break;
3605	        }
3606	        default:
3607	            serverPanic("Unknown client read error: %d", c->read_error);
3608	            break;
3609	    }
3610	}
