3830	void readQueryFromClient(connection *conn) {
3831	    client *c = connGetPrivateData(conn);
3832	    int nread, big_arg = 0;
3833	    size_t qblen, readlen;
3834	
3835	    if (!(c->io_flags & CLIENT_IO_READ_ENABLED)) {
3836	        atomicSetWithSync(c->pending_read, 1);
3837	        return;
3838	    } else if (server.io_threads_num > 1) {
3839	        atomicSetWithSync(c->pending_read, 0);
3840	    }
3841	
3842	    c->read_error = 0;
3843	
3844	    c->stat_total_read_events++;
3845	
3846	    /* Update the number of reads of io threads on server */
3847	    atomicIncr(IOThreads[c->running_tid].io_reads_processed, 1);
3848	
3849	    readlen = PROTO_IOBUF_LEN;
3850	    /* If this is a multi bulk request, and we are processing a bulk reply
3851	     * that is large enough, try to maximize the probability that the query
3852	     * buffer contains exactly the SDS string representing the object, even
3853	     * at the risk of requiring more read(2) calls. This way the function
3854	     * processMultiBulkBuffer() can avoid copying buffers to create the
3855	     * Redis Object representing the argument. */
3856	    if (c->reqtype == PROTO_REQ_MULTIBULK && c->multibulklen && c->bulklen != -1
3857	        && c->bulklen >= PROTO_MBULK_BIG_ARG)
3858	    {
3859	        /* For big argv, the client always uses its private query buffer.
3860	         * Using the reusable query buffer would eventually expand it beyond 32k,
3861	         * causing the client to take ownership of the reusable query buffer. */
3862	        if (!c->querybuf) c->querybuf = sdsempty();
3863	
3864	        ssize_t remaining = (size_t)(c->bulklen+2)-(sdslen(c->querybuf)-c->qb_pos);
3865	        big_arg = 1;
3866	
3867	        /* Note that the 'remaining' variable may be zero in some edge case,
3868	         * for example once we resume a blocked client after CLIENT PAUSE. */
3869	        if (remaining > 0) readlen = remaining;
3870	
3871	        /* Master client needs expand the readlen when meet BIG_ARG(see #9100),
3872	         * but doesn't need align to the next arg, we can read more data. */
3873	        if (c->flags & CLIENT_MASTER && readlen < PROTO_IOBUF_LEN)
3874	            readlen = PROTO_IOBUF_LEN;
3875	    } else if (c->querybuf == NULL) {
3876	        if (unlikely(thread_reusable_qb_used)) {
3877	            /* The reusable query buffer is already used by another client,
3878	             * switch to using the client's private query buffer. This only
3879	             * occurs when commands are executed nested via processEventsWhileBlocked(). */
3880	            c->querybuf = sdsnewlen(NULL, PROTO_IOBUF_LEN);
3881	            sdsclear(c->querybuf);
3882	        } else {
3883	            /* Create the reusable query buffer if it doesn't exist. */
3884	            if (!thread_reusable_qb) {
3885	                thread_reusable_qb = sdsnewlen(NULL, PROTO_IOBUF_LEN);
3886	                sdsclear(thread_reusable_qb);
3887	            }
3888	
3889	            /* Assign the reusable query buffer to the client and mark it as in use. */
3890	            serverAssert(sdslen(thread_reusable_qb) == 0);
3891	            c->querybuf = thread_reusable_qb;
3892	            c->io_flags |= CLIENT_IO_REUSABLE_QUERYBUFFER;
3893	            thread_reusable_qb_used = 1;
3894	        }
3895	    }
3896	
3897	    qblen = sdslen(c->querybuf);
3898	    if (!(c->flags & CLIENT_MASTER) && // master client's querybuf can grow greedy.
3899	        (big_arg || sdsalloc(c->querybuf) < PROTO_IOBUF_LEN)) {
3900	        /* When reading a BIG_ARG we won't be reading more than that one arg
3901	         * into the query buffer, so we don't need to pre-allocate more than we
3902	         * need, so using the non-greedy growing. For an initial allocation of
3903	         * the query buffer, we also don't wanna use the greedy growth, in order
3904	         * to avoid collision with the RESIZE_THRESHOLD mechanism. */
3905	        c->querybuf = sdsMakeRoomForNonGreedy(c->querybuf, readlen);
3906	        /* We later set the peak to the used portion of the buffer, but here we over
3907	         * allocated because we know what we need, make sure it'll not be shrunk before used. */
3908	        if (c->querybuf_peak < qblen + readlen) c->querybuf_peak = qblen + readlen;
3909	    } else {
3910	        c->querybuf = sdsMakeRoomFor(c->querybuf, readlen);
3911	
3912	        /* Read as much as possible from the socket to save read(2) system calls. */
3913	        readlen = sdsavail(c->querybuf);
3914	    }
3915	    nread = connRead(c->conn, c->querybuf+qblen, readlen);
3916	    if (nread == -1) {
3917	        if (connGetState(conn) == CONN_STATE_CONNECTED) {
3918	            goto done;
3919	        } else {
3920	            c->read_error = CLIENT_READ_CONN_DISCONNECTED;
3921	            freeClientAsync(c);
3922	            goto done;
3923	        }
3924	    } else if (nread == 0) {
3925	        c->read_error = CLIENT_READ_CONN_CLOSED;
3926	        freeClientAsync(c);
3927	        goto done;
3928	    }
3929	
3930	    sdsIncrLen(c->querybuf,nread);
3931	    qblen = sdslen(c->querybuf);
3932	    if (c->querybuf_peak < qblen) c->querybuf_peak = qblen;
3933	
3934	    if (!(c->flags & CLIENT_MASTER) || c->running_tid == IOTHREAD_MAIN_THREAD_ID)
3935	        c->lastinteraction = server.unixtime;
3936	    else
3937	        /* Avoid contention with genRedisInfoString as it can access master
3938	         * client's data. If this is a master running in IO thread the value of
3939	         * c->lastinteraction will be updated during processClientsFromIOThread */
3940	        c->io_lastinteraction = server.unixtime;
3941	
3942	    if (c->flags & CLIENT_MASTER) {
3943	        if (c->running_tid == IOTHREAD_MAIN_THREAD_ID) {
3944	            c->read_reploff += nread;
3945	        } else {
3946	            /* Same comment as for c->io_lastinteraction */
3947	            c->io_read_reploff += nread;
3948	        }
3949	        atomicIncr(server.stat_net_repl_input_bytes, nread);
3950	    } else {
3951	        atomicIncr(server.stat_net_input_bytes, nread);
3952	    }
3953	    c->net_input_bytes += nread;
3954	
3955	    if (!(c->flags & CLIENT_MASTER) &&
3956	        /* The commands cached in the MULTI/EXEC queue have not been executed yet,
3957	         * so they are also considered a part of the query buffer in a broader sense.
3958	         *
3959	         * For unauthenticated clients, the query buffer cannot exceed 1MB at most. */
3960	        (c->mstate.argv_len_sums + sdslen(c->querybuf) > server.client_max_querybuf_len ||
3961	         (c->mstate.argv_len_sums + sdslen(c->querybuf) > 1024*1024 && authRequired(c))))
3962	    {
3963	        c->read_error = CLIENT_READ_REACHED_MAX_QUERYBUF;
3964	        freeClientAsync(c);
3965	        atomicIncr(server.stat_client_qbuf_limit_disconnections, 1);
3966	        goto done;
3967	    }
3968	
3969	    /* There is more data in the client input buffer, continue parsing it
3970	     * and check if there is a full command to execute. */
3971	    if (processInputBuffer(c) == C_ERR)
3972	         c = NULL;
3973	
3974	done:
3975	    if (c && isClientReadErrorFatal(c)) {
3976	        if (c->running_tid == IOTHREAD_MAIN_THREAD_ID) {
3977	            handleClientReadError(c);
3978	        }
3979	    }
3980	
3981	    if (c && (c->io_flags & CLIENT_IO_REUSABLE_QUERYBUFFER)) {
3982	        serverAssert(c->qb_pos == 0); /* Ensure the client's query buffer is trimmed in processInputBuffer */
3983	        resetReusableQueryBuf(c);
3984	    }
3985	    beforeNextClient(c);
3986	}
